int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = k + 1; // Initialize with a value larger than any possible a_i or k
        int min_idx = -1;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long total_spells = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue; // Cannot copy a pile to itself, and we are using min_val as source
            }
            // For each other pile a[i], we can add min_val to it until it exceeds k.
            // The number of times min_val can be added is floor((k - a[i]) / min_val).
            // Note: k - a[i] must be non-negative. Since a[i] <= k, this is always true.
            // If a[i] == k, then k - a[i] = 0, and 0 / min_val = 0, which is correct.
            total_spells += (k - a[i]) / min_val;
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

