int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The problem guarantees that a solution always exists.
        // Reversing the permutation always produces a different permutation
        // (unless n=1, but n>=2 is guaranteed) and has the same fingerprint.
        // If p is a palindrome (e.g., [1,2,1] which is not a permutation, or [1,2,3,2,1] not a permutation),
        // then reversing it would yield the same permutation.
        // However, for a permutation, if p is equal to its reverse, it means p_i = p_{n-1-i}.
        // For example, if n=2, p=[1,2], reverse is [2,1]. Different.
        // If n=3, p=[1,2,3], reverse is [3,2,1]. Different.
        // If n=4, p=[1,2,3,4], reverse is [4,3,2,1]. Different.
        // A permutation cannot be a palindrome unless n=1 (which is not allowed)
        // because if p_i = p_{n-1-i} for all i, then for n > 1,
        // p_1 = p_n, p_2 = p_{n-1}, etc.
        // This would imply that if n is odd, the middle element p_{(n+1)/2} is unique.
        // If n is even, all elements come in pairs.
        // For example, if n=4, p=[a,b,b,a]. This is not a permutation because 'a' and 'b' appear twice.
        // So, reversing a permutation always yields a different permutation.

        for (int i = n - 1; i >= 0; --i) {
            std::cout << p[i] << (i == 0 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

