void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    int current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the total value contributed by 'val' to current_sum.
        // This is equivalent to combining all 'val's into larger powers of two.
        // For example, if we have three 2s, we can form one 4 and one 2 remains.
        // The 'current_sum' effectively tracks the total value that can be
        // combined into powers of two up to 2048.
        current_sum += val * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

