#include <algorithm>

void solve() {
    int n;
    long long d; // d can be up to 100, but sum of costs can exceed int if n is large, though here n is also 100.
                 // Using long long for d and remaining_days is safer.
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];
    long long remaining_days = d;

    // Iterate through piles from 2nd to nth (index 1 to n-1)
    for (int i = 1; i < n; ++i) {
        // Cost to move one haybale from pile i+1 (0-indexed i) to pile 1 (0-indexed 0)
        // is i days.
        long long cost_per_haybale = i; 

        if (remaining_days >= cost_per_haybale) {
            // Calculate how many haybales can be moved from this pile
            // based on remaining days and cost per haybale.
            long long max_haybales_from_this_pile = remaining_days / cost_per_haybale;

            // We can only move at most a[i] haybales from this pile.
            long long haybales_to_move = std::min((long long)a[i], max_haybales_from_this_pile);

            current_a1 += haybales_to_move;
            remaining_days -= haybales_to_move * cost_per_haybale;
        } else {
            // Not enough days to move even one haybale from this pile.
            // Since piles are processed in increasing order of cost,
            // we won't be able to move haybales from subsequent piles either.
            break; 
        }
    }

    std::cout << current_a1 << std::endl;
}

