#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        // Add virtual 'R' at position -1 (cell 0) and position n (cell n+1)
        // This simplifies boundary conditions.
        // The frog starts at cell 0, which is effectively an 'R' cell.
        // The target is cell n+1, which is effectively an 'R' cell.
        // We are interested in the maximum distance between consecutive 'R' cells.

        // Positions of 'R' cells, including virtual 'R' at 0 and n+1.
        std::vector<int> r_positions;
        r_positions.push_back(0); // Virtual 'R' at cell 0 (start)

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                r_positions.push_back(i + 1); // Cell i corresponds to s[i], so its position is i+1
            }
        }
        r_positions.push_back(n + 1); // Virtual 'R' at cell n+1 (target)

        int max_dist = 0;
        for (size_t i = 0; i < r_positions.size() - 1; ++i) {
            max_dist = std::max(max_dist, r_positions[i+1] - r_positions[i]);
        }

        std::cout << max_dist << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by the minimum of coders and mathematicians,
        // as each team must have at least one of each.
        // It's also limited by the total number of students divided by 3.
        // So, an upper bound for k is min(c, m, (c + m + x) / 3).
        // Let's call this upper bound 'max_possible_teams'.
        // The actual answer will be less than or equal to this.

        // We can use binary search to find the maximum k.
        // The search space for k is from 0 to 10^8 (since c, m, x <= 10^8).
        // A tighter upper bound is min(c, m, (c + m + x) / 3).
        // Since c, m, x can be up to 10^8, (c+m+x)/3 can be up to 10^8.
        // So, the upper bound for k is roughly 10^8.

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3}); // Initial upper bound
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;

            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians as a minimum.
            // The remaining students are (c - mid) coders, (m - mid) mathematicians, and x no-specialization students.
            // The total number of remaining students is (c - mid) + (m - mid) + x.
            // Each team needs 3 members. We've already accounted for 'mid' coders and 'mid' mathematicians.
            // So, for 'mid' teams, we need 'mid' additional members (3 * mid - mid - mid = mid).
            // These 'mid' additional members can come from the remaining coders, mathematicians, or no-specialization students.
            // The total pool of available "other" students is (c - mid) + (m - mid) + x.

            // Check if we have enough students to form 'mid' teams:
            // 1. Enough coders: c >= mid
            // 2. Enough mathematicians: m >= mid
            // 3. Enough total students: (c + m + x) >= 3 * mid
            // These three conditions are implicitly handled by the 'high' initialization.
            // The crucial condition is whether we have enough "flexible" students.
            // After taking 'mid' coders and 'mid' mathematicians (one for each team),
            // we need 'mid' more students to fill the third slot in each of the 'mid' teams.
            // These 'mid' students can be any of the remaining (c - mid) coders, (m - mid) mathematicians, or x no-specialization students.
            // So, we need to check if (c - mid) + (m - mid) + x >= mid.

            if (c >= mid && m >= mid && (c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
