int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the top part of the carrot (from apex to cut x_i)
        // should be i * (total_area / n).
        // Total area = 0.5 * base * height = 0.5 * 1 * h = h / 2.
        // Area of top part = i * (h / (2n)).
        //
        // For a triangle similar to the original with height x_i,
        // its base b_i = x_i / h (by similar triangles, b_i / x_i = 1 / h).
        // Its area = 0.5 * b_i * x_i = 0.5 * (x_i / h) * x_i = x_i^2 / (2h).
        //
        // So, x_i^2 / (2h) = i * (h / (2n)).
        // x_i^2 = i * h^2 / n.
        // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n).
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

