int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) { // Should not happen based on constraints 1 <= m
            std::cout << 0 << "\n";
            continue;
        }

        long long count = n / m; // Number of terms in the sequence m, 2m, ..., count*m

        if (count == 0) { // No pages divisible by m up to n
            std::cout << 0 << "\n";
            continue;
        }

        // Calculate the sum of last digits for one cycle (10 terms)
        // The last digits are (m % 10), (2m % 10), ..., (10m % 10)
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_sum += (static_cast<long long>(i) * m) % 10;
        }

        // Number of full cycles
        long long num_full_cycles = count / 10;
        long long total_sum = num_full_cycles * cycle_sum;

        // Remaining terms after full cycles
        long long remaining_terms = count % 10;
        for (int i = 1; i <= remaining_terms; ++i) {
            total_sum += (static_cast<long long>(i) * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

