// Function to determine if Box 4 can be the special box
// Box 4: [1, inf)
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // Final product must be positive and magnitude >= 1
    // For positive product: (A+B) must be even.
    // For magnitude >= 1:
    //   This requires at least one toy from Box 1 or Box 4.
    //   If all toys are from Box 2 or Box 3, the product magnitude will always be < 1.

    long long N = A + B + C + D;

    if (N == 1) {
        return D == 1;
    }

    // For the final product to be positive, the total count of negative numbers (A+B) must be even.
    if ((A + B) % 2 != 0) {
        return false; // Product is negative
    }

    // For the final product to have magnitude >= 1:
    // This requires at least one toy from Box 1 or Box 4.
    // If A == 0 and D == 0, then all toys are from Box 2 or Box 3, so product magnitude is always < 1.
    if (A == 0 && D == 0) {
        return false; // Product magnitude < 1
    }

    // If A+B is even and A+D > 0, then Box 4 is possible.
    return true;
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        std::cout << (can_be_box1(A, B, C, D) ? "Ya" : "Tidak") << " ";
        std::cout << (can_be_box2(A, B, C, D) ? "Ya" : "Tidak") << " ";
        std::cout << (can_be_box3(A, B, C, D) ? "Ya" : "Tidak") << " ";
        std::cout << (can_be_box4(A, B, C, D) ? "Ya" : "Tidak") << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_ops
    // prefix_min_ops[i] stores the minimum value a[i] must have
    // to satisfy a[0] < a[1] < ... < a[i]
    // Specifically, a[i] must be at least i.
    // So, a[i] - i must be non-negative.
    // If a[i] < i, it's impossible to make a[i] >= i.
    // We can achieve a[i] = i by decreasing a[i] by a[i]-i.
    // The actual value of a[i] after operations must be at least i.
    // So, a[i] (original) must be at least i.
    // If a[i] < i for any i, then it's impossible to form the strictly increasing prefix up to a[i].
    // This is because a[0] >= 0, a[1] >= 1, ..., a[i] >= i.
    // So, we need a[i] >= i for all i in the increasing part.
    // The first element a[0] must be at least 0.
    // The second element a[1] must be at least 1.
    // The i-th element a[i] must be at least i.
    // So, for the prefix a_0, ..., a_k, we need a_i >= i for all 0 <= i <= k.
    // This means a_i - i >= 0.
    // The maximum possible k for the increasing part is the largest k such that a_i >= i for all 0 <= i <= k.

    int max_k_prefix = -1; // Stores the largest index i such that a[0]...a[i] can be made strictly increasing
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            break;
        }
        max_k_prefix = i;
    }

    // Calculate suffix_min_ops
    // suffix_min_ops[i] stores the minimum value a[i] must have
    // to satisfy a[i] > a[i+1] > ... > a[n-1]
    // Specifically, a[i] must be at least n-1-i.
    // So, a[i] - (n-1-i) must be non-negative.
    // If a[i] < n-1-i, it's impossible to make a[i] >= n-1-i.
    // We can achieve a[i] = n-1-i by decreasing a[i] by a[i]-(n-1-i).
    // The actual value of a[i] after operations must be at least n-1-i.
    // So, a[i] (original) must be at least n-1-i.
    // If a[i] < n-1-i for any i, then it's impossible to form the strictly decreasing suffix from a[i].
    // This is because a[n-1] >= 0, a[n-2] >= 1, ..., a[i] >= n-1-i.
    // So, we need a[i] >= n-1-i for all i in the decreasing part.
    // The minimum possible k for the decreasing part is the smallest k such that a[k]...a[n-1] can be made strictly decreasing.

    int min_k_suffix = n; // Stores the smallest index i such that a[i]...a[n-1] can be made strictly decreasing
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1 - i)) {
            break;
        }
        min_k_suffix = i;
    }

    // A sharpened array requires a peak at index k.
    // The prefix a[0]...a[k] must be strictly increasing.
    // The suffix a[k]...a[n-1] must be strictly decreasing.
    // This means k must be a valid index for both conditions.
    // So, we need to find if there exists a k such that:
    // 1. a[0]...a[k] can be made strictly increasing (i.e., k <= max_k_prefix)
    // 2. a[k]...a[n-1] can be made strictly decreasing (i.e., k >= min_k_suffix)
    // If such a k exists, then max_k_prefix >= min_k_suffix.
    // If max_k_prefix >= min_k_suffix, then any k in [min_k_suffix, max_k_prefix] can be the peak.
    // For example, if k = min_k_suffix, then a[0]...a[min_k_suffix] can be made increasing,
    // and a[min_k_suffix]...a[n-1] can be made decreasing.
    // The condition for a peak at index k is that a[k] must be at least k AND a[k] must be at least n-1-k.
    // This is implicitly handled by max_k_prefix and min_k_suffix.
    // If max_k_prefix >= min_k_suffix, then there is at least one index k that satisfies both conditions.
    // For example, k = min_k_suffix.
    // For this k, a[min_k_suffix] >= min_k_suffix (from prefix condition)
    // and a[min_k_suffix] >= n-1-min_k_suffix (from suffix condition).
    // So, a[min_k_suffix] can be set to max(min_k_suffix, n-1-min_k_suffix) and still satisfy both.
    // The existence of such a k is sufficient.

    if (max_k_prefix >= min_k_suffix) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareElementA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareElementB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> A_sorted(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A_sorted[i].value;
        A_sorted[i].original_index = i;
    }

    std::vector<ElementB> B_sorted(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B_sorted[i].value;
        B_sorted[i].original_index = i;
    }

    std::sort(A_sorted.begin(), A_sorted.end(), compareElementA);
    std::sort(B_sorted.begin(), B_sorted.end(), compareElementB);

    std::vector<long long> result_A_prime(m);

    // Use a multiset to store A values that are available for assignment.
    // This allows efficient retrieval of the largest available A value.
    // We need to store the actual values, not indices, as we are assigning values.
    std::multiset<long long> available_A_values;

    int a_ptr = 0; // Pointer for A_sorted

    // Iterate through B_sorted in increasing order of B_i
    // This corresponds to iterating through the target positions in the final A' array
    // based on the sorted B values.
    for (int i = 0; i < m; ++i) {
        // Add all A_j such that A_j >= B_sorted[i].value to the multiset.
        // Since A_sorted is sorted, we can do this efficiently.
        while (a_ptr < m && A_sorted[a_ptr].value >= B_sorted[i].value) {
            available_A_values.insert(A_sorted[a_ptr].value);
            a_ptr++;
        }

        // The problem statement guarantees A_i >= B_j for all i, j.
        // This means that for any B_sorted[i], there will always be at least one A_j
        // such that A_j >= B_sorted[i]. In fact, all A_j will satisfy this.
        // So, available_A_values will never be empty here.

        // To maximize F(A', B), we want to pair the smallest B_i with the largest available A_j.
        // The largest available A_j is at the end of the multiset.
        long long assigned_A_value = *available_A_values.rbegin();

        // Assign this A value to the original index corresponding to B_sorted[i].
        result_A_prime[B_sorted[i].original_index] = assigned_A_value;

        // Remove the assigned A value from the multiset.
        available_A_values.erase(std::prev(available_A_values.end()));
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_A_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

