        int countR = 0;
        int countP = 0;
        int countS = 0;

        for (char ch : s) {
            if (ch == 'R') {
                countR++;
            } else if (ch == 'P') {
                countP++;
            } else { // ch == 'S'
                countS++;
            }
        }

        char optimal_move_char;
        if (countR >= countP && countR >= countS) {
            // R is most frequent or tied for most frequent.
            // To beat R, we play P.
            optimal_move_char = 'P';
        } else if (countP >= countR && countP >= countS) {
            // P is most frequent or tied for most frequent.
            // To beat P, we play S.
            optimal_move_char = 'S';
        } else { // S must be most frequent
            // To beat S, we play R.
            optimal_move_char = 'R';
        }

        for (int i = 0; i < n; ++i) {
            std::cout << optimal_move_char;
        }
        std::cout << "\n";
