// Function to check if a subarray is a permutation of its length
// This version uses a frequency array and checks max value.
// It's optimized for prefix/suffix checks.
bool is_permutation_check(int len, int max_val, const std::vector<int>& counts) {
    if (max_val != len) {
        return false;
    }
    for (int i = 1; i <= len; ++i) {
        if (counts[i] != 1) {
            return false;
        }
    }
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix permutation properties
    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<int> prefix_counts(n + 1, 0);
    int prefix_max_val = 0;
    bool prefix_valid_so_far = true;
    for (int i = 0; i < n; ++i) {
        int val = a[i];
        if (val > n || prefix_counts[val] > 0) { // val > n is technically val > i+1
            prefix_valid_so_far = false;
        }
        prefix_counts[val]++;
        prefix_max_val = std::max(prefix_max_val, val);

        if (prefix_valid_so_far && prefix_max_val == (i + 1)) {
            is_prefix_perm[i + 1] = true;
        }
    }

    // Precompute suffix permutation properties
    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<int> suffix_counts(n + 1, 0);
    int suffix_max_val = 0;
    bool suffix_valid_so_far = true;
    for (int i = n - 1; i >= 0; --i) {
        int val = a[i];
        int current_suffix_len = n - i;
        if (val > n || suffix_counts[val] > 0) { // val > n is technically val > current_suffix_len
            suffix_valid_so_far = false;
        }
        suffix_counts[val]++;
        suffix_max_val = std::max(suffix_max_val, val);

        if (suffix_valid_so_far && suffix_max_val == current_suffix_len) {
            is_suffix_perm[current_suffix_len] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 can be from 1 to n-1
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

