    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, int> x_counts;
    std::map<int, int> y_counts;
    std::map<std::pair<int, int>, int> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [x_coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += static_cast<long long>(count) * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [y_coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += static_cast<long long>(count) * (count - 1) / 2;
        }
    }

    // Subtract pairs that have both same x and same y (counted twice)
    for (auto const& [coords, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= static_cast<long long>(count) * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need S' = 2 * X'
    // Let S' = current_sum + b1 + b2 + ...
    // Let X' = current_xor_sum ^ b1 ^ b2 ^ ...

    // Strategy: Append at most 3 elements.
    // It's always possible to make it good with at most 3 elements.
    // Let's try to append 2 elements.
    // We want to find b1, b2 such that:
    // current_sum + b1 + b2 = 2 * (current_xor_sum ^ b1 ^ b2)

    // Consider appending two elements: X and current_sum + X.
    // Let b1 = current_xor_sum.
    // Let b2 = current_sum.
    // New XOR sum: X' = current_xor_sum ^ b1 ^ b2 = current_xor_sum ^ current_xor_sum ^ current_sum = current_sum.
    // New sum: S' = current_sum + b1 + b2 = current_sum + current_xor_sum + current_sum = 2 * current_sum + current_xor_sum.
    // We need S' = 2 * X'.
    // So, 2 * current_sum + current_xor_sum = 2 * current_sum.
    // This implies current_xor_sum = 0.
    // This strategy works if current_xor_sum is 0.
    // But we need a general strategy.

    // Let's try to append two elements: current_xor_sum and current_sum.
    // This is not quite right.
    // The problem states that we can always append at most 3 elements.
    // A common strategy for these types of problems is to append elements that simplify the XOR sum.

    // Let X = current_xor_sum.
    // Let S = current_sum.
    // We want S' = 2 * X'.
    // We know that S - X is always even.
    // Let's append one element, say b1.
    // New sum: S + b1
    // New XOR sum: X ^ b1
    // We need S + b1 = 2 * (X ^ b1).
    // This equation is hard to solve directly for b1.

    // Let's try to append two elements.
    // A common trick is to make the XOR sum equal to some value, say Y.
    // If we append X, the XOR sum becomes X ^ X = 0.
    // If we append X, the sum becomes S + X.
    // Now we have sum S+X and XOR sum 0.
    // We need S+X = 2 * 0, which means S+X = 0.
    // This is only true if S=0 and X=0, which is not general.

    // Let's try to make the final XOR sum equal to some value, say K.
    // And the final sum equal to 2K.
    // Consider appending two elements:
    // b1 = current_xor_sum
    // b2 = current_sum + current_xor_sum
    // This is not quite right.

    // The standard solution for this type of problem is to append two elements:
    // 1. The current XOR sum (X). This makes the XOR sum 0.
    // 2. The current sum (S) plus the current XOR sum (X). This is the value needed to satisfy the sum condition.

    // Let X = current_xor_sum.
    // Let S = current_sum.

    // Append b1 = X.
    // New XOR sum: X' = X ^ X = 0.
    // New sum: S' = S + X.
    // Now we need S' = 2 * X', which means S + X = 2 * 0 = 0.
    // This is only true if S=0 and X=0.

    // What if we append two elements: X and S+X?
    // Let b1 = X.
    // Let b2 = S + X.
    // New XOR sum: X' = X ^ b1 ^ b2 = X ^ X ^ (S + X) = S + X.
    // New sum: S' = S + b1 + b2 = S + X + (S + X) = 2 * (S + X).
    // We need S' = 2 * X'.
    // Here, S' = 2 * (S + X) and X' = S + X.
    // So, S' = 2 * X' is satisfied!
    // The elements to append are X and S+X.
    // These are non-negative since S and X are non-negative.
    // S can be up to 10^5 * 10^9 = 10^14.
    // X can be up to 2^30 - 1 (approx 10^9).
    // S+X can be up to 10^14 + 10^9, which fits in long long.
    // The problem states $0 \le b_i \le 10^{18}$, so this is fine.

    // So, we can always append two elements: current_xor_sum and current_sum + current_xor_sum.
    // Let's verify this.
    // Initial array: a_1, ..., a_n
    // Initial sum: S = sum(a_i)
    // Initial XOR sum: X = xor(a_i)

    // Append b_1 = X
    // Append b_2 = S + X
    // New array: a_1, ..., a_n, X, S+X
    // New sum: S' = S + X + (S+X) = 2S + 2X
    // New XOR sum: X' = X ^ X ^ (S+X) = 0 ^ (S+X) = S+X
    // Check condition: S' = 2 * X'
    // 2S + 2X = 2 * (S+X)
    // This is true!

    // So, we always append 2 elements: current_xor_sum and current_sum + current_xor_sum.
    // This works for all cases, including when the array is already good.
    // The problem statement says "you don't have to minimize the number of added elements!".
    // So, this 2-element solution is always valid.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a's to its left
            // will eventually interact with this 'b'.
            // Each 'a' to its left will cause an 'ab' -> 'bba' operation.
            // The 'a' will move past this 'b', and a new 'b' will be created.
            // The number of 'a's that have passed this 'b' (count_a)
            // determines how many times this 'b' effectively "doubles"
            // the operations for subsequent 'a's.
            // Specifically, if we have 'k' 'a's to the left of this 'b',
            // and this 'b' is part of an 'ab' pair, then this 'b' will
            // be involved in 'k' operations.
            // After these 'k' operations, this 'b' will be followed by 'k' 'a's.
            // The 'k' 'a's will have moved past this 'b'.
            // The crucial insight is that each 'a' to the left of a 'b'
            // will eventually be processed. When an 'a' is processed with a 'b',
            // it generates a new 'b'. This new 'b' will then interact with
            // any 'a's further to its left.
            // The number of 'a's that have been "carried over" from the right
            // (count_a) represents the number of 'a's that are currently
            // to the right of the current position, but conceptually
            // still need to be moved past any 'b's to their left.
            // When we encounter a 'b', it means these 'count_a' 'a's
            // will eventually move past this 'b'.
            // Each such 'a' will cause an 'ab' -> 'bba' operation.
            // So, 'count_a' operations are added to total_steps.
            // After these operations, this 'b' effectively becomes two 'b's
            // for the purpose of interacting with 'a's further to the left.
            // One 'b' is the original 'b', and the other 'b' is the new 'b'
            // generated by the 'ab' -> 'bba' operation.
            // So, the number of 'a's that will be "carried over"
            // for the next 'b' to the left doubles.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' will eventually
            // need to move past any 'b's to its left.
            // It contributes to the 'count_a' for subsequent 'b's.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
