// Function to check if a number is a power of 2
bool is_power_of_two(long long n) {
    return n > 0 && (n & (n - 1)) == 0;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n;
        std::cin >> n;

        long long chanek_score = 0;
        bool chanek_turn = true;

        while (n > 0) {
            if (chanek_turn) {
                if (n % 2 == 1) { // N is odd
                    chanek_score += 1;
                    n -= 1;
                } else { // N is even
                    // If N is a power of 2, taking N/2 is optimal for the current player.
                    // This leads to a 2/3 vs 1/3 split for the current player vs opponent over the power-of-2 segment.
                    // If N is even but not a power of 2, taking 1 is optimal.
                    // This leaves N-1 (odd) for the opponent, forcing them to take 1, leaving N-2 (even) for Chanek.
                    // This effectively "skips" the opponent's turn for a large move.
                    if (is_power_of_two(n)) {
                        chanek_score += n / 2;
                        n /= 2;
                    } else {
                        chanek_score += 1;
                        n -= 1;
                    }
                }
            } else { // Opponent's turn
                // Opponent plays optimally to maximize their own score.
                // This means they follow the same logic as Chanek, but for their own benefit.
                if (n % 2 == 1) { // N is odd
                    n -= 1; // Opponent takes 1
                } else { // N is even
                    if (is_power_of_two(n)) {
                        n /= 2; // Opponent takes N/2
                    } else {
                        n -= 1; // Opponent takes 1
                    }
                }
            }
            chanek_turn = !chanek_turn;
        }
        std::cout << chanek_score << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left side.
    // 'i' represents the number of items taken from the left.
    // So, items w[0]...w[i-1] are taken from the left.
    for (int i = 0; i <= n; ++i) {
        // 'j' represents the number of items taken from the right side.
        // j = n - i
        int j = n - i;

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        // The sum of weights for items taken from the right is total_sum - prefix_sum[i]
        // which is prefix_sum[n] - prefix_sum[i]
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalty for imbalance
        if (i > j) { // More items taken from left than right
            // The difference is i - j.
            // The number of extra items taken from the left is (i - j - 1).
            // For example, if i=3, j=1, diff=2. We took 2 more from left.
            // This means the last item taken from the left was the (j+1)-th item from the left.
            // The last item taken from the right was the j-th item from the right.
            // The (j+1)-th item from the left was taken after the j-th item from the right.
            // The (j+2)-th item from the left was taken after the (j+1)-th item from the left.
            // So, (i - j - 1) times we took an item from the left when the previous was also left.
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) { // More items taken from right than left
            // The difference is j - i.
            // The number of extra items taken from the right is (j - i - 1).
            current_energy += (j - i - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

