// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    if (n == 0) {
        return "000000000000000000"; // 18 zeros for 0
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) {
            pattern += '0';
        } else {
            pattern += '1';
        }
        n /= 10;
    }
    // Pad with '0's from the left to a fixed length (18 for max 10^18-1)
    // The problem states max pattern length is 18.
    // 10^18 has 19 digits, but 10^18-1 has 18 nines.
    // A number like 10^18 itself would be 1 followed by 18 zeros.
    // The pattern for 10^18 would be 00...01 (18 zeros then 1).
    // The problem implies numbers up to 10^18-1.
    // Let's use 18 as the fixed length.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the left to fixed length 18
            std::string padded_s = s;
            while (padded_s.length() < 18) {
                padded_s = '0' + padded_s;
            }
            std::cout << counts[padded_s] << "\n";
        }
    }

    return 0;
}

