void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    std::string ans(n, ' ');
    bool found_solution = false;

    for (int p = 0; p <= 9; ++p) { // p is the split point digit
        int last1 = -1;
        int last2 = -1;
        bool possible_p = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                // Must be color 1
                if (d[i] >= last1) {
                    ans[i] = '1';
                    last1 = d[i];
                } else {
                    possible_p = false;
                    break;
                }
            } else if (d[i] > p) {
                // Must be color 2
                if (d[i] >= last2) {
                    ans[i] = '2';
                    last2 = d[i];
                } else {
                    possible_p = false;
                    break;
                }
            } else { // d[i] == p
                // Can be color 1 or 2. Prioritize color 2 if possible.
                // This strategy ensures that if a digit 'p' can be color 2,
                // it is colored 2, which helps keep last1 small.
                if (d[i] >= last2) { // Can be color 2
                    ans[i] = '2';
                    last2 = d[i];
                } else if (d[i] >= last1) { // Must be color 1
                    ans[i] = '1';
                    last1 = d[i];
                } else { // Cannot be either
                    possible_p = false;
                    break;
                }
            }
        }

        if (possible_p) {
            found_solution = true;
            std::cout << ans << "\n";
            break;
        }
    }

    if (!found_solution) {
        std::cout << "-\n";
    }
}

