// Function to get prime factors of a number
// Returns a vector of pairs: (prime_factor, exponent)
std::vector<std::pair<long long, int>> get_prime_factors(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // Let p = k * q.
        // We are looking for x = p / d such that x % q != 0.
        // This means (p / d) % q != 0.
        // We want to maximize p / d, which means minimizing d.
        // The smallest d that makes (p/d) % q != 0 is what we need.

        // Consider prime factors of q.
        // If x is not divisible by q, then there must be at least one prime factor f of q
        // such that the exponent of f in x is less than its exponent in q.

        std::vector<std::pair<long long, int>> q_factors = get_prime_factors(q);
        long long max_x = 1; // Since p >= 1, there's always at least 1.

        for (const auto& factor_pair : q_factors) {
            long long f = factor_pair.first;
            // int q_exp = factor_pair.second; // Not directly needed, we just need f

            // Calculate the largest power of f that divides p
            long long current_p = p;
            long long p_f_power = 1;
            while (current_p > 0 && current_p % f == 0) {
                current_p /= f;
                p_f_power *= f;
            }

            // The candidate x is p / f_power.
            // This x has one less factor of f than p_f_power.
            // If p_f_power is f^k, then p / f_power is p / f^k.
            // We need to remove factors of f from p until p is no longer divisible by f.
            // Then we divide p by f.
            // Example: p=12, q=6. q_factors = {2:1, 3:1}.
            // For f=2: p=12. p_f_power = 2^2 = 4. current_p = 3.
            // Candidate x = p / (p_f_power / f) = 12 / (4/2) = 12 / 2 = 6.
            // This is wrong. We need to remove factors of f from p until p is no longer divisible by q.
            // The logic should be:
            // For each prime factor f of q:
            //   Find the largest power of f, say f^k, such that f^k divides p.
            //   Then p / f^k is a divisor of p that is not divisible by f.
            //   This p / f^k is a candidate for x.
            //   We want the largest such x.

            // Let's re-evaluate.
            // We are looking for x = p / d such that x % q != 0.
            // This means p / d is not divisible by q.
            // This means there is some prime factor f of q such that the exponent of f in p/d
            // is less than its exponent in q.

            // Consider a prime factor f of q.
            // Let p = f^a * P_rem, where P_rem is not divisible by f.
            // Let q = f^b * Q_rem, where Q_rem is not divisible by f.
            // Since p is divisible by q, we must have a >= b.
            // We want to find x = p / d such that x is not divisible by q.
            // To make x not divisible by q, we can make x not divisible by f^b.
            // The largest divisor of p that is not divisible by f^b is p / f^(a - (b-1)) = p / f^(a-b+1).
            // This is because if we divide p by f^(a-b+1), the exponent of f in x becomes a - (a-b+1) = b-1.
            // Since b-1 < b, x is not divisible by f^b, and thus not divisible by q.
            // We want to maximize x, so we want to minimize the divisor d.
            // The smallest d that makes x not divisible by f^b is f^(a-b+1).
            // So, for each prime factor f of q, a candidate for x is p / f^(a-b+1).
            // We take the maximum of these candidates.

            long long current_p_copy = p;
            long long p_exp_f = 0; // exponent of f in p
            while (current_p_copy > 0 && current_p_copy % f == 0) {
                current_p_copy /= f;
                p_exp_f++;
            }

            long long current_q_copy = q;
            long long q_exp_f = 0; // exponent of f in q
            while (current_q_copy > 0 && current_q_copy % f == 0) {
                current_q_copy /= f;
                q_exp_f++;
            }

            // The divisor we need to remove from p is f^(p_exp_f - q_exp_f + 1)
            // This ensures that the exponent of f in x becomes q_exp_f - 1, which is less than q_exp_f.
            long long divisor_to_remove = 1;
            for (int i = 0; i < p_exp_f - q_exp_f + 1; ++i) {
                divisor_to_remove *= f;
            }

            max_x = std::max(max_x, p / divisor_to_remove);
        }
        std::cout << max_x << "\n";
    }

    return 0;
}

#include <iostream>
