void solve() {
    int n;
    std::cin >> n;

    long long min_x = -2000000000LL; // Effectively negative infinity
    long long max_x = 2000000000LL;  // Effectively positive infinity
    long long min_y = -2000000000LL; // Effectively negative infinity
    long long max_y = 2000000000LL;  // Effectively positive infinity

    for (int i = 0; i < n; ++i) {
        long long x, y;
        int f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1 = 0: cannot move left (x_c - 1).
        // If robot is at (x, y) and cannot move left, it means it cannot reach any point (X, Y) where X < x.
        // So, X must be >= x. This implies X_min for this robot is x.
        if (f1 == 0) { // Cannot move left
            min_x = std::max(min_x, x);
        }
        // f3 = 0: cannot move right (x_c + 1).
        // If robot is at (x, y) and cannot move right, it means it cannot reach any point (X, Y) where X > x.
        // So, X must be <= x. This implies X_max for this robot is x.
        if (f3 == 0) { // Cannot move right
            max_x = std::min(max_x, x);
        }
        // f4 = 0: cannot move down (y_c - 1).
        // If robot is at (x, y) and cannot move down, it means it cannot reach any point (X, Y) where Y < y.
        // So, Y must be >= y. This implies Y_min for this robot is y.
        if (f4 == 0) { // Cannot move down
            min_y = std::max(min_y, y);
        }
        // f2 = 0: cannot move up (y_c + 1).
        // If robot is at (x, y) and cannot move up, it means it cannot reach any point (X, Y) where Y > y.
        // So, Y must be <= y. This implies Y_max for this robot is y.
        if (f2 == 0) { // Cannot move up
            max_y = std::min(max_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        // A valid point exists. The problem guarantees that if a point exists,
        // one exists with coordinates not exceeding 10^5 by absolute value.
        // We can pick any point within the valid range.
        // For example, (min_x, min_y) or (max_x, max_y) or (0,0) if it's in range.
        // The problem statement says "X and Y should not exceed 10^5 by absolute value".
        // The initial coordinates are up to 10^5. So min_x, max_x, min_y, max_y can be up to 10^5.
        // We can just output min_x and min_y.
        std::cout << 1 << " " << min_x << " " << min_y << "\n";
    } else {
        std::cout << 0 << "\n";
    }
}

