#include <iostream>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;
        long long N = std::abs(n);
        long long M = std::abs(m);

        if (N > k || M > k) {
            std::cout << -1 << "\n";
            continue;
        }

        long long min_coord = std::min(N, M);
        long long max_coord = std::max(N, M);

        long long remaining_moves = k - min_coord;
        long long remaining_diff = max_coord - min_coord;

        if (remaining_moves < remaining_diff) {
            std::cout << -1 << "\n";
            continue;
        }

        long long ans;
        if ((remaining_moves - remaining_diff) % 2 == 0) {
            // All remaining_diff moves can be axial, then remaining_moves - remaining_diff moves are pairs of +1/-1 axial moves.
            // Each pair of +1/-1 axial moves can be converted to two diagonal moves if parity allows.
            // The total number of moves is k.
            // The number of diagonal moves is min_coord + (k - min_coord - remaining_diff)
            // This simplifies to k - remaining_diff = k - (max_coord - min_coord)
            ans = k - (max_coord - min_coord);
        } else {
            // If (remaining_moves - remaining_diff) is odd, we must use one more axial move to adjust parity.
            // This means we effectively use one less diagonal move.
            // The target (N, M) has a certain parity sum (N+M).
            // After min_coord diagonal moves, we are at (min_coord, min_coord).
            // We need to reach (max_coord, min_coord) or (min_coord, max_coord) using remaining_diff axial moves.
            // Then we need to make (k - min_coord - remaining_diff) moves.
            // If (k - min_coord - remaining_diff) is odd, we cannot make all of them diagonal pairs.
            // We must use one axial move to change parity.
            // This means we use k-1 moves to reach a point with the same parity as (N,M) and then one more axial move.
            // The maximum number of diagonal moves would be k-1.
            // However, we need to consider the parity of (N+M) and k.
            // If (N+M) and k have different parities, it's impossible to reach (N,M) in k moves.
            // Each move changes (x+y) by an odd amount (1 or 2).
            // (x_new + y_new) - (x_old + y_old) = (dx + dy).
            // dx, dy are in {-1, 0, 1}.
            // If diagonal: dx, dy are non-zero. dx+dy is -2, 0, or 2 (even).
            // If axial: one of dx, dy is zero, other is non-zero. dx+dy is -1 or 1 (odd).
            // This is incorrect. (x+y) changes by dx+dy.
            // (x_new + y_new) % 2 = (x_old + y_old + dx + dy) % 2.
            // For diagonal move: dx, dy are +/-1. dx+dy is 0 or +/-2. So (dx+dy) is even. Parity of (x+y) does not change.
            // For axial move: one of dx, dy is 0, other is +/-1. So (dx+dy) is +/-1. Parity of (x+y) changes.
            // Starting at (0,0), (x+y) is 0 (even).
            // After k moves, (N+M) must have the same parity as k_axial_moves.
            // (N+M) % 2 == (number of axial moves) % 2.
            // (N+M) % 2 == (k - number of diagonal moves) % 2.
            // We want to maximize diagonal moves, so minimize axial moves.
            // Minimum axial moves is max_coord - min_coord if k >= max_coord.
            // If k - (max_coord - min_coord) is odd, then we need to make one more axial move.
            // So the number of axial moves will be (max_coord - min_coord) + 1.
            // This means total diagonal moves will be k - ((max_coord - min_coord) + 1).
            // This is k - (max_coord - min_coord) - 1.
            ans = k - (max_coord - min_coord) - 1;
        }
        std::cout << ans << "\n";
    }
    return 0;
}

