    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> present_in_s;

    for (char c = 'a'; c <= 'z'; ++c) {
        adj[c] = std::set<char>();
    }

    for (size_t i = 0; i < s.length(); ++i) {
        present_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i-1]);
            adj[s[i-1]].insert(s[i]);
        }
    }

    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::set<char> visited;

    // Find a starting point for a chain (a character with only one required neighbor)
    char start_char = '\0';
    for (char c : present_in_s) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If no character has only one required neighbor, it means all present characters
    // either have 0 required neighbors (isolated) or 2 required neighbors (part of a cycle).
    // If there's a cycle, it must be a single cycle involving all present_in_s characters.
    // If there are isolated characters, we can pick any of them as a start.
    // If present_in_s is empty (s is empty), this logic still works, start_char remains '\0'.
    if (start_char == '\0' && !present_in_s.empty()) {
        // All present characters have 2 neighbors, implying a cycle.
        // Pick any character from present_in_s to start.
        start_char = *present_in_s.begin();
    } else if (start_char == '\0' && present_in_s.empty()) {
        // s is empty, any layout is fine.
        // We'll handle this by letting the loop below not run, and then appending remaining chars.
    }

    if (start_char != '\0') {
        char current = start_char;
        char prev = '\0'; // Sentinel for the previous character in the chain

        while (visited.find(current) == visited.end()) {
            layout += current;
            visited.insert(current);

            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }

            if (next_char == '\0') { // End of chain or cycle completed
                break;
            }
            prev = current;
            current = next_char;
        }
    }

    // Check if all characters from 's' that have required neighbors are included in the layout.
    // This implicitly checks for multiple disjoint chains/cycles among present_in_s characters.
    for (char c : present_in_s) {
        if (adj[c].size() > 0 && visited.find(c) == visited.end()) {
            std::cout << "NO\n";
            return;
        }
    }

    // Append remaining unvisited characters (those not in 's' or isolated in 's')
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

