int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (no internal elements to change)
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> L(n, 0), R(n, 0);

    // Calculate L[i]: length of consecutive 0s ending at i
    // Calculate R[i]: length of consecutive 0s starting at i
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            L[i] = (i > 0 ? L[i - 1] : 0) + 1;
        } else {
            L[i] = 0;
        }
    }
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 0) {
            R[i] = (i < n - 1 ? R[i + 1] : 0) + 1;
        } else {
            R[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            // Find the nearest 0 to the left and right
            // If a[i] is 1, L[i] is 0. We need to look at L[i-1]
            // If a[i] is 1, R[i] is 0. We need to look at R[i+1]
            int left_zeros = (i > 0) ? L[i - 1] : 0;
            int right_zeros = (i < n - 1) ? R[i + 1] : 0;

            if (left_zeros == 0 && right_zeros == 0) {
                // This 1 is surrounded by 1s or boundaries, it will never change to 0.
                // It will remain 1.
                // If it's 1, it needs 0 steps to stabilize.
                // This case doesn't affect max_k for changing 1s to 0s.
            } else if (left_zeros == 0) { // Only right zeros
                max_k = std::max(max_k, (right_zeros + 1) / 2);
            } else if (right_zeros == 0) { // Only left zeros
                max_k = std::max(max_k, (left_zeros + 1) / 2);
            } else { // Zeros on both sides
                max_k = std::max(max_k, std::min(left_zeros, right_zeros));
            }
        }
    }

    std::cout << max_k << std::endl;

    std::vector<int> final_a = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 1) {
            int left_zeros = (i > 0) ? L[i - 1] : 0;
            int right_zeros = (i < n - 1) ? R[i + 1] : 0;

            if (left_zeros == 0 && right_zeros == 0) {
                // Surrounded by 1s or boundaries, remains 1.
                final_a[i] = 1;
            } else if (left_zeros == 0) { // Only right zeros
                if (max_k >= (right_zeros + 1) / 2) {
                    final_a[i] = 0;
                } else {
                    final_a[i] = 1;
                }
            } else if (right_zeros == 0) { // Only left zeros
                if (max_k >= (left_zeros + 1) / 2) {
                    final_a[i] = 0;
                } else {
                    final_a[i] = 1;
                }
            } else { // Zeros on both sides
                if (max_k >= std::min(left_zeros, right_zeros)) {
                    final_a[i] = 0;
                } else {
                    final_a[i] = 1;
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_s = 0;
    int initial_b = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s++;
        } else {
            initial_b++;
        }
    }

    // Calculate prefix sums for differences (1 for strawberry, -1 for blueberry)
    // For left part (indices 0 to n-1), prefix sums from left to right
    // For right part (indices n to 2n-1), prefix sums from right to left

    // Left part: a[0]...a[n-1]
    // diff_L[k] = (count of 1s in a[0...k-1]) - (count of 2s in a[0...k-1])
    // k jars removed from left means jars a[0]...a[k-1] are removed.
    // The remaining jars on the left are a[k]...a[n-1].
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Right part: a[n]...a[2n-1]
    // diff_R[k] = (count of 1s in a[2n-1]...a[2n-k]) - (count of 2s in a[2n-1]...a[2n-k])
    // k jars removed from right means jars a[2n-k]...a[2n-1] are removed.
    // The remaining jars on the right are a[n]...a[2n-k-1].
    std::vector<int> diff_R(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_R[i + 1] = diff_R[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars removed from the left
    // to achieve a certain difference in the remaining left segment.
    // key: difference, value: number of jars removed from left
    std::map<int, int> left_diff_to_removed_count;

    // Iterate through all possible numbers of jars removed from the left (0 to n)
    // Let k be the number of jars removed from the left.
    // The jars a[0]...a[k-1] are removed.
    // The remaining jars on the left are a[k]...a[n-1].
    // The difference for these remaining jars is diff_L[n] - diff_L[k].
    // The number of jars removed is k.
    for (int k = 0; k <= n; ++k) {
        int current_left_diff = diff_L[n] - diff_L[k];
        if (left_diff_to_removed_count.find(current_left_diff) == left_diff_to_removed_count.end()) {
            left_diff_to_removed_count[current_left_diff] = k;
        } else {
            left_diff_to_removed_count[current_left_diff] = std::min(left_diff_to_removed_count[current_left_diff], k);
        }
    }

    int min_total_removed = 2 * n; // Initialize with max possible removals

    // Iterate through all possible numbers of jars removed from the right (0 to n)
    // Let k be the number of jars removed from the right.
    // The jars a[2n-k]...a[2n-1] are removed.
    // The remaining jars on the right are a[n]...a[2n-k-1].
    // The difference for these remaining jars is diff_R[n] - diff_R[k].
    // Note: diff_R is calculated from right to left.
    // So, diff_R[k] is the difference of the k jars removed from the right.
    // The total difference of all jars on the right (a[n]...a[2n-1]) is diff_R[n].
    // The difference of the remaining jars on the right is diff_R[n] - diff_R[k].
    for (int k = 0; k <= n; ++k) {
        int current_right_diff = diff_R[n] - diff_R[k];
        // We need (remaining_left_s - remaining_left_b) + (remaining_right_s - remaining_right_b) = 0
        // So, remaining_left_diff + remaining_right_diff = 0
        // This means remaining_left_diff = -remaining_right_diff
        int target_left_diff = -current_right_diff;

        if (left_diff_to_removed_count.count(target_left_diff)) {
            int removed_from_left = left_diff_to_removed_count[target_left_diff];
            min_total_removed = std::min(min_total_removed, removed_from_left + k);
        }
    }

    std::cout << min_total_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Max length for which 2^L-1 is within reasonable bounds for direct calculation
    // 2^18-1 is ~2.6e5, 2^19-1 is ~5.2e5. Max N is 2e5.
    // If L > 19, then 2^L-1 > N.
    // If a substring has length L, its value is at most 2^L-1.
    // If L > 19, then 2^L-1 > 2e5.
    // If s_l...s_r is good, then its length L must equal its value V.
    // If L > 19, then V >= 2^19-1 > 2e5.
    // But the maximum possible length of any substring is N <= 2e5.
    // So, if L > 19, then V > N >= L, meaning L != V.
    // Thus, any good substring must have length L <= 19.
    // Let's pick a slightly safer upper bound, say 20 or 21, to avoid off-by-one issues with powers of 2.
    // Max length of s is 2e5.
    // If length L = 18, max value is 2^18-1 = 262143. This can be > N.
    // If length L = 19, max value is 2^19-1 = 524287. This can be > N.
    // The condition is L = V.
    // If L > 19, then V >= 2^L-1.
    // If L > 19, then V >= 2^19-1 = 524287.
    // But L itself is at most N = 2e5.
    // So if L > 19, then V > L. Thus L != V.
    // So we only need to check substrings of length up to 19.
    // Let's use a constant `MAX_LEN_CHECK` for this, say 20.
    const int MAX_LEN_CHECK = 20; // Max length of substring to check directly

    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', it can only be the start of a good substring if its value is 0.
            // This means the substring must be "0". Length 1, value 0. Not good.
            // Or "00", length 2, value 0. Not good.
            // Or "01", length 2, value 1. Not good.
            // A substring starting with '0' can only be good if its value is 0.
            // If its value is 0, its length must be 0, which is impossible for a non-empty substring.
            // So, a good substring cannot start with '0' unless its value is 0.
            // The only way for a binary string to have value 0 is if all its digits are '0'.
            // If s_l...s_r consists of only '0's, its value is 0.
            // For it to be good, its length must be 0, which is impossible.
            // Therefore, a good substring must start with '1'.
            // This is a crucial observation.
            // Wait, the problem statement says f(000) = 0.
            // If s_l...s_r = "000", length is 3, value is 0. 3 != 0. Not good.
            // So, a good substring must indeed start with '1'.
            // This means we only need to iterate `i` over indices where `s[i] == '1'`.
            // This is incorrect. The example says s = 0110, good substrings: 011.
            // s_2...s_4 = 011. Length 3. f(011) = 3. This is good.
            // So a good substring CAN start with '0'.
            // The definition of f(t) allows leading zeros.
            // My initial reasoning was flawed.
            // Let's re-evaluate.
            // For s_l...s_r = "011", l=2, r=4. Length = 3. f("011") = 3. Good.
            // For s_l...s_r = "000", length = 3. f("000") = 0. Not good.
            // So, we must iterate over all possible starting positions `i`.
            // And for each `i`, iterate over possible ending positions `j`.

            // Optimization: If s[i] == '0', we can skip some checks.
            // If s[i] == '0', then the value of s[i...j] will be the same as s[i+1...j]
            // if s[i+1...j] is not empty.
            // This means if s[i...j] is good, then length(s[i...j]) = value(s[i...j]).
            // length(s[i...j]) = j - i + 1.
            // value(s[i...j]) = value(s[i+1...j]).
            // So, j - i + 1 = value(s[i+1...j]).
            // This means we can potentially find good substrings starting with '0'.
            // Example: s = "011", i=0.
            // j=0: "0". len=1, val=0. Not good.
            // j=1: "01". len=2, val=1. Not good.
            // j=2: "011". len=3, val=3. Good.
            // So, we must iterate over all `i`.
        }

        long long current_val = 0;
        for (int j = i; j < std::min(n, i + MAX_LEN_CHECK); ++j) {
            current_val = (current_val << 1) | (s[j] - '0');
            long long len = j - i + 1;
            if (current_val == len) {
                good_substrings_count++;
            }
        }

        // For substrings longer than MAX_LEN_CHECK, their value will be too large.
        // If len > MAX_LEN_CHECK, then current_val >= 2^(len-1).
        // If len > MAX_LEN_CHECK, and MAX_LEN_CHECK is 20, then len >= 21.
        // current_val >= 2^20 = 1048576.
        // But len <= n <= 2e5.
        // So current_val will always be strictly greater than len for len > MAX_LEN_CHECK.
        // Thus, no good substrings exist for len > MAX_LEN_CHECK.
        // This is correct. The loop for `j` can stop at `i + MAX_LEN_CHECK - 1`.
        // The `std::min(n, i + MAX_LEN_CHECK)` correctly handles this.
    }

    std::cout << good_substrings_count << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> dp_y(n + 1, -2); // -2: uncomputed, -1: infinite loop, >=0: final y
    std::vector<int> dp_x(n + 1, 0);     // 0: uncomputed, -1: infinite loop, >=1: final x

    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for the current run

        long long current_y = 0;
        int current_x = 1;

        // First pair of operations (x+a_x, y+a_x) then (x-a_x, y+a_x)
        // This is special because x starts at 1.
        // After this, x becomes 1 + a[1] - a[1+a[1]]
        // and y becomes a[1] + a[1+a[1]]

        // Step 2: x = x + a_x, y = y + a_x
        current_y += a[current_x];
        current_x += a[current_x];

        // Check termination after first step 2
        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
            continue;
        }

        // Step 3: y = y + a_x, x = x - a_x
        current_y += a[current_x];
        current_x -= a[current_x];

        // Check termination after first step 3
        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
            continue;
        }

        // Now current_x is the starting point for subsequent iterations
        // and current_y is the accumulated y value.
        // We need to find the result for starting at current_x with y=0
        // and add it to current_y.

        if (dp_y[current_x] != -2) { // If already computed or known to loop
            if (dp_y[current_x] == -1) {
                std::cout << -1 << "\n";
            } else {
                std::cout << current_y + dp_y[current_x] << "\n";
            }
            continue;
        }

        // If not computed, compute it using path compression / cycle detection
        std::vector<int> path;
        int temp_x = current_x;
        long long temp_y = 0;

        while (temp_x > 0 && temp_x <= n && dp_y[temp_x] == -2) {
            path.push_back(temp_x);
            dp_y[temp_x] = -1; // Mark as visited (potentially in a cycle)
            dp_x[temp_x] = -1;

            // Step 2: x = x + a_x, y = y + a_x
            temp_y += a[temp_x];
            temp_x += a[temp_x];

            if (temp_x <= 0 || temp_x > n) {
                break; // Terminated
            }

            // Step 3: y = y + a_x, x = x - a_x
            temp_y += a[temp_x];
            temp_x -= a[temp_x];
        }

        long long final_y_val;
        int final_x_val;

        if (temp_x <= 0 || temp_x > n) { // Terminated
            final_y_val = temp_y;
            final_x_val = temp_x; // Not used, but for consistency
        } else if (dp_y[temp_x] == -1) { // Cycle detected
            final_y_val = -1;
            final_x_val = -1;
        } else { // Reached an already computed state
            final_y_val = temp_y + dp_y[temp_x];
            final_x_val = dp_x[temp_x];
        }

        // Propagate results back along the path
        for (int node_x : path) {
            if (final_y_val == -1) {
                dp_y[node_x] = -1;
                dp_x[node_x] = -1;
            } else {
                dp_y[node_x] = final_y_val;
                dp_x[node_x] = final_x_val;
            }
        }

        if (final_y_val == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << current_y + final_y_val << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
