struct Item {
    int value;
    int original_index;
};

bool compareItems(const Item& a, const Item& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<Item> a(n);
        std::vector<Item> b(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i].value;
            a[i].original_index = i;
        }
        for (int i = 0; i < n; ++i) {
            std::cin >> b[i].value;
            b[i].original_index = i;
        }

        std::sort(a.begin(), a.end(), compareItems);
        std::sort(b.begin(), b.end(), compareItems);

        std::vector<int> x(n);
        std::vector<int> y(n);

        for (int i = 0; i < n; ++i) {
            x[a[i].original_index] = a[i].value;
            y[a[i].original_index] = b[n - 1 - i].value;
        }

        for (int i = 0; i < n; ++i) {
            std::cout << x[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << y[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long min_val = a[0];
    long long operations = 0;

    for (int i = 1; i < n; ++i) {
        // For each pile a[i] (which is not the smallest),
        // we can add min_val to it as many times as possible
        // without exceeding k.
        // The current value of this pile is a[i].
        // We can add min_val until a[i] + min_val * count > k.
        // So, min_val * count <= k - a[i].
        // count <= (k - a[i]) / min_val.
        // Since count must be an integer, count = floor((k - a[i]) / min_val).

        if (a[i] >= k) {
            // If a[i] is already >= k, we cannot add anything to it.
            // This case is technically covered by the calculation below
            // if k - a[i] becomes negative or zero.
            continue;
        }

        long long remaining_capacity = k - a[i];
        operations += remaining_capacity / min_val;
    }

    std::cout << operations << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists.
    // Reversing the permutation is a common strategy for problems
    // involving adjacent sums or differences, as it often preserves
    // the set of absolute differences or sums.
    //
    // Let p = [p_1, p_2, ..., p_n].
    // The sums are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    //
    // Let p' be the reversed permutation: p' = [p_n, p_{n-1}, ..., p_1].
    // The sums for p' are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    //
    // This is the same multiset of sums as for p, just in reverse order.
    // Since the fingerprint F(p) is the *sorted* array of these sums,
    // F(p) will be equal to F(p').
    //
    // For p' to be different from p, we need p_i != p'_i for some i.
    // This means p_i != p_{n-i+1} for some i.
    // If p is a palindrome (p_i = p_{n-i+1} for all i), then p' would be equal to p.
    // However, a permutation of length n cannot be a palindrome if n > 1.
    // For example, if n=2, p=[1,2], p'=[2,1]. They are different.
    // If n=3, p=[1,2,3], p'=[3,2,1]. They are different.
    //
    // A permutation of length n contains distinct integers from 1 to n.
    // If p were a palindrome, then p_1 = p_n, p_2 = p_{n-1}, etc.
    // But all elements must be distinct.
    // This implies that if n > 1, p_1 must be different from p_n.
    // If p_1 = p_n, then p_1 and p_n are the same element, which contradicts
    // the definition of a permutation (all elements distinct).
    // Therefore, p_1 != p_n for any permutation of length n > 1.
    // Since p_1 != p_n, then p_1 != p'_1 (because p'_1 = p_n).
    // Thus, p' is always different from p for n > 1.
    // The problem states n >= 2.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

