        int n, d;
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        int current_a1 = a[0];
        for (int i = 1; i < n; ++i) {
            // Cost to move one haybale from pile i+1 (1-indexed) to pile 1 (1-indexed)
            // is i days (0-indexed pile i to 0-indexed pile 0).
            int cost_per_haybale = i; 

            if (d >= cost_per_haybale) {
                // Calculate how many haybales can be moved from pile i
                // given the remaining days and the cost per haybale.
                int haybales_to_move = std::min(a[i], d / cost_per_haybale);

                current_a1 += haybales_to_move;
                d -= haybales_to_move * cost_per_haybale;
            } else {
                // Not enough days to move even one haybale from this pile.
                // Since piles are processed in increasing order of distance (cost),
                // we won't be able to move haybales from any further piles either.
                break; 
            }
        }
        std::cout << current_a1 << std::endl;
    }
    return 0;
}

