            // 3. The number is not divisible by 2 (ends in 3, an odd digit).
            // 4. The number is not divisible by 3 (sum of digits: 2 + (n-2)*7 + 3 = 5 + 7n - 14 = 7n - 9.
            //    For n=2, sum=5. Not div by 3.
            //    For n=3, sum=12. Div by 3. This construction fails for n=3.
            //    Let's re-evaluate.
            //
            // A simpler construction:
            // First digit 2.
            // All other n-1 digits are 3.
            // Example: n=2 -> 23
            //          n=3 -> 233
            //          n=4 -> 2333
            //
            // Check divisibility for 233...3:
            // 1. Not divisible by 2 (ends in 3).
            // 2. Not divisible by 3 (sum of digits is 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
            //    If 3n-1 is divisible by 3, then -1 must be divisible by 3, which is false.
            //    So, 3n-1 is never divisible by 3.
            // This construction works for all n >= 2.

            std::cout << '2';
            for (int i = 0; i < n - 1; ++i) {
                std::cout << '3';
            }
            std::cout << "\n";
        }
    }
    return 0;
}

