#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    // Initialize min_suffix with the last element, as it's the minimum of the suffix starting at n-1.
    // The last element a[n-1] can never be a bad price because there are no days after it.
    int min_suffix = a[n - 1]; 

    // Iterate from the second to last element down to the first element.
    // For each element a[i], we compare it with the minimum price found in the suffix a[i+1...n-1].
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix, it means a[i] is a new minimum
            // or equal to the current minimum in the suffix.
            // Update min_suffix to be the minimum of a[i] and the previous min_suffix.
            // This is equivalent to min_suffix = std::min(a[i], min_suffix);
            min_suffix = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

