int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic works because if p[i] is n, then all a[i][j] (j!=i) are p[j].
        // The maximum of these p[j] values would be n-1 (the largest among the other n-1 elements).
        // If p[i] is not n, then there is some p[k] = n.
        // For that k, a[k][i] = min(p[k], p[i]) = min(n, p[i]) = p[i].
        // So, p[i] will appear in row k.
        // For row i, max_val_in_row will be p[i] if p[i] is not n.
        // This is because if p[i] is not n, there must be some p[j] > p[i].
        // For such j, a[i][j] = min(p[i], p[j]) = p[i].
        // If all p[j] < p[i], then p[i] must be n.
        // So, if max_val_in_row is n-1, it means p[i] is n.
        // Otherwise, p[i] is max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

