#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_R_pos = -1; // Represents the position of the last 'R' or the starting cell 0.
                             // If last_R_pos = -1, it means the frog is at cell 0.
                             // If last_R_pos = i, it means the frog is at cell i.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed for string characters, 0-indexed for cells).
                // The frog is at cell i+1.
                // The previous 'R' or start was at last_R_pos.
                // The gap is (i+1) - last_R_pos.
                max_gap = std::max(max_gap, (i + 1) - last_R_pos);
                last_R_pos = i + 1;
            }
        }

        // After iterating through the string, consider the jump from the last 'R' position
        // to the target cell n+1.
        // The last 'R' was at last_R_pos.
        // The target is n+1.
        // The gap is (n+1) - last_R_pos.
        max_gap = std::max(max_gap, (n + 1) - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

