#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the triangle from the apex to a cut at distance x
        // is proportional to x^2.
        // Specifically, Area(x) = (x^2 / h^2) * Area(total)
        // Area(total) = (1/2) * base * h = (1/2) * 1 * h = h/2
        // So, Area(x) = (x^2 / h^2) * (h/2) = x^2 / (2h)

        // We want the i-th cut to define a triangle from the apex
        // that has an area equal to i times the area of one piece.
        // Each piece has area (h/2) / n = h / (2n).
        // So, Area(x_i) = i * (h / (2n))

        // Equating the two expressions for Area(x_i):
        // x_i^2 / (2h) = i * h / (2n)
        // x_i^2 = i * h^2 / n
        // x_i = sqrt(i * h^2 / n)
        // x_i = h * sqrt(i / n)

        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used to generate differences 1 to k.

    // Generate k distinct differences: 1, 2, ..., k
    // We use numbers from 1 to k+1 to achieve this.
    // The pattern is: 1, (k+1), 2, k, 3, (k-1), ...
    // This generates differences: k, k-1, k-2, ..., 1.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
    }

    // The remaining numbers are k+2, k+3, ..., n.
    // Append them in increasing order to avoid introducing new distinct differences.
    // The last number used was either `left-1` or `right+1`.
    // If `k` is even, the last number used was `right+1`. `left` is `k/2 + 1`. `right` is `k/2 + 1`.
    // If `k` is odd, the last number used was `left-1`. `left` is `(k+1)/2 + 1`. `right` is `(k+1)/2`.
    // In both cases, `left` points to the next available smallest number.
    // `right` points to the next available largest number.
    // The numbers used are `1, ..., k+1`.
    // The next number to append is `k+2`.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents the number of stairs in the current staircase (1, 3, 7, 15, ...)
        while (true) {
            // Cost of a staircase with k stairs is k * (k + 1) / 2
            // For k = 1, cost = 1
            // For k = 3, cost = 6
            // For k = 7, cost = 28
            // For k = 15, cost = 120
            long long cost_of_staircase = k * (k + 1) / 2;

            if (current_cost + cost_of_staircase <= x) {
                current_cost += cost_of_staircase;
                count++;
                // Next k will be 2*k + 1
                // To avoid overflow, check if k can be safely multiplied by 2 and added 1
                // Max k is around 2*10^9 for cost to be 2*10^18.
                // If k is already large, 2*k+1 might overflow.
                // However, k * (k+1)/2 is the actual cost.
                // If k is 2*10^9, k*(k+1)/2 is approx 2*10^18.
                // The next k would be 4*10^9, which is fine for long long.
                // The next cost would be (4*10^9)^2 / 2 = 8*10^18, which is also fine.
                // The maximum value of k for which k*(k+1)/2 <= 10^18 is when k is approx sqrt(2*10^18) = 1.414 * 10^9.
                // So k will not exceed long long limits.
                k = 2 * k + 1;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

