        } else if (c == ')' && close_needed > 0) {
            // We can only add a ')' if we have already added an opening bracket
            // for it, or if we are just trying to balance the sequence.
            // Since we are guaranteed a solution exists and we are picking
            // k/2 open and k/2 close, we can just add it if needed.
            // The balance check is implicitly handled by ensuring we pick
            // k/2 of each.
            result += ')';
            close_needed--;
        }
        if (open_needed == 0 && close_needed == 0) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m > n) {
            std::cout << 0 << "\n";
            continue;
        }

        long long count = n / m; // Number of multiples of m up to n

        // Calculate the sum of last digits for one cycle (10 multiples of m)
        // The last digits are (m % 10), (2m % 10), ..., (10m % 10)
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_sum += (static_cast<long long>(i) * m) % 10;
        }

        // Number of full cycles
        long long num_full_cycles = count / 10;
        long long total_sum = num_full_cycles * cycle_sum;

        // Remaining multiples after full cycles
        long long remaining_multiples = count % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (i * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
