void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i...n-1] is non-decreasing.
    // This means a[i] <= a[i+1] <= ... <= a[n-1].
    // If we remove elements up to index `i-1`, the remaining suffix starts with a[i].
    // This suffix is a candidate for the "right part" of the good array.
    int right_decreasing_idx = n - 1;
    while (right_decreasing_idx > 0 && a[right_decreasing_idx - 1] >= a[right_decreasing_idx]) {
        right_decreasing_idx--;
    }

    // Now, `a[right_decreasing_idx ... n-1]` is non-decreasing.
    // We need to find the rightmost index `j` such that `a[0...j]` is non-increasing.
    // This means `a[0] >= a[1] >= ... >= a[j]`.
    // If we remove elements from index `j+1` onwards, the remaining prefix ends with a[j].
    // This prefix is a candidate for the "left part" of the good array.
    int left_increasing_idx = right_decreasing_idx;
    while (left_increasing_idx > 0 && a[left_increasing_idx - 1] <= a[left_increasing_idx]) {
        left_increasing_idx--;
    }

    // The elements from `a[0]` to `a[left_increasing_idx - 1]` must be removed.
    // The length of this prefix is `left_increasing_idx`.
    std::cout << left_increasing_idx << std::endl;
}

