void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] = index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // For m > 1, we need to expand the segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from min_idx_of_1_to_m to max_idx_of_1_to_m.
        // Let's maintain current_min_idx and current_max_idx for numbers 1 to m-1.
        // When we consider 'm', we update current_min_idx and current_max_idx
        // to include the position of 'm'.

        // Update min/max indices to include the position of 'm'
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the segment [current_min_idx, current_max_idx]
        // has length 'm'.
        // The length of this segment is current_max_idx - current_min_idx + 1.
        if (current_max_idx - current_min_idx + 1 == m) {
            result[m - 1] = '1';
        }
    }

    std::cout << result << std::endl;
}

