int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // d^2 - 4d >= 0 is true for d >= 4
            // a = (d + sqrt(d^2 - 4d)) / 2
            // b = (d - sqrt(d^2 - 4d)) / 2
            // Both a and b will be non-negative.
            // sqrt(d^2 - 4d) is real.
            // d + sqrt(d^2 - 4d) is clearly positive.
            // d - sqrt(d^2 - 4d):
            // We need to check if d - sqrt(d^2 - 4d) >= 0
            // d >= sqrt(d^2 - 4d)
            // d^2 >= d^2 - 4d (since d >= 0, both sides are non-negative, so squaring preserves inequality)
            // 0 >= -4d
            // 4d >= 0
            // This is true since d >= 0.
            // So both a and b are non-negative.

            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            std::cout << std::fixed << std::setprecision(9) << "Y " << a << " " << b << "\n";
        }
    }
    return 0;
}

