int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int left_ptr = 0; // Pointer for elements to be placed (the 'b' array elements)
    int right_ptr = 0; // Pointer for original array elements (the 'a' array elements)

    while (left_ptr < n && right_ptr < n) {
        // We are trying to find an element a[left_ptr] from the sorted array
        // that can be placed at a position originally occupied by a[right_ptr]
        // such that a[left_ptr] > a[right_ptr].
        // Since both arrays are sorted, if a[left_ptr] > a[right_ptr],
        // we found a valid pair. We increment both pointers and the count.
        // If a[left_ptr] <= a[right_ptr], then a[left_ptr] cannot be greater
        // than a[right_ptr]. To potentially find a greater element, we must
        // advance left_ptr to a larger value. We keep right_ptr fixed for now.
        if (a[left_ptr] > a[right_ptr]) {
            count++;
            left_ptr++;
            right_ptr++;
        } else {
            left_ptr++;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareElementsA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareElementsB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> A(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A[i].value;
        A[i].original_index = i;
    }

    std::vector<ElementB> B(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B[i].value;
        B[i].original_index = i;
    }

    std::sort(A.begin(), A.end(), compareElementsA);
    std::sort(B.begin(), B.end(), compareElementsB);

    std::vector<long long> result_A_prime(m);

    for (int i = 0; i < m; ++i) {
        // The i-th smallest B[i].value should be paired with the (m-1-i)-th smallest A[i].value
        // to maximize (A[i].value + 1) / (B[i].value + 1)
        // This means the i-th smallest B[i].value (B[i] after sorting)
        // is paired with the (m-1-i)-th smallest A[i].value (A[m-1-i] after sorting).
        // The original index of this B value is B[i].original_index.
        // The value from A is A[m-1-i].value.
        result_A_prime[B[i].original_index] = A[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_A_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 != 0) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            // Check if N is a power of 2
            // A number is a power of 2 if (N & (N - 1)) == 0
            if ((n & (n - 1)) == 0) { // N is a power of 2
                chanek_coins += n / 2;
                n /= 2;
            } else { // N is even but not a power of 2
                // Take 1 coin is always better for Chanek if N is even and not a power of 2
                // because it leaves an odd number for the opponent, or an even number
                // that is not a power of 2, which means opponent can't take N/2 optimally.
                // Taking N/2 would leave N/2 for opponent, which is even and not a power of 2,
                // allowing opponent to take N/4.
                // By taking 1, Chanek leaves N-1 (odd) for opponent.
                // Opponent takes 1, leaves N-2 (even).
                // Chanek takes N-2/2.
                // This strategy is better than taking N/2 directly.
                chanek_coins += n / 2;
                n /= 2;
            }
        }
    }
    return chanek_coins;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

