// Function to determine if a box can be the special box
// A, B, C, D are initial counts of toys in boxes 1, 2, 3, 4 respectively.
// target_box is 1, 2, 3, or 4.
bool can_be_special_box(long long A, long long B, long long C, long long D, int target_box) {
    long long total_toys = A + B + C + D;

    if (total_toys == 0) {
        // This case is excluded by A+B+C+D > 0 constraint.
        // But if it were allowed, no toy means no special box.
        return false;
    }

    // If there's only one toy initially, that toy is the super toy.
    // The special box is simply the box that toy was in.
    if (total_toys == 1) {
        if (A == 1 && target_box == 1) return true;
        if (B == 1 && target_box == 2) return true;
        if (C == 1 && target_box == 3) return true;
        if (D == 1 && target_box == 4) return true;
        return false;
    }

    // For total_toys > 1, we need to consider the parity of negative numbers
    // and the possibility of controlling magnitude.

    // Let's analyze the final sign.
    // The final sign is determined by the parity of negative numbers multiplied.
    // Initial negative toys are from Box 1 (A) and Box 2 (B).
    long long initial_neg_count = A + B;

    // The number of negative toys can change.
    // N * N -> P
    // N * P -> N
    // P * P -> P
    // The parity of negative numbers changes only when two negative numbers are multiplied.
    // If we multiply N1 * N2, the count of negative numbers decreases by 2, and one positive number is added.
    // If we multiply N * P, the count of negative numbers decreases by 1, and one negative number is added. (Net change 0)
    // If we multiply P1 * P2, the count of negative numbers remains the same, and one positive number is added.
    // So, the parity of negative numbers (initial_neg_count) is invariant.
    // The final toy will be negative if initial_neg_count is odd.
    // The final toy will be positive if initial_neg_count is even.

    bool final_sign_is_negative = (initial_neg_count % 2 != 0);

    // Box 1: x <= -1 (Negative, |x| >= 1)
    // Box 2: -1 < x < 0 (Negative, |x| < 1)
    // Box 3: 0 < x < 1 (Positive, |x| < 1)
    // Box 4: x >= 1 (Positive, |x| >= 1)

    // Case 1: Target Box 1 (Negative, |x| >= 1)
    if (target_box == 1) {
        // Must have odd number of initial negative toys.
        if (!final_sign_is_negative) return false;

        // To get |x| >= 1:
        // We need at least one toy with |x| >= 1 (from Box 1 or Box 4)
        // OR we need to be able to multiply enough |x| < 1 toys to get |x| >= 1.
        // This is always possible if we have at least two toys with |x| < 1 and one toy with |x| >= 1.
        // Example: 0.5 * 0.5 * 4 = 1.
        // If we have A+D >= 1, we have at least one toy with |x| >= 1.
        // If we have B+C >= 1, we have at least one toy with |x| < 1.
        // If we have A+D >= 1 and B+C >= 1, we can always make a product >= 1 or <= -1.
        // Example: -2 * 0.5 = -1.
        // Example: 2 * 0.5 = 1.
        // Example: -2 * 0.6 = -1.2.
        // Example: 2 * 0.6 = 1.2.
        // If we have A+D >= 1, we can always ensure the final product has magnitude >= 1.
        // We can always pick a toy with |x| >= 1 and multiply it last with a toy that has the desired sign.
        // If we have A+D >= 1, we can always make the final product have magnitude >= 1.
        // If A+D == 0, all initial toys have |x| < 1. Then any product will have |x| < 1.
        // So, A+D must be >= 1.
        return (A + D >= 1);
    }

    // Case 2: Target Box 2 (Negative, |x| < 1)
    if (target_box == 2) {
        // Must have odd number of initial negative toys.
        if (!final_sign_is_negative) return false;

        // To get |x| < 1:
        // If all initial toys have |x| < 1 (A+D == 0), then the final product will always have |x| < 1.
        if (A + D == 0) return true;

        // If there is at least one toy with |x| >= 1 (A+D >= 1):
        // We need to be able to make the final product have magnitude < 1.
        // This is possible if we have at least one toy with |x| < 1 (B+C >= 1).
        // We can pick a toy with |x| >= 1 (e.g., 2) and a toy with |x| < 1 (e.g., 0.1).
        // Multiply them: 2 * 0.1 = 0.2. This is < 1.
        // We can always arrange the multiplications such that the last multiplication involves a toy with |x| < 1
        // and a toy with |x| >= 1, resulting in a product with |x| < 1.
        // For example, if we have 2, 0.1, 0.5. We want < 1.
        // (2 * 0.5) * 0.1 = 1 * 0.1 = 0.1.
        // (2 * 0.1) * 0.5 = 0.2 * 0.5 = 0.1.
        // This is possible if we have at least one toy with |x| >= 1 AND at least one toy with |x| < 1.
        // So, A+D >= 1 AND B+C >= 1.
        return (B + C >= 1);
    }

    // Case 3: Target Box 3 (Positive, |x| < 1)
    if (target_box == 3) {
        // Must have even number of initial negative toys.
        if (final_sign_is_negative) return false;

        // To get |x| < 1:
        // If all initial toys have |x| < 1 (A+D == 0), then the final product will always have |x| < 1.
        if (A + D == 0) return true;

        // If there is at least one toy with |x| >= 1 (A+D >= 1):
        // We need to be able to make the final product have magnitude < 1.
        // This is possible if we have at least one toy with |x| < 1 (B+C >= 1).
        // Same logic as Box 2 for magnitude.
        return (B + C >= 1);
    }

    // Case 4: Target Box 4 (Positive, |x| >= 1)
    if (target_box == 4) {
        // Must have even number of initial negative toys.
        if (final_sign_is_negative) return false;

        // To get |x| >= 1:
        // Same logic as Box 1 for magnitude.
        // A+D must be >= 1.
        return (A + D >= 1);
    }

    return false; // Should not reach here
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        std::cout << (can_be_special_box(A, B, C, D, 1) ? "Ya" : "Tidak");
        std::cout << " " << (can_be_special_box(A, B, C, D, 2) ? "Ya" : "Tidak");
        std::cout << " " << (can_be_special_box(A, B, C, D, 3) ? "Ya" : "Tidak");
        std::cout << " " << (can_be_special_box(A, B, C, D, 4) ? "Ya" : "Tidak") << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a subarray is a permutation
// max_val: the maximum value expected in the permutation (its length)
// counts: frequency array for elements in the subarray
// max_seen: the maximum element encountered in the subarray
// Returns true if it's a permutation, false otherwise.
bool is_permutation(int max_val, const std::vector<int>& counts, int max_seen) {
    if (max_seen != max_val) {
        return false;
    }
    for (int i = 1; i <= max_val; ++i) {
        if (counts[i] != 1) {
            return false;
        }
    }
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix properties
    // max_prefix[i] stores the maximum value in a[0...i]
    // counts_prefix[i][j] stores the count of j in a[0...i]
    // is_perm_prefix[i] is true if a[0...i] is a permutation of length i+1
    std::vector<int> max_prefix(n);
    std::vector<std::vector<int>> counts_prefix(n + 1, std::vector<int>(n + 1, 0)); // counts_prefix[len][val]
    std::vector<bool> is_perm_prefix(n + 1, false); // is_perm_prefix[len]

    int current_max_prefix = 0;
    for (int i = 0; i < n; ++i) {
        current_max_prefix = std::max(current_max_prefix, a[i]);
        max_prefix[i] = current_max_prefix;

        // Copy counts from previous prefix
        if (i > 0) {
            for (int j = 1; j <= n; ++j) { // Max possible value is n-1, but for safety use n
                counts_prefix[i + 1][j] = counts_prefix[i][j];
            }
        }
        counts_prefix[i + 1][a[i]]++;

        // Check if a[0...i] is a permutation of length i+1
        if (max_prefix[i] == i + 1) {
            bool distinct_and_correct_values = true;
            for (int j = 1; j <= i + 1; ++j) {
                if (counts_prefix[i + 1][j] != 1) {
                    distinct_and_correct_values = false;
                    break;
                }
            }
            is_perm_prefix[i + 1] = distinct_and_correct_values;
        }
    }

    // Precompute suffix properties
    // max_suffix[i] stores the maximum value in a[i...n-1]
    // counts_suffix[i][j] stores the count of j in a[i...n-1]
    // is_perm_suffix[i] is true if a[i...n-1] is a permutation of length n-i
    std::vector<int> max_suffix(n);
    std::vector<std::vector<int>> counts_suffix(n + 1, std::vector<int>(n + 1, 0)); // counts_suffix[start_idx][val]
    std::vector<bool> is_perm_suffix(n + 1, false); // is_perm_suffix[len]

    int current_max_suffix = 0;
    for (int i = n - 1; i >= 0; --i) {
        current_max_suffix = std::max(current_max_suffix, a[i]);
        max_suffix[i] = current_max_suffix;

        // Copy counts from previous suffix
        if (i < n - 1) {
            for (int j = 1; j <= n; ++j) { // Max possible value is n-1, but for safety use n
                counts_suffix[i][j] = counts_suffix[i + 1][j];
            }
        }
        counts_suffix[i][a[i]]++;

        // Check if a[i...n-1] is a permutation of length n-i
        if (max_suffix[i] == n - i) {
            bool distinct_and_correct_values = true;
            for (int j = 1; j <= n - i; ++j) {
                if (counts_suffix[i][j] != 1) {
                    distinct_and_correct_values = false;
                    break;
                }
            }
            is_perm_suffix[n - i] = distinct_and_correct_values;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 can be from 1 to n-1
        int l2 = n - l1;
        if (is_perm_prefix[l1] && is_perm_suffix[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

