char get_winning_move(char bot_move) {
    if (bot_move == 'R') return 'P';
    if (bot_move == 'S') return 'R';
    if (bot_move == 'P') return 'S';
    return ' '; // Should not happen
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        std::map<char, int> counts;
        for (char ch : s) {
            counts[ch]++;
        }

        char most_frequent_char = ' ';
        int max_count = -1;

        // Iterate in a fixed order to ensure consistent tie-breaking if needed,
        // though any tie-breaker works here.
        // R, P, S is a common order.
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_char = 'R';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_char = 'P';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_char = 'S';
        }

        // If all counts are 0 (empty string, though constraints say n >= 1),
        // or if there's a tie, any choice works.
        // For n >= 1, at least one count will be positive.
        // The problem statement implies s is non-empty.

        char optimal_response = get_winning_move(most_frequent_char);

        for (int i = 0; i < n; ++i) {
            std::cout << optimal_response;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        current_sum += a[i];
        current_xor_sum ^= a[i];
    }

    // Case 0: Already good
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
        return;
    }

    // Case 1: Append two elements
    // We need to find b1, b2 such that (current_sum + b1 + b2) = 2 * (current_xor_sum ^ b1 ^ b2)
    // Let b1 = current_xor_sum.
    // Then current_xor_sum ^ b1 = current_xor_sum ^ current_xor_sum = 0.
    // The equation becomes (current_sum + current_xor_sum + b2) = 2 * (0 ^ b2) = 2 * b2.
    // current_sum + current_xor_sum = 2 * b2 - b2 = b2.
    // So, b2 = current_sum + current_xor_sum.
    // The two elements to append are current_xor_sum and (current_sum + current_xor_sum).
    // Let's verify this:
    // New sum S' = current_sum + current_xor_sum + (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum)
    // New XOR sum X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum) = 0 ^ (current_sum + current_xor_sum) = current_sum + current_xor_sum
    // Is S' = 2 * X'?
    // 2 * (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum). Yes.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << (current_sum + current_xor_sum) << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

