// Function to convert an integer to its 18-digit parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern += '0';
            } else {
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with leading zeros to make it 18 characters long
    // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
    // and "If the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This implies we should always consider 18 digits.
    // For example, 92 with pattern 010.
    // 92 -> 10 (parity from right)
    // 010 -> 010 (pattern from right)
    // The padding rule means we effectively compare 18-digit strings.
    // So, 92 becomes 00...0010 (18 digits)
    // 010 becomes 00...010 (18 digits)
    // The comparison is digit by digit from right.
    // My `pattern` string is built from right to left.
    // So, if `n=92`, `pattern` is "10".
    // If `s="010"`, `s` is "010".
    // The comparison is:
    // 1st from right: 1 (from 92) vs 0 (from 010) -> Mismatch.
    // This is not what the example says.
    // Example: s = 010, 92 matches.
    // 92: digits are 9, 2.
    // 1st from right: 2 (even) -> 0
    // 2nd from right: 9 (odd) -> 1
    // So 92's parity pattern is "10" (reading from left to right, most significant parity first).
    // s = "010".
    // The problem states "parity of the i-th from the right digit in decimal notation matches the i-th from the right digit of the pattern."
    // For 92:
    // 1st from right: 2 (even)
    // 2nd from right: 9 (odd)
    // For s = 010:
    // 1st from right: 0
    // 2nd from right: 1
    // 3rd from right: 0
    // Match: 2 (even) == 0 (pattern), 9 (odd) == 1 (pattern).
    // This means the pattern string should be built from right to left, and then padded.
    // My `pattern` string is built from right to left.
    // For 92, `pattern` becomes "01".
    // For 2212, `pattern` becomes "0100".
    // For 50, `pattern` becomes "00".
    // For 414, `pattern` becomes "010".
    // All these match "010" if we pad them to 18 digits with '0's on the left.
    // So, the `pattern` string should be padded to 18 characters with '0's on the left.
    // Example: 92 -> "01" (from right to left). Pad to 18: "00...0010".
    // Example: s="010". Pad to 18: "00...010".
    // This is consistent.

    // The `pattern` string is built from right to left.
    // So, for 92, it's "01".
    // We need to pad it to 18 characters with '0's on the left.
    // This means `pattern` should be `std::string(18 - pattern.length(), '0') + pattern;`
    // But the map key should be fixed length.
    // Let's make it fixed length 18.
    std::string fixed_pattern = "";
    for (int i = 0; i < 18; ++i) {
        if (n > 0) {
            if ((n % 10) % 2 == 0) {
                fixed_pattern += '0';
            } else {
                fixed_pattern += '1';
            }
            n /= 10;
        } else {
            fixed_pattern += '0';
        }
    }
    // The `fixed_pattern` is now built from right to left.
    // For example, 92 -> "01000...00" (18 chars).
    // For s="010", it's also "01000...00".
    // This is correct.
    return fixed_pattern;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern to 18 characters with '0's on the right.
            // This is because the `get_parity_pattern` function builds the string
            // from right-most digit to left-most digit.
            // So, if s="010", it means 1st digit from right is 0, 2nd is 1, 3rd is 0.
            // The string `s` is given as "010", which means s[0] is 0, s[1] is 1, s[2] is 0.
            // If we reverse `s` first, then pad, it will be correct.
            // Example: s="010". Reversed: "010". Padded: "01000...00".
            // Example: s="1". Reversed: "1". Padded: "1000...00".
            // This is consistent with `get_parity_pattern`.
            std::string padded_s = s;
            while (padded_s.length() < 18) {
                padded_s += '0';
            }
            std::cout << counts[padded_s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_val: minimum possible value for a[i] if it's part of an increasing sequence starting from 0.
    // Specifically, prefix_min_val[i] is the minimum value a[i] can take such that
    // 0 <= a[0] < a[1] < ... < a[i].
    // This means a[j] >= j for 0 <= j <= i.
    // So, a[i] must be at least i.
    // Also, a[i] cannot be greater than its original value.
    // Thus, a[i] must be at least max(i, a[i-1]+1) if we were building it strictly.
    // But we can decrease elements. So, a[i] must be at least i.
    // If a[i] < i, it's impossible to make a[i] = i, so it's impossible to satisfy the condition.
    // If a[i] >= i, we can always make a[i] = i.
    // So, we need a[i] >= i for all i in the increasing part.
    // Let's define `left_reach[i]` as the maximum length of a strictly increasing sequence ending at `i`
    // starting from index 0, where `a[j]` is decreased to `j`.
    // `left_reach[i]` is true if `a[i] >= i`.
    // We can find the first index `i` from the left where `a[i] < i`.
    // All indices `0` to `i-1` can potentially be part of the increasing sequence `0, 1, ..., i-1`.
    int left_boundary = n; // The first index `i` such that `a[i] < i`.
                           // All indices `0` to `left_boundary - 1` satisfy `a[j] >= j`.
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            left_boundary = i;
            break;
        }
    }

    // Calculate suffix_min_val: minimum possible value for a[i] if it's part of a decreasing sequence ending at 0.
    // Specifically, suffix_min_val[i] is the minimum value a[i] can take such that
    // a[i] > a[i+1] > ... > a[n-1] >= 0.
    // This means a[j] >= (n-1-j) for i <= j <= n-1.
    // So, a[i] must be at least (n-1-i).
    // If a[i] < (n-1-i), it's impossible.
    // If a[i] >= (n-1-i), we can always make a[i] = (n-1-i).
    // We can find the first index `i` from the right where `a[i] < (n-1-i)`.
    // All indices `i+1` to `n-1` can potentially be part of the decreasing sequence `..., 1, 0`.
    int right_boundary = -1; // The first index `i` such that `a[i] < (n-1-i)`.
                             // All indices `right_boundary + 1` to `n-1` satisfy `a[j] >= (n-1-j)`.
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1 - i)) {
            right_boundary = i;
            break;
        }
    }

    // A sharpened array requires a peak `k`.
    // The elements `a[0], ..., a[k-1]` must be strictly increasing.
    // The elements `a[k], ..., a[n-1]` must be strictly decreasing.
    // For the increasing part `a[0] < ... < a[k-1]`, we can make `b[j] = j` for `0 <= j < k`.
    // This is possible if `a[j] >= j` for all `0 <= j < k`.
    // This means `k-1` must be less than `left_boundary`. So `k <= left_boundary`.
    // For the decreasing part `a[k] > ... > a[n-1]`, we can make `b[j] = (n-1-j)` for `k <= j <= n-1`.
    // This is possible if `a[j] >= (n-1-j)` for all `k <= j <= n-1`.
    // This means `k` must be greater than `right_boundary`. So `k > right_boundary`.

    // Combining these, we need to find a `k` such that `right_boundary < k <= left_boundary`.
    // Such a `k` exists if and only if `right_boundary < left_boundary`.
    // If `right_boundary < left_boundary`, we can pick any `k` in this range.
    // For example, we can pick `k = right_boundary + 1`.
    // Then `a[0], ..., a[right_boundary]` can be made `0, ..., right_boundary`.
    // And `a[right_boundary+1], ..., a[n-1]` can be made `(n-1-(right_boundary+1)), ..., 0`.
    // The peak would be `a[right_boundary+1]`.
    // The condition `a[right_boundary] < a[right_boundary+1]` would be `right_boundary < (n-1-(right_boundary+1))`.
    // This is not what we need. We need to ensure that the peak `a_k` is greater than `a_{k-1}` and `a_{k+1}`.
    // The values we can achieve are `b_j = j` for `j < k` and `b_j = (n-1-j)` for `j >= k`.
    // The peak `b_k` would be `k` if it's part of the increasing sequence, or `n-1-k` if it's part of the decreasing sequence.
    // The definition of sharpened array says `a_k` is the peak.
    // So `b_k` must be `k` (if we consider it as the end of increasing part) and `n-1-k` (if we consider it as the start of decreasing part).
    // This is confusing. Let's simplify.
    // We need to find a `k` such that:
    // 1. For `0 <= i < k`, `a[i]` can be made `i`. This requires `a[i] >= i`.
    // 2. For `k <= i < n`, `a[i]` can be made `n-1-i`. This requires `a[i] >= n-1-i`.
    // If these conditions hold, we can form the array `0, 1, ..., k-1, n-1-k, n-1-(k+1), ..., 0`.
    // This array is `0, 1, ..., k-1, n-1-k, n-2-k, ..., 0`.
    // For this to be sharpened, we need `k-1 < n-1-k` (if `k > 0`) and `n-1-k > n-2-k` (if `k < n-1`).
    // The second part `n-1-k > n-2-k` is always true.
    // The first part `k-1 < n-1-k` simplifies to `2k < n`, or `k < n/2`.
    // This is not the definition of sharpened. The definition allows `k` to be any index.
    // The values `b_i` must be `b_0 < b_1 < ... < b_k` and `b_k > b_{k+1} > ... > b_{n-1}`.
    // We can choose `b_i = i` for `i < k` and `b_i = (n-1-i)` for `i >= k`.
    // This is possible if `a[i] >= i` for `i < k` and `a[i] >= (n-1-i)` for `i >= k`.
    // The peak value `b_k` would be `n-1-k`.
    // The value `b_{k-1}` would be `k-1`.
    // We need `b_{k-1} < b_k`, so `k-1 < n-1-k`. This means `2k < n`, or `k < n/2`.
    // This is too restrictive.

    // Let's re-evaluate.
    // We need to find a `k` such that we can construct `b` with `b_i <= a_i` and `b_i >= 0`.
    // For `i < k`, we need `b_i < b_{i+1}`. The smallest possible `b_i` is `i`.
    // So, we must have `a[i] >= i` for all `i < k`.
    // For `i >= k`, we need `b_i > b_{i+1}`. The smallest possible `b_i` is `n-1-i`.
    // So, we must have `a[i] >= n-1-i` for all `i >= k`.

    // The condition `a[i] >= i` for `i < k` means that `k` must be less than or equal to `left_boundary`.
    // The condition `a[i] >= n-1-i` for `i >= k` means that `k` must be greater than `right_boundary`.
    // So, we need to find if there exists an integer `k` such that `right_boundary < k <= left_boundary`.
    // Such a `k` exists if and only if `right_boundary < left_boundary`.

    // Example: n=3, a = [0, 1, 0]
    // left_boundary:
    // a[0]=0 >= 0.
    // a[1]=1 >= 1.
    // a[2]=0 < 2. So left_boundary = 2.
    // right_boundary:
    // n-1-i: [2, 1, 0]
    // a[2]=0 >= 0.
    // a[1]=1 >= 1.
    // a[0]=0 < 2. So right_boundary = 0.
    // Is right_boundary < left_boundary? 0 < 2. Yes.
    // Possible k values: 1, 2.
    // If k=1:
    //   i < 1: a[0] >= 0. (0 >= 0, true)
    //   i >= 1: a[1] >= (3-1-1)=1, a[2] >= (3-1-2)=0. (1 >= 1, 0 >= 0, true)
    //   So we can form [0, 1, 0]. This is sharpened with peak at index 1.
    // Output: Yes. Correct.

    // Example: n=3, a = [1, 0, 1]
    // left_boundary:
    // a[0]=1 >= 0.
    // a[1]=0 < 1. So left_boundary = 1.
    // right_boundary:
    // n-1-i: [2, 1, 0]
    // a[2]=1 >= 0.
    // a[1]=0 < 1. So right_boundary = 1.
    // Is right_boundary < left_boundary? 1 < 1. No.
    // Output: No. Correct.

    // Example: n=4, a = [0, 1, 1, 0]
    // left_boundary:
    // a[0]=0 >= 0.
    // a[1]=1 >= 1.
    // a[2]=1 < 2. So left_boundary = 2.
    // right_boundary:
    // n-1-i: [3, 2, 1, 0]
    // a[3]=0 >= 0.
    // a[2]=1 >= 1.
    // a[1]=1 < 2. So right_boundary = 1.
    // Is right_boundary < left_boundary? 1 < 2. Yes.
    // Possible k values: 2.
    // If k=2:
    //   i < 2: a[0] >= 0, a[1] >= 1. (0 >= 0, 1 >= 1, true)
    //   i >= 2: a[2] >= (4-1-2)=1, a[3] >= (4-1-3)=0. (1 >= 1, 0 >= 0, true)
    //   So we can form [0, 1, 1, 0]. This is sharpened with peak at index 1 (value 1) and index 2 (value 1).
    //   The definition of sharpened requires `a_k > a_{k+1}`.
    //   If k=2, `b_1 < b_2` and `b_2 > b_3`.
    //   We can make `b = [0, 1, 1, 0]`.
    //   Is `0 < 1 < 1`? No.
    //   Is `0 < 1` and `1 > 0`? Yes. Peak at index 1.
    //   Is `0 < 1` and `1 > 0`? Yes. Peak at index 2.
    //   The problem is that the construction `b_i = i` for `i < k` and `b_i = n-1-i` for `i >= k`
    //   might not satisfy `b_{k-1} < b_k`.
    //   Specifically, we need `k-1 < n-1-k`.
    //   In the example [0, 1, 1, 0], n=4.
    //   If k=2, `k-1 = 1`, `n-1-k = 4-1-2 = 1`.
    //   `1 < 1` is false. So `b_{k-1} < b_k` is not satisfied by this construction.
    //   This means the simple construction `b_i = i` and `b_i = n-1-i` is not sufficient.

    // The conditions are:
    // 1. For `1 <= i < k`, `b_i < b_{i+1}`. This implies `b_i >= i` (if `b_1` starts at 0).
    //    More generally, `b_i >= b_1 + (i-1)`.
    //    Since we can decrease, we can make `b_1 = 0`. So `b_i >= i-1`.
    //    Let's use 0-indexed: `b_i >= i`.
    //    So, `a[i] >= i` for `0 <= i < k`.
    // 2. For `k <= i < n`, `b_i > b_{i+1}`. This implies `b_i >= n-1-i` (if `b_{n-1}` ends at 0).
    //    So, `a[i] >= n-1-i` for `k <= i < n`.
    // 3. `b_{k-1} < b_k` (if `k > 0`).
    // 4. `b_k > b_{k+1}` (if `k < n-1`).

    // The conditions `a[i] >= i` for `i < k` and `a[i] >= n-1-i` for `i >= k` are necessary.
    // If these hold, we can construct `b_i = i` for `i < k` and `b_i = n-1-i` for `i >= k`.
    // Let's call this `b_i^*`.
    // The array `b^*` is `[0, 1, ..., k-1, n-1-k, n-2-k, ..., 0]`.
    // For this `b^*` to be sharpened with peak `k`:
    // - `b_0^* < b_1^* < ... < b_{k-1}^*` is `0 < 1 < ... < k-1`, which is true for `k > 1`.
    // - `b_k^* > b_{k+1}^* > ... > b_{n-1}^*` is `n-1-k > n-2-k > ... > 0`, which is true for `k < n-1`.
    // - We need `b_{k-1}^* < b_k^*`. This means `k-1 < n-1-k`, or `2k < n`.
    // This is the condition that was too restrictive.

    // The problem is that `b_i` doesn't have to be exactly `i` or `n-1-i`.
    // We just need to find *some* `b_i` values.
    // Let `L[i]` be the minimum value `a[i]` can take if it's part of an increasing sequence `0, 1, ..., i`.
    // So `L[i] = i`. This is possible if `a[i] >= i`.
    // Let `R[i]` be the minimum value `a[i]` can take if it's part of a decreasing sequence `n-1-i, n-2-i, ..., 0`.
    // So `R[i] = n-1-i`. This is possible if `a[i] >= n-1-i`.

    // We need to find a `k` such that:
    // For `0 <= i < k`, `a[i]` can be made `b_i` such that `b_0 < b_1 < ... < b_{k-1}`.
    // The minimum possible value for `b_i` is `i`. So we need `a[i] >= i`.
    // For `k <= i < n`, `a[i]` can be made `b_i` such that `b_k > b_{k+1} > ... > b_{n-1}`.
    // The minimum possible value for `b_i` is `n-1-i`. So we need `a[i] >= n-1-i`.

    // Let's define `can_reach_left[i]` as true if `a[j] >= j` for all `0 <= j <= i`.
    // `can_reach_left[i] = (a[i] >= i) && (i == 0 || can_reach_left[i-1])`.
    // Let's define `can_reach_right[i]` as true if `a[j] >= n-1-j` for all `i <= j < n`.
    // `can_reach_right[i] = (a[i] >= n-1-i) && (i == n-1 || can_reach_right[i+1])`.

    // We need to find a `k` (1-indexed in problem, 0-indexed here) such that:
    // `can_reach_left[k-1]` is true (if `k > 0`)
    // `can_reach_right[k]` is true (if `k < n`)
    // If `k=0`, it's a strictly decreasing array. `can_reach_right[0]` must be true.
    // If `k=n-1`, it's a strictly increasing array. `can_reach_left[n-1]` must be true.

    // Let's compute `can_reach_left` and `can_reach_right` arrays.
    std::vector<bool> can_reach_left(n);
    can_reach_left[0] = (a[0] >= 0);
    for (int i = 1; i < n; ++i) {
        can_reach_left[i] = can_reach_left[i-1] && (a[i] >= i);
    }

    std::vector<bool> can_reach_right(n);
    can_reach_right[n-1] = (a[n-1] >= 0); // n-1-(n-1) = 0
    for (int i = n - 2; i >= 0; --i) {
        can_reach_right[i] = can_reach_right[i+1] && (a[i] >= (n - 1 - i));
    }

    // Now, we need to find if there exists a `k` (0-indexed peak) such that:
    // 1. If `k=0`: `can_reach_right[0]` is true. (Array is `b_0 > b_1 > ... > b_{n-1}`)
    // 2. If `k=n-1`: `can_reach_left[n-1]` is true. (Array is `b_0 < b_1 < ... < b_{n-1}`)
    // 3. If `0 < k < n-1`: `can_reach_left[k-1]` is true AND `can_reach_right[k]` is true.
    //    This means we can make `b_0, ..., b_{k-1}` as `0, ..., k-1`
    //    AND `b_k, ..., b_{n-1}` as `n-1-k, ..., 0`.
    //    The resulting array would be `[0, 1, ..., k-1, n-1-k, n-2-k, ..., 0]`.
    //    For this to be sharpened, we need `b_{k-1} < b_k`.
    //    So, `k-1 < n-1-k`. This simplifies to `2k < n`.

    // The condition `2k < n` is for the specific construction `b_i = i` and `b_i = n-1-i`.
    // This is not what the problem implies. The problem implies we can choose *any* `b_i` as long as `b_i <= a_i` and `b_i >= 0`.
    // The conditions `a[i] >= i` for `i < k` and `a[i] >= n-1-i` for `i >= k` are necessary.
    // If these conditions hold, we can always construct a sharpened array.
    // For example, we can set `b_i = i` for `i < k`.
    // And `b_i = n-1-i` for `i > k`.
    // For `b_k`, we can set `b_k = std::max(k, n-1-k)`.
    // But we also need `b_k > b_{k-1}` and `b_k > b_{k+1}`.
    // So `b_k` must be at least `k-1+1 = k` and at least `n-1-(k+1)+1 = n-k-1`.
    // So `b_k` must be at least `std::max(k, n-k-1)`.
    // And `b_k` must be at most `a[k]`.
    // So we need `a[k] >= std::max(k, n-k-1)`.
    // This is equivalent to `a[k] >= k` AND `a[k] >= n-k-1`.
    // These are exactly the conditions `a[k] >= k` (from `can_reach_left`) and `a[k] >= n-1-k` (from `can_reach_right`).

    // So, we need to find a `k` (0-indexed) such that:
    // `can_reach_left[k]` is true AND `can_reach_right[k]` is true.
    // This means `a[i] >= i` for all `0 <= i <= k` AND `a[i] >= n-1-i` for all `k <= i < n`.
    // If such a `k` exists, we can construct the array `b` as follows:
    // `b_i = i` for `0 <= i < k`.
    // `b_k = std::max(k, n-1-k)`. (This is not quite right, `b_k` must be `a_k` or less, and satisfy `b_k > b_{k-1}` and `b_k > b_{k+1}`)
    // `b_i = n-1-i` for `k < i < n`.
    // The actual values for `b_i` can be:
    // `b_i = i` for `0 <= i < k`.
    // `b_i = n-1-i` for `k < i < n`.
    // `b_k = std::max(k-1+1, n-(k+1)-1+1)` if `k` is not 0 or `n-1`.
    // `b_k = std::max(k, n-k-1)`.
    // This `b_k` must be `<= a_k`.
    // So we need `a_k >= k` and `a_k >= n-k-1`.
    // These are exactly the conditions `a[k] >= k` and `a[k] >= n-1-k`.

    // So, the condition is simply:
    // Is there any `k` (0-indexed) such that `can_reach_left[k]` is true AND `can_reach_right[k]` is true?
    // This means `a[i] >= i` for all `0 <= i <= k` AND `a[i] >= n-1-i` for all `k <= i < n`.
    // If such a `k` exists, we can make `b_i = i` for `i < k`, `b_i = n-1-i` for `i > k`.
    // For `b_k`, we can choose `b_k = a_k`.
    // Then we need to check if `b_{k-1} < b_k` and `b_k > b_{k+1}`.
    // `k-1 < a_k` and `a_k > n-1-(k+1)`.
    // This is `a_k >= k` and `a_k >= n-k`.
    // This is slightly different from `a_k >= n-1-k`.

    // Let's use the `left_boundary` and `right_boundary` logic.
    // `left_boundary` is the first index `i` where `a[i] < i`.
    // All `j < left_boundary` satisfy `a[j] >= j`.
    // `right_boundary` is the first index `i` where `a[i] < n-1-i`.
    // All `j > right_boundary` satisfy `a[j] >= n-1-j`.

    // We need to find a peak `k`.
    // For `0 <= i < k`, we need `a[i] >= i`. This means `k <= left_boundary`.
    // For `k < i < n`, we need `a[i] >= n-1-i`. This means `k >= right_boundary`.
    // For `i = k`, we need `a[k] >= k` AND `a[k] >= n-1-k`.
    // This means `k < left_boundary` (if `a[k] < k`) or `k <= left_boundary` (if `a[k] >= k`).
    // And `k > right_boundary` (if `a[k] < n-1-k`) or `k >= right_boundary` (if `a[k] >= n-1-k`).

    // The condition is simply that there exists an index `k` such that:
    // `a[i] >= i` for all `0 <= i <= k`
    // `a[i] >= n-1-i` for all `k <= i < n`
    // This means `can_reach_left[k]` is true AND `can_reach_right[k]` is true.
    // If such a `k` exists, we can construct `b` as:
    // `b_i = i` for `i < k`.
    // `b_i = n-1-i` for `i > k`.
    // `b_k = std::max(k, n-1-k)`.
    // Since `can_reach_left[k]` is true, `a[k] >= k`.
    // Since `can_reach_right[k]` is true, `a[k] >= n-1-k`.
    // So `a[k] >= std::max(k, n-1-k)`.
    // Thus, we can set `b_k = std::max(k, n-1-k)`.
    // This `b` array will be `[0, 1, ..., k-1, std::max(k, n-1-k), n-1-(k+1), ..., 0]`.
    // We need to check if this is sharpened.
    // `b_{k-1} < b_k` means `k-1 < std::max(k, n-1-k)`. This is always true because `k-1 < k`.
    // `b_k > b_{k+1}` means `std::max(k, n-1-k) > n-1-(k+1)`. This is always true because `n-1-(k+1) = n-k-2`.
    // `k > n-k-2` and `n-1-k > n-k-2`. Both are true.

    // So the condition is indeed: exists `k` such that `can_reach_left[k]` and `can_reach_right[k]` are both true.
    bool possible = false;
    for (int k = 0; k < n; ++k) {
        if (can_reach_left[k] && can_reach_right[k]) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

