// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            // If p is not divisible by q, then p itself is the largest divisor of p
            // and it satisfies the condition p % q != 0.
            std::cout << p << "\n";
            continue;
        }

        // If p is divisible by q, then p cannot be the answer.
        // We need to find the largest divisor x of p such that x is not divisible by q.

        // Get prime factors of q.
        // We only care about distinct prime factors of q.
        std::vector<long long> q_prime_factors = get_prime_factors(q);

        long long max_x = 0;

        // Iterate through each distinct prime factor f of q.
        for (long long f : q_prime_factors) {
            long long current_p = p;
            // Divide current_p by f until it's no longer divisible by q.
            // This means we are removing factors of f from p.
            // We want to remove just enough factors of f so that current_p is no longer divisible by q.
            // The smallest number of factors of f to remove is such that current_p / f^k is not divisible by q.
            // More precisely, we want to find the largest divisor of p that is not divisible by q.
            // Consider p / (f^k) where f^k is the highest power of f that divides q.
            // No, this is not quite right. We need to remove factors of f from p until p is no longer divisible by q.
            // Let's find the highest power of f that divides p.
            // Let p = A * f^a and q = B * f^b, where A, B are not divisible by f.
            // Since p % q == 0, we must have a >= b.
            // We want to find x = p / f^k such that x % q != 0.
            // The largest such x would be p / f^(a - b + 1).
            // This ensures that the power of f in x is a - (a - b + 1) = b - 1, which is less than b.
            // So x will not be divisible by f^b, and thus not divisible by q.

            long long temp_p = p;
            while (temp_p % q == 0) {
                temp_p /= f;
            }
            max_x = std::max(max_x, temp_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

