#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        char last1 = '0' - 1; // Represents a value smaller than any digit
        char last2 = '0' - 1;
        bool possible_with_pivot = true;

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];
            bool can_be_1 = (current_digit >= last1 && current_digit <= pivot_digit);
            bool can_be_2 = (current_digit >= last2 && current_digit >= pivot_digit);

            if (can_be_1 && can_be_2) {
                // Prefer color 1 if it keeps the digit in S1 and is <= pivot_digit
                // This ensures S1 is as long as possible with digits <= pivot_digit
                // and S2 starts with digits >= pivot_digit.
                // If current_digit == pivot_digit, it can go to S1 or S2.
                // If it goes to S1, last1 becomes pivot_digit.
                // If it goes to S2, last2 becomes pivot_digit.
                // To maximize chances, we want S1 to contain as many pivot_digits as possible
                // before S2 starts taking them.
                // So, if current_digit == pivot_digit, assign to 1.
                // If current_digit > pivot_digit, it must go to 2.
                // If current_digit < pivot_digit, it must go to 1.
                // The logic `current_digit <= pivot_digit` for color 1 and `current_digit >= pivot_digit` for color 2
                // naturally handles this.
                // If current_digit == pivot_digit, both are true.
                // We prioritize 1 for current_digit == pivot_digit.
                if (current_digit == pivot_digit) {
                    result[i] = '1';
                    last1 = current_digit;
                } else { // current_digit > pivot_digit is not possible here because can_be_1 implies current_digit <= pivot_digit
                         // current_digit < pivot_digit is not possible here because can_be_2 implies current_digit >= pivot_digit
                         // This branch should ideally not be reached if the conditions are strict.
                         // Let's re-evaluate:
                         // can_be_1: current_digit >= last1 AND current_digit <= pivot_digit
                         // can_be_2: current_digit >= last2 AND current_digit >= pivot_digit
                         // If both are true, then current_digit must be pivot_digit.
                         // Because if current_digit < pivot_digit, can_be_2 is false.
                         // If current_digit > pivot_digit, can_be_1 is false.
                         // So if both are true, current_digit == pivot_digit.
                         // In this case, we assign to 1.
                    result[i] = '1';
                    last1 = current_digit;
                }
            } else if (can_be_1) {
                result[i] = '1';
                last1 = current_digit;
            } else if (can_be_2) {
                result[i] = '2';
                last2 = current_digit;
            } else {
                possible_with_pivot = false;
                break;
            }
        }

        if (possible_with_pivot) {
            found_solution = true;
            break;
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum of r from 1 to b-1: (b-1)*b/2
    // Let sum_r = (b-1)*b/2
    // (b-1) * b can be large, so we need to take modulo carefully.
    // Since b-1 and b are consecutive, one is even.
    // (b-1) * b / 2 = ((b-1)/2) * b if b-1 is even
    // (b-1) * b / 2 = (b-1) * (b/2) if b is even

    long long sum_r_term1 = (b - 1);
    long long sum_r_term2 = b;

    long long sum_r_val;
    if (sum_r_term1 % 2 == 0) {
        sum_r_val = (sum_r_term1 / 2) % MOD;
        sum_r_val = (sum_r_val * (sum_r_term2 % MOD)) % MOD;
    } else { // sum_r_term2 must be even
        sum_r_val = (sum_r_term1 % MOD);
        sum_r_val = (sum_r_val * (sum_r_term2 / 2 % MOD)) % MOD;
    }

    // Sum of k from 1 to a: a*(a+1)/2
    // Let sum_k = a*(a+1)/2
    long long sum_k_term1 = a;
    long long sum_k_term2 = (a + 1);

    long long sum_k_val;
    if (sum_k_term1 % 2 == 0) {
        sum_k_val = (sum_k_term1 / 2) % MOD;
        sum_k_val = (sum_k_val * (sum_k_term2 % MOD)) % MOD;
    } else { // sum_k_term2 must be even
        sum_k_val = (sum_k_term1 % MOD);
        sum_k_val = (sum_k_val * (sum_k_term2 / 2 % MOD)) % MOD;
    }

    // The total sum is (sum_k * b + a) * sum_r
    // S = ( (sum_k % MOD) * (b % MOD) % MOD + (a % MOD) ) % MOD * (sum_r % MOD) % MOD

    long long term_kb = (sum_k_val * (b % MOD)) % MOD;
    long long inner_sum_k_part = (term_kb + (a % MOD)) % MOD;

    long long final_ans = (inner_sum_k_part * sum_r_val) % MOD;

    std::cout << final_ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int char_code = 0; char_code < 26; ++char_code) {
        if (char_indices[char_code].empty()) {
            continue;
        }

        // These are the possible values of k for which s[k] == char_code
        const std::vector<int>& possible_k_for_char = char_indices[char_code];

        if (possible_k_for_char.size() == 1) {
            // If only one k results in this t[0], Vasya wins for this k.
            // The probability of this k occurring is 1/L.
            total_win_prob += 1.0 / L;
            continue;
        }

        // If multiple k values result in this t[0], Vasya needs to pick a j.
        // He wants to maximize the number of k's he can uniquely identify.
        int max_wins_for_this_char = 0;

        // Iterate over all possible second positions j (from 1 to L-1)
        for (int j = 1; j < L; ++j) {
            // For a fixed j, we count how many k's from possible_k_for_char
            // can be uniquely identified.
            int current_wins_for_j = 0;

            // Group k's by the pair (s[k], s[(k+j)%L])
            // Since s[k] is already fixed (char_code), we group by s[(k+j)%L]
            std::vector<std::vector<int>> groups_by_second_char(26);
            for (int k_val : possible_k_for_char) {
                groups_by_second_char[s[(k_val + j) % L] - 'a'].push_back(k_val);
            }

            for (int second_char_code = 0; second_char_code < 26; ++second_char_code) {
                if (groups_by_second_char[second_char_code].size() == 1) {
                    // If only one k results in this (t[0], t[j]) pair, Vasya wins for this k.
                    current_wins_for_j++;
                }
            }
            max_wins_for_this_char = std::max(max_wins_for_this_char, current_wins_for_j);
        }

        // Each of these max_wins_for_this_char k's has a probability of 1/L.
        total_win_prob += static_cast<double>(max_wins_for_this_char) / L;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob << std::endl;

    return 0;
}

