void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i-1]);
            adj[s[i-1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::set<char> visited_in_layout;

    // Find a starting point for a path (a character with only one required neighbor)
    char start_char = '\0';
    for (char c : used_in_s) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If all characters in s have two neighbors (i.e., form a cycle or a single long path where start/end are not distinct)
    // or if s has only one character, pick the first character of s as a starting point.
    if (start_char == '\0' && !s.empty()) {
        start_char = s[0];
    }

    if (start_char != '\0') {
        char current = start_char;
        char prev = '\0'; // To keep track of the previous character in the path

        while (current != '\0' && visited_in_layout.find(current) == visited_in_layout.end()) {
            layout += current;
            visited_in_layout.insert(current);

            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }
            prev = current;
            current = next_char;
        }
    }

    // Check if all characters from s are included in the generated layout segment
    if (layout.length() != used_in_s.size()) {
        // This means there are multiple disconnected components or cycles in the required adjacencies.
        // For example, if s = "ab" and s = "cd" were combined, but they are separate test cases.
        // Or if there's a cycle like "abcba", then 'a' has 1 neighbor, 'b' has 2, 'c' has 2.
        // If s = "abacaba", 'a' has 'b' and 'c', 'b' has 'a', 'c' has 'a'.
        // 'b' is degree 1, 'c' is degree 1, 'a' is degree 2.
        // Start with 'b': b-a-c. Length 3. used_in_s.size() is 3. This is fine.
        // What if s = "abacaba" and we start with 'a'?
        // 'a' has neighbors 'b' and 'c'. If we pick 'b', then a-b. Next for 'b' is 'a'. We are stuck.
        // This implies that if we start with a degree-2 node, we might not explore the full path.
        // The logic for finding start_char should be robust.
        // If all nodes in `used_in_s` have degree 2, it means they form a cycle.
        // A cycle cannot be represented on a linear keyboard without breaking adjacency for at least one pair.
        // Example: "abcda" -> a-b, b-c, c-d, d-a. This forms a cycle a-b-c-d-a.
        // If we lay it out as a-b-c-d, then d-a is not adjacent.
        // So, if all characters in `used_in_s` have degree 2, it's impossible.
        // The only exception is if `used_in_s` has only 2 characters, say 'a' and 'b', and `s` is "ababab".
        // Then 'a' needs 'b', 'b' needs 'a'. Both have degree 1. This is handled by `adj[c].size() == 1`.
        // If `used_in_s` has > 2 characters and all have degree 2, it's a cycle.

        bool all_degree_2 = true;
        if (!used_in_s.empty()) {
            for (char c : used_in_s) {
                if (adj[c].size() != 2) {
                    all_degree_2 = false;
                    break;
                }
            }
        } else { // s is empty, but problem constraints say |s| >= 1.
            all_degree_2 = false;
        }

        if (all_degree_2) {
            std::cout << "NO\n";
            return;
        }
        // If we reach here, it means `start_char` was not found (all nodes have degree 2)
        // OR `start_char` was found but the path didn't cover all `used_in_s` characters.
        // The latter case implies multiple components, which is impossible for a single path.
        // So, if `layout.length() != used_in_s.size()`, it's impossible.
        // This covers the "abcda" case. 'a' has neighbors 'b', 'd'. 'b' has 'a', 'c'. 'c' has 'b', 'd'. 'd' has 'c', 'a'.
        // All have degree 2. `start_char` will be `s[0]` ('a').
        // Path: a-b-c-d. `layout` is "abcd". `used_in_s` has 'a','b','c','d'. Size 4.
        // `layout.length()` is 4. `used_in_s.size()` is 4. They are equal.
        // So the check `layout.length() != used_in_s.size()` is not enough to catch cycles.
        // The `all_degree_2` check is crucial.
        // Let's re-evaluate:
        // If `start_char` is found (degree 1 node), we build a path. If this path doesn't cover all `used_in_s`,
        // it means there are other disconnected components of required adjacencies. This is impossible.
        // So, if `start_char` is found, `layout.length()` MUST be equal to `used_in_s.size()`.
        // If `start_char` is NOT found, it means all nodes in `used_in_s` have degree 2.
        // This implies a cycle (if `used_in_s.size() > 2`) or a single edge (if `used_in_s.size() == 2`).
        // If `used_in_s.size() == 2`, say 'a' and 'b', then `adj['a']` has {'b'}, `adj['b']` has {'a'}.
        // Both have degree 1. So `start_char` would be found.
        // Therefore, if `start_char` is NOT found, it implies `used_in_s.size() > 2` AND all nodes have degree 2, which is a cycle.
        // So, the `all_degree_2` check is correct for cycles.
        // If `start_char` was found, but `layout.length() != used_in_s.size()`, it means there are multiple paths.
        // This is also impossible.
        std::cout << "NO\n";
        return;
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

