#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_s = 0;
    int initial_b = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s++;
        } else {
            initial_b++;
        }
    }

    // Calculate prefix sums for differences (S - B)
    // For left side (0 to n-1), we iterate from left to right.
    // For right side (n to 2n-1), we iterate from right to left.

    // Map to store the minimum number of jars eaten from the left side
    // to achieve a certain difference (S - B).
    // key: difference (S - B)
    // value: number of jars eaten (k_L)
    std::map<int, int> left_diff_to_kL;
    left_diff_to_kL[0] = 0; // 0 jars eaten, difference is 0

    int current_s_left = 0;
    int current_b_left = 0;
    for (int kL = 1; kL <= n; ++kL) {
        if (a[kL - 1] == 1) {
            current_s_left++;
        } else {
            current_b_left++;
        }
        int diff = current_s_left - current_b_left;
        if (left_diff_to_kL.find(diff) == left_diff_to_kL.end()) {
            left_diff_to_kL[diff] = kL;
        }
    }

    // Calculate initial difference for the whole array
    int target_diff = initial_s - initial_b;

    // Initialize minimum jars eaten to a large value
    int min_jars_eaten = 2 * n; // Max possible jars eaten

    // Case 1: No jars eaten from the right side (k_R = 0)
    // We need to find if target_diff can be achieved by eating only from the left.
    // This means we need to find a k_L such that (S_total - S_eaten_L) - (B_total - B_eaten_L) = 0
    // (S_total - B_total) - (S_eaten_L - B_eaten_L) = 0
    // target_diff - (S_eaten_L - B_eaten_L) = 0
    // S_eaten_L - B_eaten_L = target_diff
    if (left_diff_to_kL.count(target_diff)) {
        min_jars_eaten = std::min(min_jars_eaten, left_diff_to_kL[target_diff]);
    }

    // Iterate through possible jars eaten from the right side (k_R)
    int current_s_right = 0;
    int current_b_right = 0;
    for (int kR = 1; kR <= n; ++kR) {
        if (a[2 * n - kR] == 1) {
            current_s_right++;
        } else {
            current_b_right++;
        }
        int diff_eaten_R = current_s_right - current_b_right;

        // We need to find k_L such that:
        // (S_total - S_eaten_L - S_eaten_R) - (B_total - B_eaten_L - B_eaten_R) = 0
        // (S_total - B_total) - (S_eaten_L - B_eaten_L) - (S_eaten_R - B_eaten_R) = 0
        // target_diff - (S_eaten_L - B_eaten_L) - diff_eaten_R = 0
        // (S_eaten_L - B_eaten_L) = target_diff - diff_eaten_R
        int required_diff_left = target_diff - diff_eaten_R;

        if (left_diff_to_kL.count(required_diff_left)) {
            min_jars_eaten = std::min(min_jars_eaten, left_diff_to_kL[required_diff_left] + kR);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
