// Function to solve a single test case
void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Iterate through all possible starting positions l
    for (int l = 0; l < n; ++l) {
        long long current_val = 0;
        // Iterate through possible lengths len, starting from 1
        // The maximum possible length for a binary string to have value len is roughly log2(len).
        // For len = 20, log2(20) is about 4.3.
        // For len = 60, log2(60) is about 5.9.
        // The maximum value of len we care about is around 60 because 2^60 is too large for long long.
        // If len > 60, then 2^len - 1 is much larger than len.
        // Specifically, for len >= 20, 2^len - 1 > len.
        // The condition is len = f(s_l...s_r).
        // If s_l = '0', then f(s_l...s_r) can be 0.
        // If s_l = '1', then f(s_l...s_r) >= 2^(len-1).
        // So if s_l = '1', we need len = f(s_l...s_r) >= 2^(len-1).
        // This inequality only holds for len=1 (1 >= 2^0=1).
        // For len=2, 2 < 2^1=2 is false.
        // For len > 1, 2^(len-1) grows much faster than len.
        // So if s_l = '1', the only possibility is len=1.
        // This means we only need to check len=1 for s_l='1'.
        // For s_l='0', we can have longer substrings.
        // The maximum length of a substring we need to check is limited.
        // If len > 60, then 2^len - 1 is very large.
        // The maximum value of len is n.
        // If len is large, say 60, then f(s_l...s_r) can be at most 2^60 - 1.
        // If len > 60, then f(s_l...s_r) can be at most 2^60 - 1.
        // But we need len = f(s_l...s_r).
        // So we only need to check lengths up to roughly 60.
        // Let's use a slightly larger bound, say 65, to be safe, as 2^63-1 is max long long.
        // The maximum length of s is 2e5.
        // The maximum value of len is n.
        // If len > 63, then 2^(len-1) will overflow long long if we calculate it directly.
        // However, we are comparing len with current_val.
        // If current_val exceeds n, then it can't be equal to len (since len <= n).
        // So we can stop early if current_val becomes too large.
        // The maximum value of n is 2e5.
        // log2(2e5) is about 17.6. So we only need to check up to about 18-20 bits for current_val.
        // This means the length of the substring (r-l+1) can be at most around 20.
        // Let's refine this:
        // If s_l = '1', then f(s_l...s_r) >= 2^(len-1).
        // We need len = f(s_l...s_r).
        // This implies len >= 2^(len-1).
        // This only holds for len=1 (1 >= 2^0 = 1).
        // For len=2, 2 < 2^1 = 2 is false.
        // For len > 1, 2^(len-1) grows much faster than len.
        // So if s_l = '1', the only good substring is "1" itself (len=1).
        // This means we only need to check len=1 for s_l='1'.
        //
        // If s_l = '0', then f(s_l...s_r) can be 0.
        // We need len = f(s_l...s_r).
        // The maximum value of len is n (2e5).
        // The maximum value of f(s_l...s_r) that can be equal to len is n.
        // If f(s_l...s_r) > n, it cannot be equal to len.
        // The maximum number of bits needed to represent n (2e5) is ceil(log2(2e5+1)) = 18.
        // So, if the substring length (len) exceeds 18, and s_l = '0',
        // then f(s_l...s_r) will be at most 2^(len-1) - 1 (if s_l is '0', it's like a string of length len-1).
        // No, f(s_l...s_r) is just the value.
        // If len > 18, then f(s_l...s_r) can be at most 2^len - 1.
        // If s_l = '0', then f(s_l...s_r) is the value of s_{l+1}...s_r.
        // The length of s_{l+1}...s_r is len-1.
        // So f(s_l...s_r) <= 2^(len-1) - 1.
        // We need len = f(s_l...s_r) <= 2^(len-1) - 1.
        // This inequality holds for len >= 2.
        // For len=1, 1 <= 2^0 - 1 = 0 is false.
        // For len=2, 2 <= 2^1 - 1 = 1 is false.
        // For len=3, 3 <= 2^2 - 1 = 3 is true.
        // For len=4, 4 <= 2^3 - 1 = 7 is true.
        // So if s_l = '0', we can have len >= 3.
        //
        // The maximum length of a substring we need to consider is limited by the maximum value of n.
        // If len > 20, then 2^(len-1) is already much larger than 2e5.
        // So if current_val (which is f(s_l...s_r)) exceeds n, we can stop.
        // The maximum length of a substring we need to check is about 20 (since 2^18 > 2e5).
        // Let's use a constant MAX_LEN_CHECK = 20 for safety.
        // This means r - l + 1 <= MAX_LEN_CHECK.
        // So r <= l + MAX_LEN_CHECK - 1.

        for (int r = l; r < n; ++r) {
            int len = r - l + 1;

            if (s[r] == '1') {
                // If s[r] is '1', we add 2^(len-1) to current_val.
                // Check for overflow before adding.
                // If current_val is already large enough that adding 2^(len-1) would exceed n,
                // or if 2^(len-1) itself would overflow long long, we can stop.
                // The maximum value of len is n (2e5).
                // If len-1 >= 63, 2^(len-1) overflows long long.
                // If len-1 >= 18, 2^(len-1) > 2e5.
                // So if len > 18, and s[r] is '1', current_val will likely exceed n.
                // We can cap len at around 60 to avoid 2^(len-1) overflow.
                // But more importantly, if current_val > n, it can't be equal to len.
                // So we can break early if current_val exceeds n.
                if (len > 60) { // Avoid 2^(len-1) overflow for long long
                    // If len is this large, and s[r] is '1', current_val will be huge.
                    // It will definitely be greater than n (max 2e5).
                    // So we can break.
                    break;
                }
                current_val += (1LL << (len - 1));
            }

            // Optimization: If current_val already exceeds n, it cannot be equal to len.
            // Since len is at most n, if current_val > n, we can stop for this 'l'.
            // This is a crucial optimization.
            if (current_val > n) {
                break;
            }

            if (current_val == len) {
                good_substrings_count++;
            }

            // If s[l] was '1', we only check len=1.
            // For len > 1, if s[l] = '1', then f(s_l...s_r) >= 2^(len-1).
            // We need len = f(s_l...s_r).
            // This implies len >= 2^(len-1).
            // This only holds for len=1.
            // So if s[l] == '1' and len > 1, we can break.
            // This check should be done after processing len=1.
            if (s[l] == '1' && len == 1) {
                // If s[l] is '1', and len is 1, current_val is 1.
                // 1 == 1, so it's a good substring.
                // After this, for s[l] = '1', any further len > 1 will not satisfy the condition.
                // So we can break from the inner loop.
                break;
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

