        m = std::abs(m);

        if (n > m) {
            std::swap(n, m);
        }

        // Now n <= m

        if (k < m) {
            std::cout << -1 << "\n";
        } else {
            long long ans;
            long long parity_diff = (k - m) % 2;

            if (parity_diff == 0) {
                // k and m have the same parity.
                // If n and m have the same parity, then k, n, m all have the same parity.
                // We can reach (n,m) in m moves (n diagonal, m-n non-diagonal).
                // We have k-m extra moves. Each pair of extra moves can be (1,0)->(0,0) or (1,1)->(0,0) etc.
                // Each pair of extra moves (e.g., (1,0) then (-1,0)) changes the total moves by 2,
                // and changes the number of diagonal moves by 0 or 2.
                // So, if k-m is even, we can always achieve the target.
                // The maximum diagonal moves would be k.
                ans = k;
            } else { // parity_diff == 1
                // k and m have different parities.
                // This means k-m is odd.
                // We need to adjust the target or moves to match parity.
                // Consider the parity of (n, m) and k.
                // If n and m have the same parity:
                //   (n, m) is (even, even) or (odd, odd).
                //   m has different parity than k.
                //   Example: (2,2) in 3 moves. m=2, k=3. k-m=1 (odd).
                //   We can reach (2,2) in 2 moves. We have 1 extra move.
                //   If we make one extra move, say (1,0), we are at (3,2).
                //   To get back to (2,2), we need another move, say (-1,0). Total 2 moves.
                //   So, if we have an odd number of extra moves, we must end up at a point
                //   whose coordinates have different parity than (n,m) if we only use
                //   moves that change one coordinate by 1.
                //   However, we can use diagonal moves.
                //   If n and m have the same parity, and k has different parity:
                //   Example: (2,2) in 3 moves.
                //   (0,0) -> (1,1) -> (2,2) (2 moves, 2 diag)
                //   We need 3 moves. We can do (0,0) -> (1,0) -> (1,1) -> (2,2). (1 diag)
                //   Or (0,0) -> (1,1) -> (1,2) -> (2,2). (2 diag)
                //   The maximum possible diagonal moves is k-1.
                //   This is because if k-m is odd, we must make at least one move that
                //   changes the parity of the sum of coordinates (x+y).
                //   A diagonal move (dx!=0, dy!=0) changes x+y by dx+dy, which is 0 or +-2 (even).
                //   A non-diagonal move (dx=0 XOR dy=0) changes x+y by dx+dy, which is +-1 (odd).
                //   The parity of (x+y) changes if and only if a non-diagonal move is made.
                //   The parity of (N+M) must match the parity of K.
                //   (0,0) -> (N,M) in K moves.
                //   Parity of (N+M) must be same as parity of K.
                //   If (N+M) % 2 != K % 2, it's impossible.
                //   Let's check this condition:
                //   (n+m)%2 == (k%2)
                //   If (n+m)%2 != (k%2), then it's impossible.
                //   Example: (10,1) in 9 moves. n=1, m=10. n+m=11 (odd). k=9 (odd). Parity matches.
                //   m=10, k=9. k < m, so -1.
                //   Example: (2,2) in 3 moves. n=2, m=2. n+m=4 (even). k=3 (odd). Parity mismatch.
                //   Output is 1. My logic says -1. What's wrong?
                //   The parity of (x+y) changes if and only if a non-diagonal move is made.
                //   This is true for Manhattan distance.
                //   For Chebyshev distance (8-directional moves), the parity of (x+y) can change
                //   even with diagonal moves.
                //   (0,0) -> (1,1) (diagonal). x+y changes from 0 to 2. Parity same.
                //   (0,0) -> (1,0) (non-diagonal). x+y changes from 0 to 1. Parity different.
                //   (0,0) -> (0,1) (non-diagonal). x+y changes from 0 to 1. Parity different.
                //   The parity of (x+y) changes if and only if an odd number of non-diagonal moves are made.
                //   Let D be diagonal moves, ND be non-diagonal moves. Total moves K = D + ND.
                //   Each diagonal move changes x by +-1 and y by +-1. So x_final = sum(dx_i), y_final = sum(dy_i).
                //   The parity of x_final is sum(parity of dx_i).
                //   The parity of y_final is sum(parity of dy_i).
                //   For a diagonal move, dx_i and dy_i are both odd.
                //   For a non-diagonal move, one of dx_i, dy_i is odd, the other is even.
                //   This is not helpful.

                // Let's re-evaluate the parity condition.
                // The final coordinates (N, M) must have the same parity as K if we consider the sum N+M.
                // (x_final + y_final) % 2 == K % 2.
                // Each move changes x by dx, y by dy.
                // (x+dx + y+dy) % 2 == (x+y + dx+dy) % 2.
                // So (N+M) % 2 == (0+0 + sum(dx_i+dy_i)) % 2.
                // (N+M) % 2 == (sum(dx_i+dy_i)) % 2.
                // For a diagonal move, dx, dy are both +-1. So dx+dy is +-2 or 0 (even).
                // For a non-diagonal move, one of dx, dy is +-1, the other is 0. So dx+dy is +-1 (odd).
