        // After the call, we reset visited[1] to 0 and memo[1] to {0,0} for the next iteration.
        // This is because a_global[1] changes.

        // Temporarily reset for x=1
        visited[1] = 0;
        memo[1] = {0, 0};

        std::pair<int, long long> result_for_i = calculate_result(1);

        if (result_for_i.second == -1) {
