        //
        // We need to find the smallest `b_i` in this range such that `b_i >= prev_b`.
        //
        // Case 1: `a_i + x < m`.
        // The possible values for `b_i` are `a_i, a_i+1, ..., a_i+x`.
        // If `a_i >= prev_b`: We can choose `b_i = a_i`. This is the smallest possible value for `b_i` that satisfies `b_i >= prev_b`.
        // If `a_i < prev_b`: We must increment `a_i`.
        //   We need `a_i + y >= prev_b` for some `y <= x`.
        //   The smallest `y` is `prev_b - a_i`.
        //   If `prev_b - a_i <= x`, then we can achieve `prev_b`. So `b_i = prev_b`.
        //   Else (`prev_b - a_i > x`), we cannot reach `prev_b`. The maximum we can reach is `a_i + x`.
        //   If `a_i + x < prev_b`, then it's impossible. Return false.
        //   Else (`a_i + x >= prev_b`), we must choose `b_i = a_i + x`.
        //
        // Case 2: `a_i + x >= m`.
        // The possible values for `b_i` are `a_i, a_i+1, ..., m-1, 0, 1, ..., (a_i+x)%m`.
        //
        // If `a_i >= prev_b`:
        //   We can choose `b_i = a_i`. This is a valid choice.
        //   However, we can also choose `b_i = (a_i + x) % m` (which is `a_i + x - m`).
        //   This value is smaller than `a_i`. If `a_i + x - m >= prev_b`, then we should choose `b_i = a_i + x - m`
        //   because it's smaller and still satisfies `b_i >= prev_b`.
        //   So, if `a_i + x - m >= prev_b`, then `b_i = a_i + x - m`.
        //   Else, `b_i = a_i`.
        //
        // If `a_i < prev_b`:
        //   We cannot choose `a_i`. We must increment it.
        //   We need to find `y` such that `(a_i + y) % m >= prev_b` and `y <= x`.
        //   Since `a_i < prev_b`, and `a_i + x >= m`, the values `a_i, ..., m-1, 0, ..., (a_i+x)%m` are available.
        //   The value `prev_b` is definitely reachable because the range of values wraps around `m`.
        //   Specifically, `prev_b` is either in `[a_i, m-1]` or `[0, (a_i+x)%m]`.
        //   If `prev_b >= a_i`: The required `y` is `prev_b - a_i`. This `y` is always `<= m-1`.
        //     Since `x >= m - a_i` (because `a_i + x >= m`), and `prev_b - a_i <= m - a_i`,
        //     it implies `prev_b - a_i <= x`. So `prev_b` is reachable.
        //     Thus, `b_i = prev_b`.
        //   If `prev_b < a_i`: This means `prev_b` must be in the wrapped-around part `[0, (a_i+x)%m]`.
        //     The required `y` is `prev_b + m - a_i`.
        //     We need to check if `prev_b + m - a_i <= x`.
        //     If it is, then `b_i = prev_b`.
        //     Else (`prev_b + m - a_i > x`), we cannot reach `prev_b`.
        //     The smallest value we can reach that is `>= prev_b` is `(a_i + x) % m`.
        //     So, `b_i = (a_i + x) % m`.
        //
        // This logic is getting complicated. Let's simplify.
        // For each `a_i`, we need to choose `b_i` such that `b_i = (a_i + y_i) % m` for `0 <= y_i <= x`,
        // and `b_i >= prev_b`. We want to minimize `b_i`.
        //
        // There are two main scenarios for `a_i` relative to `prev_b`:
        // 1. `a_i >= prev_b`:
        //    We can potentially keep `a_i` as `b_i` (i.e., `y_i = 0`). This is valid.
        //    We also have the option to increment `a_i` by `x` to get `(a_i + x) % m`.
        //    If `(a_i + x) % m` is smaller than `a_i` (which happens when `a_i + x >= m`),
        //    AND `(a_i + x) % m` is still `>= prev_b`, then we should choose `(a_i + x) % m` for `b_i`
        //    because it's smaller and allows more flexibility for future elements.
        //    Otherwise, we choose `a_i`.
        //    So, if `a_i >= prev_b`:
        //      If `(a_i + x) % m < a_i` (i.e., `a_i + x >= m`) AND `(a_i + x) % m >= prev_b`:
        //        `b_i = (a_i + x) % m`.
        //      Else:
        //        `b_i = a_i`.
        //
        // 2. `a_i < prev_b`:
        //    We cannot keep `a_i`. We must increment it.
        //    We need to find `y_i` such that `0 < y_i <= x` and `(a_i + y_i) % m >= prev_b`.
        //    The smallest value `(a_i + y_i) % m` that is `>= prev_b` is `prev_b` itself.
        //    Can we achieve `prev_b`?
        //    This requires `y_i = (prev_b - a_i + m) % m`.
        //    If this `y_i <= x`, then we can set `b_i = prev_b`.
        //    Otherwise, we cannot reach `prev_b` by incrementing `a_i` by at most `x`.
        //    The only other option is to increment `a_i` by exactly `x`.
        //    If `(a_i + x) % m < prev_b`, then it's impossible to satisfy `b_i >= prev_b`. Return false.
        //    Else, we must choose `b_i = (a_i + x) % m`.
        //
        // Let's combine these:
        //
        // If `a_i >= prev_b`:
        //   `val_if_incremented = (a_i + x) % m`.
        //   If `val_if_incremented < a_i` (meaning `a_i + x >= m`) AND `val_if_incremented >= prev_b`:
        //     `prev_b = val_if_incremented`.
        //   Else:
        //     `prev_b = a_i`.
        // Else (`a_i < prev_b`):
        //   `val_if_incremented = (a_i + x) % m`.
        //   If `val_if_incremented < prev_b`:
        //     Return false. // Cannot satisfy `b_i >= prev_b`
        //   Else:
        //     `prev_b = val_if_incremented`.
        //
        // This logic seems correct and covers all cases.

        long long val_if_incremented = (current_a + x) % m;

        if (current_a >= prev_b) {
            // Option 1: Keep current_a. This is valid.
            // Option 2: Use val_if_incremented. This is valid if val_if_incremented >= prev_b.
            // We want to choose the smaller of the two valid options.
            // If val_if_incremented < current_a (i.e., current_a + x >= m),
            // AND val_if_incremented >= prev_b, then we prefer val_if_incremented.
            if (val_if_incremented < current_a && val_if_incremented >= prev_b) {
                prev_b = val_if_incremented;
            } else {
                prev_b = current_a;
            }
        } else { // current_a < prev_b
            // We cannot keep current_a. We must increment it.
            // The only way to satisfy b_i >= prev_b is if val_if_incremented >= prev_b.
            if (val_if_incremented < prev_b) {
                return false; // Impossible to make b_i >= prev_b
            } else {
                prev_b = val_if_incremented;
            }
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1; // Maximum possible operations needed is m-1 (e.g., 0, m-1 -> 0,0)
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

