        // Since all elements must be distinct, this can only happen if n=1.
        // For n >= 2, p_0 must be different from p_{n-1} (unless n=1).
        // If p_0 = p_{n-1}, then p is not a permutation of distinct elements.
        // Thus, for n >= 2, p_0 != p_{n-1}, which means p is always different from its reverse.
        // So, reversing the permutation is always a valid solution.

        for (int i = n - 1; i >= 0; --i) {
