int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        long long min_val = a[0];
        long long total_spells = 0;

        for (int i = 1; i < n; ++i) {
            // For each pile a[i] (where i > 0), we can add min_val to it
            // as many times as possible without exceeding k.
            // The number of times is (k - a[i]) / min_val.
            // Since a[i] >= min_val, k - a[i] will be less than or equal to k - min_val.
            // If a[i] is already k or more, (k - a[i]) / min_val will be 0 or negative,
            // but since a_i <= k is guaranteed initially, k - a_i >= 0.
            // So, (k - a[i]) / min_val is the correct count.
            total_spells += (k - a[i]) / min_val;
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

