#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long d; // d can be up to 100, but sum of a_i * (i-1) can exceed int
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0]; // Initial haybales in pile 1

        // Iterate through piles from 2 to n (index 1 to n-1)
        for (int i = 1; i < n; ++i) {
            // Cost to move one haybale from pile i+1 (0-indexed i) to pile 1 is i days
            long long cost_per_haybale = i; 

            if (d >= cost_per_haybale) {
                // Calculate how many haybales can be moved from pile i
                // We have 'a[i]' haybales in this pile.
                // We have 'd' days remaining.
                // Each haybale costs 'cost_per_haybale' days.
                long long max_haybales_from_this_pile = a[i];
                long long haybales_movable_by_days = d / cost_per_haybale;

                long long haybales_to_move = std::min(max_haybales_from_this_pile, haybales_movable_by_days);

                current_a1 += haybales_to_move;
                d -= haybales_to_move * cost_per_haybale;
            } else {
                // Not enough days to move even one haybale from this pile
                // or any further piles, so we can stop.
                break;
            }
        }
        std::cout << current_a1 << std::endl;
    }
    return 0;
}

