void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    // Initialize min_price_suffix with the last element's price.
    // This represents the minimum price encountered from the current position to the end of the array.
    int min_price_suffix = a[n - 1];

    // Iterate from the second to last element backwards to the first element.
    // For each element a[i], we compare it with min_price_suffix, which holds
    // the minimum price among a[i+1], a[i+2], ..., a[n-1].
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_price_suffix) {
            // If a[i] is greater than the minimum price found later, it's a bad price.
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_price_suffix, it means a[i] is
            // either equal to or less than min_price_suffix.
            // In this case, a[i] itself becomes the new minimum for elements
            // further to the left (i.e., for a[i-1], a[i-2], etc.).
            min_price_suffix = a[i];
        }
    }

    std::cout << bad_prices_count << "\n";
}

