                max_dist = std::max(max_dist, (i + 1) - last_R_pos);
                last_R_pos = i + 1;
            }
        }
        // After iterating through the string, we need to consider the jump from the last 'R' position
        // to the target cell n+1.
        max_dist = std::max(max_dist, (n + 1) - last_R_pos);
        std::cout << max_dist << "\n";
