#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by:
        // 1. The total number of students divided by 3 (each team needs 3 students).
        // 2. The number of coders (each team needs at least 1 coder).
        // 3. The number of mathematicians (each team needs at least 1 mathematician).
        // So, an initial upper bound is min(c, m, (c + m + x) / 3).
        // Let's call this 'low' for binary search.
        // The actual answer can be at most this value.
        // The minimum possible answer is 0.

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;

            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians for the mandatory slots.
            // Remaining coders: c - mid
            // Remaining mathematicians: m - mid
            // Remaining students without specialization: x

            // Total students available for the third slot in 'mid' teams:
            // (c - mid) + (m - mid) + x

            // Each of the 'mid' teams needs 1 student for the third slot.
            // So, we need 'mid' students for these third slots.

            // If (c - mid) + (m - mid) + x >= mid, then it's possible to form 'mid' teams.
            // This condition simplifies to c + m + x >= 3 * mid.
            // This is already covered by high = std::min({c, m, (c + m + x) / 3});
            // The crucial part is that the 'mid' teams must be formed using the available students.
            // The number of coders must be at least 'mid'.
            // The number of mathematicians must be at least 'mid'.
            // These are also covered by the min() for 'high'.

            // The only remaining constraint is that the sum of remaining students (after assigning one C and one M to each team)
            // must be enough to fill the third slot for all 'mid' teams.
            // The number of students needed for the third slots is 'mid'.
            // The number of students available for the third slots is (c - mid) + (m - mid) + x.

            if (c >= mid && m >= mid && (c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

