int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The area of the full triangle is A = (1/2) * base * h.
    // Since base is 1, A = h/2.
    // Each of the n pieces must have area A_piece = A / n = (h/2) / n = h / (2n).

    // Consider a smaller triangle formed by a cut at distance x from the apex.
    // Due to similarity, its base will be x/h * original_base = x/h * 1 = x/h.
    // Its area A_x = (1/2) * (x/h) * x = x^2 / (2h).

    // We want the i-th cut (from the apex) to be at distance x_i.
    // The triangle formed by the i-th cut (at x_i) should have an area equal to
    // i times the area of a single piece.
    // So, A_{x_i} = i * A_piece
    // x_i^2 / (2h) = i * (h / (2n))
    // x_i^2 = i * (h^2 / n)
    // x_i = sqrt(i * h^2 / n)
    // x_i = h * sqrt(i / n)

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

