#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number we will use for the first k differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between left and right pointers
    // For example, if k=3, we use numbers 1, 2, 3, 4.
    // p_0 = 1 (left)
    // p_1 = 4 (right) -> diff = 3
    // p_2 = 2 (left) -> diff = 2
    // p_3 = 3 (right) -> diff = 1
    // This generates differences k, k-1, ..., 1.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index, take from left
            p[i] = left;
            left++;
        } else { // Odd index, take from right
            p[i] = right;
            right--;
        }
    }

    // The remaining numbers are from k+2 to n.
    // We want to add them such that they introduce only difference 1.
    // This can be done by simply appending them in increasing order.
    // The last number used in the alternating sequence was either `left-1` or `right+1`.
    // The next number to use is `k+2`.
    // If the last number used was `left-1`, then `left` is now `(k+1)/2 + 1` or `(k+1)/2`.
    // If the last number used was `right+1`, then `right` is now `(k+1)/2 + 1` or `(k+1)/2`.
    // In either case, the numbers `left` and `right` have crossed or met.
    // The numbers used are `1, ..., k+1`.
    // The next available number is `k+2`.
    // We can just append `k+2, k+3, ..., n` to the permutation.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // This will be k+2, k+3, ..., n
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

