    // This requires an odd number of negative values and at least one value with magnitude >= 1.
    // The total number of negative values is A + B.
    // If A+B is odd, the final sign is negative.
    // If A+B is even, the final sign is positive.
    // To get magnitude >= 1, we need to be able to achieve it.
    // If A+D > 0, it means there's at least one toy with magnitude >= 1 initially.
    // If A+D == 0, all initial toys have magnitude < 1. Then any product will also have magnitude < 1.
    // So, if A+D == 0, Box 1 and Box 4 are impossible.
    if ((a + b) % 2 == 1 && (a + d > 0)) {
        ans1 = "Ya";
    }

    // Case 2: Final toy in Box 2 (value in (-1, 0))
    // This requires an odd number of negative values and magnitude < 1.
    // If A+B is odd, the final sign is negative.
    // To get magnitude < 1:
    // If A+D == 0, all initial toys have magnitude < 1, so the final product will have magnitude < 1.
    // If A+D > 0, we need to be able to make the magnitude < 1.
    // This is always possible if there are enough toys with magnitude < 1 (B+C > 0).
    // For example, if we have a toy with value 100 (from Box 4) and a toy with value 0.001 (from Box 3),
    // we can multiply them to get 0.1.
    // The only way to guarantee magnitude >= 1 is if all toys have magnitude >= 1 (B=0, C=0).
    // If B+C > 0, we can always achieve magnitude < 1.
    // If B+C == 0, then all toys are from Box 1 or Box 4. All have magnitude >= 1.
    // In this case, the final product will also have magnitude >= 1.
    // So, if B+C == 0, Box 2 and Box 3 are impossible.
    if ((a + b) % 2 == 1 && (b + c > 0 || total_toys == 1)) { // total_toys == 1 covers the case where the single toy is in Box 2
        ans2 = "Ya";
    }

    // Case 3: Final toy in Box 3 (value in (0, 1))
    // This requires an even number of negative values and magnitude < 1.
    // If A+B is even, the final sign is positive.
    // Similar to Box 2, magnitude < 1 is possible if B+C > 0 or total_toys == 1.
    if ((a + b) % 2 == 0 && (b + c > 0 || total_toys == 1)) { // total_toys == 1 covers the case where the single toy is in Box 3
        ans3 = "Ya";
    }

    // Case 4: Final toy in Box 4 (value >= 1)
    // This requires an even number of negative values and magnitude >= 1.
    // If A+B is even, the final sign is positive.
    // Similar to Box 1, magnitude >= 1 is possible if A+D > 0.
    if ((a + b) % 2 == 0 && (a + d > 0)) {
        ans4 = "Ya";
    }

    // Special handling for total_toys == 1
    if (total_toys == 1) {
        if (a == 1) {
            ans1 = "Ya"; ans2 = "Tidak"; ans3 = "Tidak"; ans4 = "Tidak";
        } else if (b == 1) {
            ans1 = "Tidak"; ans2 = "Ya"; ans3 = "Tidak"; ans4 = "Tidak";
        } else if (c == 1) {
            ans1 = "Tidak"; ans2 = "Tidak"; ans3 = "Ya"; ans4 = "Tidak";
        } else if (d == 1) {
            ans1 = "Tidak"; ans2 = "Tidak"; ans3 = "Tidak"; ans4 = "Ya";
        }
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
}

