void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix_min_val: minimum possible value for a[i]
    // such that a[0] < a[1] < ... < a[i] can be satisfied.
    // This means a[i] must be at least i.
    // And a[i] must be at least a[i-1]+1.
    // So, a[i] must be at least max(i, a[i-1]+1).
    // Since we can decrease a[i], the original a[i] must be >= i.
    // If a[i] < i, it's impossible to make a[i] = i, so it's impossible.
    // This is equivalent to checking if a[i] >= i for all i in the increasing prefix.
    // The first element a[0] must be at least 0.
    // The second element a[1] must be at least 1.
    // The i-th element a[i] must be at least i.
    // So, we need a[i] >= i for the increasing part.
    // Let's find the longest prefix where a[i] >= i.
    int left_bound = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            left_bound = i - 1;
            break;
        }
        left_bound = i;
    }

    // Calculate suffix_min_val: minimum possible value for a[i]
    // such that a[i] > a[i+1] > ... > a[n-1] can be satisfied.
    // This means a[i] must be at least n-1-i.
    // The last element a[n-1] must be at least 0.
    // The second to last a[n-2] must be at least 1.
    // The i-th element a[i] must be at least n-1-i.
    // So, we need a[i] >= n-1-i for the decreasing part.
    // Let's find the longest suffix where a[i] >= n-1-i.
    int right_bound = -1;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1 - i)) {
            right_bound = i + 1;
            break;
        }
        right_bound = i;
    }

    // If there is any k such that a[0]...a[k] can be increasing
    // and a[k]...a[n-1] can be decreasing, then it's possible.
    // This means we need to find a k such that:
    // 1. a[i] >= i for all i <= k (left part condition)
    // 2. a[i] >= n-1-i for all i >= k (right part condition)
    //
    // The `left_bound` is the largest index `j` such that `a[i] >= i` for all `0 <= i <= j`.
    // The `right_bound` is the smallest index `j` such that `a[i] >= n-1-i` for all `j <= i <= n-1`.
    //
    // We need to find if there exists a `k` such that `k <= left_bound` AND `k >= right_bound`.
    // This is equivalent to checking if `right_bound <= left_bound`.
    // If `right_bound <= left_bound`, then there is at least one `k` (e.g., `k = right_bound` or `k = left_bound` or any `k` in between)
    // that satisfies both conditions.
    // For example, if `right_bound <= left_bound`, we can pick `k = right_bound`.
    // Then for `i <= k`, we need `a[i] >= i`. Since `k = right_bound <= left_bound`, this means `i <= left_bound`, so `a[i] >= i` holds.
    // And for `i >= k`, we need `a[i] >= n-1-i`. Since `k = right_bound`, this means `i >= right_bound`, so `a[i] >= n-1-i` holds.
    //
    // So, the condition is simply `right_bound <= left_bound`.

    if (right_bound <= left_bound) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

