#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 == 1) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case: N=2, only option is take 1
                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 == 1) { // N/2 is odd
                    // Taking N/2 leaves an odd number of coins for opponent.
                    // Opponent will take 1, leaving an even number for Chanek.
                    // Taking 1 leaves an odd number of coins for opponent.
                    // Opponent will take 1, leaving an even number for Chanek.
                    // Both lead to opponent taking 1.
                    // If Chanek takes N/2, he gets N/2.
                    // If Chanek takes 1, he gets 1.
                    // Since N/2 is odd and N > 2, N/2 >= 3. So N/2 > 1.
                    // Chanek prefers N/2.
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even
                    // Taking N/2 leaves an even number of coins for opponent.
                    // Opponent can take N/4.
                    // Taking 1 leaves an odd number of coins for opponent.
                    // Opponent will take 1.
                    // Chanek wants to maximize his coins.
                    // If Chanek takes 1: he gets 1. Remaining N-1 (odd). Opponent takes 1.
                    // If Chanek takes N/2: he gets N/2. Remaining N/2 (even). Opponent takes N/4.
                    // Chanek wants to maximize his current gain + future gain.
                    // This is the core of the greedy strategy.
                    // If N/2 is even, taking N/2 is generally better as it's a larger amount.
                    // The opponent will also take N/4.
                    // If Chanek takes 1, opponent takes 1.
                    // The problem states both players play optimally to maximize their own coins.
                    // If N/2 is even, taking N/2 is always better for Chanek than taking 1.
                    // Because N/2 is even, N must be a multiple of 4.
                    // If N is a multiple of 4, N/2 is even.
                    // Chanek takes N/2. Opponent faces N/2 (even).
                    // Opponent will take N/4.
                    // If Chanek takes 1. Opponent faces N-1 (odd).
                    // Opponent will take 1.
                    // Chanek gets N/2 vs 1. N/2 is always greater than 1 for N >= 4.
                    chanek_coins += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n % 2 == 1) { // N is odd
                n -= 1;
            } else { // N is even
                if (n == 2) {
                    n -= 1;
                } else if ((n / 2) % 2 == 1) { // N/2 is odd
                    n /= 2;
                } else { // N/2 is even
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

