// Function to check if a prefix of length 'len' is a permutation
bool is_permutation(const std::vector<int>& a, int len) {
    if (len == 0) return false; // Permutations must have non-zero length
    if (len > a.size()) return false;

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        if (a[i] <= 0 || a[i] > len) {
            return false;
        }
        if (seen[a[i]]) {
            return false;
        }
        seen[a[i]] = true;
        if (a[i] > max_val) {
            max_val = a[i];
        }
    }
    return max_val == len;
}

// Function to check if a suffix of length 'len' is a permutation
bool is_suffix_permutation(const std::vector<int>& a, int start_idx, int len) {
    if (len == 0) return false; // Permutations must have non-zero length
    if (start_idx + len > a.size()) return false;

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        if (a[start_idx + i] <= 0 || a[start_idx + i] > len) {
            return false;
        }
        if (seen[a[start_idx + i]]) {
            return false;
        }
        seen[a[start_idx + i]] = true;
        if (a[start_idx + i] > max_val) {
            max_val = a[start_idx + i];
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    int max_overall = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] > max_overall) {
            max_overall = a[i];
        }
    }

    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 ranges from 1 to n-1 (inclusive)
    // If l1 = n, then l2 = 0, which is not allowed.
    // If l1 = 0, then l2 = n, which is not allowed.
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check if the first part (length l1) could be a permutation
        // Condition 1: Max element in prefix must be l1
        // Condition 2: All elements must be distinct (checked by is_permutation)
        // Condition 3: All elements must be <= l1 (checked by is_permutation)
        if (prefix_max[l1 - 1] == l1) {
            // Check if the second part (length l2) could be a permutation
            // Condition 1: Max element in suffix must be l2
            // Condition 2: All elements must be distinct (checked by is_suffix_permutation)
            // Condition 3: All elements must be <= l2 (checked by is_suffix_permutation)
            if (suffix_max[l1] == l2) {
                // If both max conditions hold, perform full permutation checks
                if (is_permutation(a, l1) && is_suffix_permutation(a, l1, l2)) {
                    results.push_back({l1, l2});
                }
            }
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

