int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long a_count = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a's to its left
            // will eventually interact with this 'b'.
            // Each 'a' to its left will contribute 'a_count' steps
            // to move past this 'b'.
            // The 'b' itself will be duplicated 'a_count' times.
            // So, this 'b' effectively doubles the number of 'a's
            // that will be processed in the future (to its left).
            total_steps = (total_steps + a_count) % mod;
            a_count = (a_count * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' will eventually
            // need to move past all 'b's to its right.
            // The current 'a_count' represents the number of 'a's
            // that are effectively "active" and need to be processed
            // with 'b's to their right.
            // This 'a' adds 1 to the count of active 'a's.
            a_count = (a_count + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

