// Function to convert a number to its parity pattern string
// The pattern string will always have length 18, padded with '0's from the left.
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                pattern += '0';
            } else { // Odd digit
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to make it 18 characters long
    // Since we built it from right to left, we need to reverse and then pad.
    // Or, more simply, just pad with '0's at the end until length 18.
    // The map key will be this 18-char string.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each 18-character parity pattern string.
    // The key is the 18-char string, value is its count.
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad the query pattern 's' with '0's to the right to make it 18 characters long.
            // This ensures it matches the format of keys in pattern_counts.
            while (s.length() < 18) {
                s += '0';
            }
            std::cout << pattern_counts[s] << "\n";
        }
    }

    return 0;
}

