#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left side
    // Let 'i' be the number of items taken from the left.
    // Then 'n - i' items must be taken from the right.
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right side

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add penalty for imbalance
        if (i > j) {
            // More items from left than right
            // The difference is i - j.
            // If i - j = 1, no extra penalty.
            // If i - j > 1, then (i - j - 1) items were taken consecutively from the left
            // after the right side ran out of items.
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) {
            // More items from right than left
            // The difference is j - i.
            // If j - i = 1, no extra penalty.
            // If j - i > 1, then (j - i - 1) items were taken consecutively from the right
            // after the left side ran out of items.
            current_energy += (j - i - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

