// Function to find prime factors of a number
// Returns a vector of unique prime factors
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            // If p is not divisible by q, then p itself is the answer.
            // It's the largest divisor of p, and it satisfies x % q != 0.
            std::cout << p << "\n";
        } else {
            // If p is divisible by q, we need to find a smaller x.
            // x must be a divisor of p, and x must not be divisible by q.
            // We want the largest such x.
            // This means we need to remove factors from p such that p is no longer divisible by q,
            // but we remove as few factors as possible to keep x large.

            // Get unique prime factors of q.
            // These are the prime factors that contribute to q's divisibility.
            std::vector<long long> q_prime_factors = get_prime_factors(q);

            long long max_x = 1;

            // For each unique prime factor f of q:
            // We try to construct an x by dividing p by f until p is no longer divisible by q.
            // The resulting p' will be a candidate for x.
            // We want the maximum among all such candidates.
            for (long long f : q_prime_factors) {
                long long current_p = p;
                // Divide current_p by f until it's no longer divisible by q.
                // This means we remove enough factors of f from current_p
                // such that current_p's exponent of f is less than q's exponent of f.
                // Or, more simply, current_p is no longer divisible by q.
                while (current_p % q == 0) {
                    current_p /= f;
                }
                // current_p is now a divisor of original p, and current_p is not divisible by q.
                // This current_p is a candidate for x.
                max_x = std::max(max_x, current_p);
            }
            std::cout << max_x << "\n";
        }
    }
    return 0;
}

