#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    for (int p = 0; p <= 9; ++p) { // p is the pivot digit
        std::vector<int> colors(n);
        int last1 = -1; // last digit placed in color 1
        int first2 = -1; // first digit placed in color 2 (not yet, but will be)
        int last2 = -1; // last digit placed in color 2

        bool possible_for_p = true;
        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                // Must be color 1
                if (d[i] < last1) {
                    possible_for_p = false;
                    break;
                }
                colors[i] = 1;
                last1 = d[i];
            } else if (d[i] > p) {
                // Must be color 2
                if (d[i] < last2) {
                    possible_for_p = false;
                    break;
                }
                colors[i] = 2;
                last2 = d[i];
                if (first2 == -1) {
                    first2 = d[i];
                }
            } else { // d[i] == p
                // Can be color 1 or color 2
                // If we already started color 2 (i.e., first2 != -1), then this 'p' must go to color 2
                if (first2 != -1) {
                    if (d[i] < last2) { // d[i] == p, so p < last2
                        possible_for_p = false;
                        break;
                    }
                    colors[i] = 2;
                    last2 = d[i];
                } else {
                    // If we haven't started color 2 yet, this 'p' can go to color 1
                    // as long as it maintains non-decreasing order for color 1.
                    // If it goes to color 1, it becomes the new last1.
                    // If it goes to color 2, it becomes the new first2 and last2.
                    // To maximize chances, we prefer putting it in color 2 if last1 <= p.
                    // This allows more digits < p to be put in color 1 later.
                    // But if last1 > p, it must go to color 2.
                    if (d[i] < last1) { // d[i] == p, so p < last1
                        // Must go to color 2
                        if (d[i] < last2) { // d[i] == p, so p < last2
                            possible_for_p = false;
                            break;
                        }
                        colors[i] = 2;
                        last2 = d[i];
                        if (first2 == -1) {
                            first2 = d[i];
                        }
                    } else { // d[i] >= last1 (p >= last1)
                        // Can go to color 1
                        colors[i] = 1;
                        last1 = d[i];
                    }
                }
            }
        }

        if (possible_for_p) {
            // Final check: last1 <= first2 (if both exist)
            if (last1 != -1 && first2 != -1 && last1 > first2) {
                possible_for_p = false;
            }
        }

        if (possible_for_p) {
            for (int i = 0; i < n; ++i) {
                std::cout << colors[i];
            }
            std::cout << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

