int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum_k = sum_{k=1 to a} k
    // Sum_k = a * (a + 1) / 2
    long long sum_k = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k = sum_k * ((MOD + 1) / 2) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // Sum_r = sum_{r=1 to b-1} r
    // Sum_r = (b-1) * b / 2
    long long sum_r = ((b - 1) % MOD * (b % MOD)) % MOD;
    sum_r = sum_r * ((MOD + 1) / 2) % MOD; // (MOD + 1) / 2 is modular inverse of 2

    // The total sum is (sum_k * b + a) * sum_r
    // Let's calculate (sum_k * b + a) first
    long long term1 = (sum_k * (b % MOD)) % MOD;
    term1 = (term1 + (a % MOD)) % MOD;

    long long ans = (term1 * sum_r) % MOD;

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i - 1]);
            adj[s[i - 1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string keyboard_layout = "";
    std::set<char> visited;
    char start_char = '\0';

    // Find a starting character for a path (degree 1 node or first char if all degree 2)
    for (char c : used_in_s) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }
    if (start_char == '\0' && !used_in_s.empty()) { // All nodes have degree 2 (a cycle or a single path)
        start_char = *used_in_s.begin();
    }

    if (start_char != '\0') {
        char current = start_char;
        char prev = '\0'; // Sentinel for the first step

        while (visited.find(current) == visited.end()) {
            keyboard_layout += current;
            visited.insert(current);

            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }
            prev = current;
            current = next_char;
        }
    }

    if (keyboard_layout.length() != used_in_s.size()) {
        // This means there are multiple disconnected components in the graph formed by s
        // or a cycle was formed and not all characters from s were included.
        // Since we only allow paths, this implies an issue.
        // However, the problem statement implies a single path/chain for the required adjacencies.
        // If there are multiple components, it's impossible to put them in one line while maintaining adjacencies.
        // Example: s = "ab", then "cd". This would require (a,b) and (c,d) adjacencies.
        // If we put "ab", then "cd" cannot be adjacent.
        // The only way this could work is if the graph is a single path.
        // If the graph has multiple components, or a cycle that doesn't cover all used_in_s, it's NO.
        // The current logic for building keyboard_layout only follows one path.
        // If start_char was found and the loop finished, and not all used_in_s are in keyboard_layout,
        // it means there are disconnected components or a cycle that doesn't include all.
        // This is implicitly handled by checking if all used_in_s are visited.
        std::cout << "NO\n";
        return;
    }

    // Add remaining characters not in s
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            keyboard_layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << keyboard_layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

