void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial total balance
    int total_balance = 0;
    for (int x : a) {
        if (x == 1) {
            total_balance++;
        } else {
            total_balance--;
        }
    }

    // Store balances for prefixes of the left side (jars n down to 1)
    // and suffixes of the right side (jars n+1 up to 2n)
    // The map stores balance -> minimum number of jars removed to achieve that balance
    std::map<int, int> left_balances;
    left_balances[0] = 0; // 0 jars removed from left, balance 0

    int current_balance = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            current_balance++;
        } else {
            current_balance--;
        }
        if (left_balances.find(current_balance) == left_balances.end()) {
            left_balances[current_balance] = (n - i);
        }
    }

    // Iterate through possible removals from the right side
    // For each right removal, calculate the required balance from the left side
    // and find the minimum total removals.
    int min_removed = 2 * n; // Max possible removals

    // Case 0: No jars removed from the right side
    // The remaining jars on the right side contribute total_balance - current_balance_left
    // So, the balance of remaining jars is current_balance_left + (total_balance - current_balance_left) = total_balance.
    // We need total_balance to be 0.
    // If total_balance is 0, then 0 jars removed from right, and 0 jars removed from left.
    // This means the initial state already has equal counts.
    if (left_balances.count(total_balance)) {
        min_removed = std::min(min_removed, left_balances[total_balance]);
    }

    current_balance = 0;
    for (int i = n; i < 2 * n; ++i) {
        if (a[i] == 1) {
            current_balance++;
        } else {
            current_balance--;
        }
        int removed_right = (i - n + 1);

        // The balance of jars remaining on the right side is (total_balance - current_balance_right_removed).
        // We need the balance of remaining jars to be 0.
        // So, balance_left_remaining + (total_balance - current_balance_right_removed) = 0
        // balance_left_remaining = current_balance_right_removed - total_balance
        int required_left_balance = current_balance - total_balance;

        if (left_balances.count(required_left_balance)) {
            min_removed = std::min(min_removed, removed_right + left_balances[required_left_balance]);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit.
    // For each bit position (0-9), we need to know how it transforms 0 and 1.
    // initial_val_0[bit_idx] = 0 after all operations if input bit is 0
    // initial_val_1[bit_idx] = 0 after all operations if input bit is 1
    // We want to find the final state for an input bit 0 and an input bit 1.
    // Let's track two numbers:
    // current_val_if_input_is_0: what the output would be if all input bits were 0
    // current_val_if_input_is_1023: what the output would be if all input bits were 1
    // (This is not quite right. We need to track for each bit position independently.)

    // Let's track two values:
    // `val_0`: the result if the initial input was 0.
    // `val_1023`: the result if the initial input was 1023 (all 1s for bits 0-9).
    // This is equivalent to tracking for each bit position:
    // `bit_0_becomes_0_or_1`: what the bit becomes if input bit is 0
    // `bit_1_becomes_0_or_1`: what the bit becomes if input bit is 1
    //
    // Let's use `current_val_for_0` and `current_val_for_1023`.
    // `current_val_for_0` starts at 0.
    // `current_val_for_1023` starts at 1023.
    // After all operations, `current_val_for_0` will be the result for input 0.
    // After all operations, `current_val_for_1023` will be the result for input 1023.
    //
    // For any bit `b`:
    // The `b`-th bit of `current_val_for_0` tells us what `0_b` becomes.
    // The `b`-th bit of `current_val_for_1023` tells us what `1_b` becomes.

    int current_val_for_0 = 0;
    int current_val_for_1023 = 1023; // All 1s for bits 0-9

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val_for_0 &= x;
            current_val_for_1023 &= x;
        } else if (op_char == '|') {
            current_val_for_0 |= x;
            current_val_for_1023 |= x;
        } else if (op_char == '^') {
            current_val_for_0 ^= x;
            current_val_for_1023 ^= x;
        }
    }

    // Now we have the final state for input 0 and input 1023.
    // For each bit position `b` (0 to 9):
    // `bit_0_becomes_val = (current_val_for_0 >> b) & 1`
    // `bit_1_becomes_val = (current_val_for_1023 >> b) & 1`

    // We need to find three constants A, B, C such that:
    // ( ( (x & A) | B) ^ C )
    // or a shorter sequence.
    //
    // Let's try to construct the final operations.
    // We need to find `final_and_mask`, `final_or_mask`, `final_xor_mask`.
    //
    // For each bit `b`:
    // Let `f_0 = (current_val_for_0 >> b) & 1` (what 0 becomes)
    // Let `f_1 = (current_val_for_1023 >> b) & 1` (what 1 becomes)
    //
    // Case 1: `f_0 = 0, f_1 = 0`
    //   Input bit `x_b` always becomes 0.
    //   This means `(x_b & A_b) | B_b ^ C_b` must be 0 for `x_b=0` and `x_b=1`.
    //   This implies `A_b` must be 0.
    //   If `A_b = 0`, then `(0 | B_b) ^ C_b = 0`.
    //   So `B_b ^ C_b = 0`, which means `B_b = C_b`.
    //   To achieve `f_0=0, f_1=0`, we need `A_b=0`.
    //   This means `final_and_mask` must have 0 at bit `b`.
    //   `final_or_mask` and `final_xor_mask` can be anything as long as `B_b = C_b`.
    //   The simplest way to force 0 is `& 0`.
    //   So, `final_and_mask` will have 0 at bit `b`.
    //   `final_or_mask` will have 0 at bit `b`.
    //   `final_xor_mask` will have 0 at bit `b`.
    //   This means `A_b = 0`, `B_b = 0`, `C_b = 0`.
    //
    // Case 2: `f_0 = 0, f_1 = 1`
    //   Input bit `x_b` becomes `x_b`. (Identity)
    //   This means `(x_b & A_b) | B_b ^ C_b = x_b`.
    //   For `x_b=0`: `(0 & A_b) | B_b ^ C_b = 0` => `B_b ^ C_b = 0` => `B_b = C_b`.
    //   For `x_b=1`: `(1 & A_b) | B_b ^ C_b = 1` => `A_b | B_b ^ C_b = 1`.
    //   Since `B_b = C_b`, `B_b ^ C_b = 0`.
    //   So `A_b | 0 = 1` => `A_b = 1`.
    //   To achieve `f_0=0, f_1=1`, we need `A_b=1, B_b=0, C_b=0`.
    //   So, `final_and_mask` will have 1 at bit `b`.
    //   `final_or_mask` will have 0 at bit `b`.
    //   `final_xor_mask` will have 0 at bit `b`.
    //
    // Case 3: `f_0 = 1, f_1 = 0`
    //   Input bit `x_b` becomes `!x_b`. (NOT)
    //   This means `(x_b & A_b) | B_b ^ C_b = !x_b`.
    //   For `x_b=0`: `(0 & A_b) | B_b ^ C_b = 1` => `B_b ^ C_b = 1`.
    //   For `x_b=1`: `(1 & A_b) | B_b ^ C_b = 0` => `A_b | B_b ^ C_b = 0`.
    //   Since `B_b ^ C_b = 1`, this means `A_b | 1 = 0`, which is impossible.
    //   This implies that a single `&`, `|`, `^` sequence cannot achieve `!x_b` if `A_b` is forced to be 0 or 1.
    //   However, we are looking for a sequence of up to 5 operations.
    //   The problem states "no more than 5 lines".
    //   The standard way to represent any 2-input boolean function (like `f_0, f_1`) is:
    //   `x_b & A_b` (if `f_0=0, f_1=1`)
    //   `x_b | B_b` (if `f_0=0, f_1=1`)
    //   `x_b ^ C_b` (if `f_0=0, f_1=1`)
    //
    // Let's define the target values for the three operations:
    // `and_val`: The constant for the `&` operation.
    // `or_val`: The constant for the `|` operation.
    // `xor_val`: The constant for the `^` operation.
    //
    // Initialize `and_val` to all 1s (1023), `or_val` to all 0s (0), `xor_val` to all 0s (0).
    // This corresponds to `x & 1023 | 0 ^ 0`, which is just `x`.
    //
    // For each bit `b` from 0 to 9:
    // `f_0 = (current_val_for_0 >> b) & 1`
    // `f_1 = (current_val_for_1023 >> b) & 1`
    //
    // If `f_0 = 0, f_1 = 0`:
    //   The bit must always become 0.
    //   To achieve this, we must set `and_val`'s `b`-th bit to 0.
    //   `and_val &= ~(1 << b)`
    //   `or_val`'s `b`-th bit must be 0.
    //   `xor_val`'s `b`-th bit must be 0.
    //
    // If `f_0 = 0, f_1 = 1`:
    //   The bit must be `x_b`. (Identity)
    //   To achieve this, `and_val`'s `b`-th bit must be 1.
    //   `or_val`'s `b`-th bit must be 0.
    //   `xor_val`'s `b`-th bit must be 0.
    //
    // If `f_0 = 1, f_1 = 0`:
    //   The bit must be `!x_b`. (NOT)
    //   To achieve this, `and_val`'s `b`-th bit must be 1.
    //   `or_val`'s `b`-th bit must be 0.
    //   `xor_val`'s `b`-th bit must be 1.
    //
    // If `f_0 = 1, f_1 = 1`:
    //   The bit must always become 1.
    //   To achieve this, `and_val`'s `b`-th bit must be 1.
    //   `or_val`'s `b`-th bit must be 1.
    //   `xor_val`'s `b`-th bit must be 0.

    int final_and_mask = 1023; // All 1s
    int final_or_mask = 0;     // All 0s
    int final_xor_mask = 0;    // All 0s

    for (int b = 0; b < 10; ++b) {
        int f_0 = (current_val_for_0 >> b) & 1;
        int f_1 = (current_val_for_1023 >> b) & 1;

        if (f_0 == 0 && f_1 == 0) { // Output bit is always 0
            // To make output 0: (x_b & 0) | 0 ^ 0 = 0
            // So, set `and_val` bit to 0.
            final_and_mask &= ~(1 << b);
            // `or_val` bit remains 0.
            // `xor_val` bit remains 0.
        } else if (f_0 == 0 && f_1 == 1) { // Output bit is x_b (identity)
            // To make output x_b: (x_b & 1) | 0 ^ 0 = x_b
            // So, `and_val` bit remains 1.
            // `or_val` bit remains 0.
            // `xor_val` bit remains 0.
        } else if (f_0 == 1 && f_1 == 0) { // Output bit is !x_b (NOT)
            // To make output !x_b: (x_b & 1) | 0 ^ 1 = !x_b
            // So, `and_val` bit remains 1.
            // `or_val` bit remains 0.
            // `xor_val` bit must be 1.
            final_xor_mask |= (1 << b);
        } else if (f_0 == 1 && f_1 == 1) { // Output bit is always 1
            // To make output 1: (x_b & 1) | 1 ^ 0 = 1
            // So, `and_val` bit remains 1.
            // `or_val` bit must be 1.
            // `xor_val` bit remains 0.
            final_or_mask |= (1 << b);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_mask != 1023) { // If not all 1s, means some bits are forced to 0
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) { // If not all 0s, means some bits are forced to 1
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) { // If not all 0s, means some bits are flipped
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

