        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        // Ensure abs_n >= abs_m for simpler logic
        if (abs_n < abs_m) {
            std::swap(abs_n, abs_m);
        }

        // Case 1: k < abs_n (not enough moves to reach the furthest coordinate)
        if (k < abs_n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: k >= abs_n
        // We can always reach (abs_n, abs_m) in abs_n moves using abs_m diagonal moves
        // and (abs_n - abs_m) axial moves.
        // The remaining k - abs_n moves must be used to return to (abs_n, abs_m).
        // Each pair of moves (e.g., (1,0) then (-1,0)) effectively uses 2 moves
        // and changes the parity of the sum of coordinates by 0.
        // Each pair of moves (e.g., (1,1) then (-1,-1)) effectively uses 2 moves
        // and changes the parity of the sum of coordinates by 0.
        //
        // The parity of (x+y) changes with each move.
        // (x1, y1) -> (x2, y2)
        // (x2+y2) - (x1+y1) = (x2-x1) + (y2-y1)
        // (x2-x1) is -1, 0, or 1. (y2-y1) is -1, 0, or 1.
        // The sum (x2-x1) + (y2-y1) can be -2, -1, 0, 1, 2.
        // It cannot be 0 if it's a move.
        // If it's a diagonal move, (x2-x1) and (y2-y1) are both non-zero.
        //   e.g., (1,1) -> sum change is 2. (1,-1) -> sum change is 0.
        //   This is not correct. (x2-x1) + (y2-y1) is the change in sum.
        //   A move changes x by dx, y by dy.
        //   (x+y) changes by (dx+dy).
        //   dx, dy are in {-1, 0, 1}. Not both 0.
        //   dx+dy can be -2, -1, 0, 1, 2.
        //   If dx+dy is even, (x+y) parity doesn't change.
        //   If dx+dy is odd, (x+y) parity changes.
        //   Moves like (1,0), (-1,0), (0,1), (0,-1) have dx+dy = +/-1. Parity changes.
        //   Moves like (1,1), (-1,-1) have dx+dy = +/-2. Parity doesn't change.
        //   Moves like (1,-1), (-1,1) have dx+dy = 0. Parity doesn't change.
        //
        // This parity argument is tricky. A simpler one:
        // Each move changes the parity of x or y or both.
        // If x changes, x_parity flips. If y changes, y_parity flips.
        //
        // Consider the parity of (abs_n + abs_m) and k.
        // Each move changes the parity of (x+y).
        // So, after k moves, the parity of (final_x + final_y) must be the same as the parity of (initial_x + initial_y + k).
        // Initial: (0,0). So (0+0) = 0.
        // Final: (abs_n, abs_m).
        // So, (abs_n + abs_m) must have the same parity as k.
        // If (abs_n + abs_m) % 2 != k % 2, it's impossible.
        // This is equivalent to (k - (abs_n + abs_m)) % 2 != 0.
        //
        // Let's check this condition.
        if ((k - abs_n) % 2 != (abs_m - abs_n) % 2) { // (k - abs_n) and (abs_m - abs_n) must have same parity
                                                      // This is equivalent to (k - abs_n - (abs_m - abs_n)) % 2 == 0
                                                      // which simplifies to (k - abs_m) % 2 == 0
                                                      // or (k % 2) == (abs_m % 2)
                                                      //
                                                      // Let's re-evaluate the parity condition.
                                                      // The sum of coordinates (x+y) changes parity with each axial move.
                                                      // (x+y) parity does not change with diagonal moves.
                                                      // Let `d` be diagonal moves, `a` be axial moves.
                                                      // `k = d + a`.
                                                      // Final (abs_n, abs_m). Initial (0,0).
                                                      // Parity of (abs_n + abs_m) must be equal to parity of `a`.
                                                      // So, (abs_n + abs_m) % 2 == a % 2.
                                                      // We know `a = k - d`.
                                                      // So, (abs_n + abs_m) % 2 == (k - d) % 2.
                                                      //
                                                      // We want to maximize `d`.
                                                      // The maximum possible `d` is `k`.
                                                      // The minimum number of moves to reach (abs_n, abs_m) is `abs_n`.
                                                      // In these `abs_n` moves, we use `abs_m` diagonal moves and `abs_n - abs_m` axial moves.
                                                      // So, `d_min_path = abs_m`, `a_min_path = abs_n - abs_m`.
                                                      //
                                                      // The remaining `k - abs_n` moves must be "wasted" moves.
                                                      // Each wasted move must be paired with another move to return to the same spot,
                                                      // or move to an adjacent spot and then back.
                                                      // A pair of moves like (1,0) then (-1,0) uses 2 moves, 0 diagonal, 2 axial.
                                                      // A pair of moves like (1,1) then (-1,-1) uses 2 moves, 2 diagonal, 0 axial.
                                                      //
                                                      // The key insight is that each move changes the parity of the sum of coordinates (x+y) if and only if it's an axial move.
                                                      // (x_final + y_final) % 2 == (x_initial + y_initial + (number of axial moves)) % 2
                                                      // (abs_n + abs_m) % 2 == (0 + 0 + a) % 2
                                                      // (abs_n + abs_m) % 2 == a % 2
                                                      // Since k = d + a, then a = k - d.
                                                      // (abs_n + abs_m) % 2 == (k - d) % 2
                                                      //
                                                      // We want to maximize `d`.
                                                      // The maximum `d` is `k`.
                                                      // If we use `k` diagonal moves, then `a = 0`.
                                                      // Condition becomes (abs_n + abs_m) % 2 == 0 % 2.
                                                      // If (abs_n + abs_m) is even, we can potentially use `k` diagonal moves.
                                                      //
                                                      // If (abs_n + abs_m) is odd, we must have `a` be odd.
                                                      // This means `k - d` must be odd.
                                                      // If `k` is even, `d` must be odd.
                                                      // If `k` is odd, `d` must be even.
                                                      // In general, `d` must have different parity than `k` if `(abs_n + abs_m)` is odd.
                                                      //
                                                      // Let's consider the parity of `k` and `abs_n + abs_m`.
                                                      // If `k` and `abs_n + abs_m` have different parities, we need to adjust.
                                                      // Each "wasted" move (beyond the minimum `abs_n` moves) can be thought of as
                                                      // moving to an adjacent cell and then immediately back.
                                                      // For example, (x,y) -> (x+1,y) -> (x,y). This uses 2 axial moves.
                                                      // Or (x,y) -> (x+1,y+1) -> (x,y). This uses 2 diagonal moves.
                                                      //
                                                      // The minimum number of moves to reach (abs_n, abs_m) is `abs_n`.
                                                      // In these `abs_n` moves, we use `abs_m` diagonal moves and `abs_n - abs_m` axial moves.
                                                      // The number of remaining moves is `k - abs_n`.
                                                      // These `k - abs_n` moves must be used in pairs, effectively returning to the same point.
                                                      // So, `k - abs_n` must be even.
                                                      // If `(k - abs_n)` is odd, it's impossible.
                                                      // This is the same as `k % 2 != abs_n % 2`.
                                                      //
                                                      // Let's test this condition:
                                                      // Example 1: (2,2,3) -> abs_n=2, abs_m=2, k=3.
                                                      // k >= abs_n (3 >= 2) -> OK.
                                                      // (k - abs_n) % 2 != 0? (3 - 2) % 2 = 1 % 2 = 1. So it's odd.
                                                      // According to this, it should be impossible. But example output is 1.
                                                      // This parity condition is wrong.

        // Let's re-evaluate the parity condition based on the example.
        // (0,0) -> (2,2) in 3 moves. Max diagonal = 1.
        // Path: (0,0) -> (1,0) (axial) -> (1,1) (diagonal) -> (2,2) (diagonal).
        // Total moves = 3. Diagonal = 2. Axial = 1.
        // Wait, example path is (0,0) -> (1,0) -> (1,1) -> (2,2).
        // This path has 2 diagonal moves. Output is 1. Why?
        // Ah, the example path is (0,0) -> (1,0) -> (1,1) -> (2,2).
        // (0,0) to (1,0) is axial.
        // (1,0) to (1,1) is axial.
        // (1,1) to (2,2) is diagonal.
        // Total moves = 3. Diagonal = 1. Axial = 2.
        // This path has 1 diagonal move.
        //
        // My understanding of "diagonal move" was: x1 != x2 AND y1 != y2.
        // (1,0) to (1,1): x1=1, x2=1, y1=0, y2=1. x1=x2, so NOT diagonal. This is axial.
        // (1,1) to (2,2): x1=1, x2=2, y1=1, y2=2. x1!=x2 AND y1!=y2. This IS diagonal.
        // So the example path has 1 diagonal move. This matches the output.

        // Let's re-think the parity.
        // Each move changes the parity of x or y or both.
        // The parity of (x,y) changes to (x',y').
        // (x',y') can be (x+dx, y+dy).
        // Parity of x changes if dx != 0. Parity of y changes if dy != 0.
        //
        // Consider the parity of the coordinates (x,y).
        // Start: (0,0) -> (even, even)
        // After 1 move:
        // Axial: (1,0) -> (odd, even)
        // Axial: (0,1) -> (even, odd)
        // Diagonal: (1,1) -> (odd, odd)
        //
        // After k moves, the parity of (x,y) will be:
        // If k is odd: (odd, even), (even, odd), or (odd, odd)
        // If k is even: (even, even), (odd, odd)
        //
        // This is not quite right.
        // The parity of x changes if dx is odd. The parity of y changes if dy is odd.
        // dx, dy are in {-1, 0, 1}.
        // dx is odd if dx = +/-1. dx is even if dx = 0.
        // dy is odd if dy = +/-1. dy is even if dy = 0.
        //
        // A diagonal move (dx!=0, dy!=0) changes both x and y parities.
        // An axial move (dx!=0, dy=0 or dx=0, dy!=0) changes exactly one parity.
        //
        // Let `d` be diagonal moves, `a` be axial moves. `k = d + a`.
        // Each diagonal move flips both x and y parities.
        // Each axial move flips exactly one parity.
        //
        // Final (abs_n, abs_m). Initial (0,0).
        // Parity of abs_n must be (0 + (number of moves that flip x parity)) % 2.
        // Parity of abs_m must be (0 + (number of moves that flip y parity)) % 2.
        //
        // Number of moves that flip x parity = `d` (from diagonal) + `a_x` (from axial moves along x-axis).
        // Number of moves that flip y parity = `d` (from diagonal) + `a_y` (from axial moves along y-axis).
        // `a_x + a_y = a`.
        //
        // So, `abs_n % 2 == (d + a_x) % 2`.
        // And `abs_m % 2 == (d + a_y) % 2`.
        //
        // Summing these: `(abs_n + abs_m) % 2 == (2d + a_x + a_y) % 2 == (a_x + a_y) % 2 == a % 2`.
        // This is the same parity condition as before: `(abs_n + abs_m) % 2 == (k - d) % 2`.
