int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> L(n, 0), R(n, 0);

    // Calculate L[i]: length of consecutive 0s ending at i, if a[i]=0
    // or length of consecutive 1s ending at i, if a[i]=1
    // This is for blocks of same values.
    L[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == a[i - 1]) {
            L[i] = L[i - 1] + 1;
        } else {
            L[i] = 1;
        }
    }

    // Calculate R[i]: length of consecutive 0s starting at i, if a[i]=0
    // or length of consecutive 1s starting at i, if a[i]=1
    R[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == a[i + 1]) {
            R[i] = R[i + 1] + 1;
        } else {
            R[i] = 1;
        }
    }

    int max_k = 0;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] != a[i - 1] && a[i] != a[i + 1]) { // Pattern 010 or 101
            int len_left = L[i - 1];
            int len_right = R[i + 1];
            int k_val = (std::min(len_left, len_right) + 1) / 2;
            max_k = std::max(max_k, k_val);
        }
    }

    std::cout << max_k << "\n";

    std::vector<int> b = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] != a[i - 1] && a[i] != a[i + 1]) { // Pattern 010 or 101
            int len_left = L[i - 1];
            int len_right = R[i + 1];

            // If a[i] is 0, it will become 1 if it's part of a 101 pattern that flips.
            // If a[i] is 1, it will become 0 if it's part of a 010 pattern that flips.
            // The value flips if its distance to the nearest stable block is <= max_k.
            // The distance is min(len_left, len_right).
            // A block of length L_left and L_right will flip up to min(L_left, L_right) positions.
            // The i-th element (0-indexed) is at distance L_left from the left block and L_right from the right block.
            // The number of steps for a[i] to flip is (min(len_left, len_right) + 1) / 2.
            // If this number of steps is <= max_k, then a[i] will flip.
            // Since we are calculating the final state after max_k steps,
            // any a[i] that would flip in max_k or fewer steps will flip.
            // This means if (min(len_left, len_right) + 1) / 2 <= max_k, it flips.
            // This is equivalent to min(len_left, len_right) < 2 * max_k.
            // Or, more simply, if min(len_left, len_right) is odd, it flips to the value of the longer block.
            // If min(len_left, len_right) is even, it flips to the value of the shorter block.
            // But after max_k steps, all such alternating patterns of length < 2*max_k + 1 will be resolved.
            // The value of b[i] will be determined by the majority of the surrounding blocks.
            // If len_left > len_right, b[i] becomes a[i-1].
            // If len_right > len_left, b[i] becomes a[i+1].
            // If len_left == len_right, b[i] becomes a[i-1] (or a[i+1], they are the same).
            // This is because a[i-1] and a[i+1] are the same value in this case (010 or 101).
            // So b[i] becomes a[i-1] (or a[i+1]).

            // The rule is: if min(len_left, len_right) >= 2*max_k, then a[i] remains a[i].
            // Otherwise, it flips to a[i-1] (which is also a[i+1]).
            if (std::min(len_left, len_right) < 2 * max_k) {
                b[i] = a[i - 1]; // a[i-1] == a[i+1] in this case
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

