#include <iostream>
#include <vector>
#include <numeric>
#include <list>

struct Child {
    long long v, d, p;
    int original_idx;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::list<Child> children_in_line;
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children_in_line.push_back({v_val, d_val, p_val, i + 1});
    }

    std::vector<int> cured_children_indices;

    while (!children_in_line.empty()) {
        Child current_doctor_child = children_in_line.front();
        children_in_line.pop_front();
        cured_children_indices.push_back(current_doctor_child.original_idx);

        long long v_cry_effect = current_doctor_child.v;
        long long d_cry_total_effect = 0;

        auto it = children_in_line.begin();
        while (it != children_in_line.end()) {
            // Apply d_cry_total_effect from previous children who left
            it->p -= d_cry_total_effect;

            // Apply v_cry_effect from the child currently at the doctor
            if (v_cry_effect > 0) {
                it->p -= v_cry_effect;
                v_cry_effect--;
            }

            if (it->p < 0) {
                d_cry_total_effect += it->d;
                it = children_in_line.erase(it); // Child leaves, iterator invalidated
            } else {
                ++it; // Move to the next child
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long a0 = elements[0].value;
    long long a1 = elements[1].value;
    long long an_2 = elements[n - 2].value;
    long long an_1 = elements[n - 1].value;

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // f values are only a_i + a_j.
    // min_f = a0 + a1
    // max_f = an_2 + an_1
    // Goodness = (an_2 + an_1) - (a0 + a1)
    long long goodness1 = (an_2 + an_1) - (a0 + a1);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Partition into two non-empty subsequences.
    // This case is only relevant if h is small enough.
    // The minimum possible f value is a0 + a1.
    // The maximum possible f value is an_1 + an_2 + h (if an_1 and an_2 are in different groups)
    // or an_1 + an_2 (if an_1 and an_2 are in the same group)
    // or an_1 + a_k + h (if an_1 is in one group and a_k in another)
    //
    // Consider the partition where a0 is in S1, and all other elements are in S2.
    // S1 = {a0}
    // S2 = {a1, a2, ..., an-1}
    //
    // Possible f values:
    // 1. a_i + a_j for a_i, a_j in S2: min is a1 + a2, max is an_2 + an_1
    // 2. a0 + a_j + h for a_j in S2: min is a0 + a1 + h, max is a0 + an_1 + h
    //
    // Overall min_f = min(a1 + a2, a0 + a1 + h)
    // Overall max_f = max(an_2 + an_1, a0 + an_1 + h)
    //
    // This specific partition strategy (a0 in S1, rest in S2) is chosen because it often minimizes goodness
    // when h is not too large. It tries to keep the smallest element separate to reduce the range of sums.
    //
    // Let's analyze the values:
    // min_f_val = min(a0 + a1 + h, a1 + a2)
    // max_f_val = max(a0 + an_1 + h, an_2 + an_1)
    //
    // Goodness = max_f_val - min_f_val
    //
    // This is the strategy used in the sample output for 3 2 / 1 2 3.
    // a0=1, a1=2, a2=3, h=2
    // S1={1}, S2={2,3}
    // f(1,2) = 1+2+2 = 5
    // f(1,3) = 1+3+2 = 6
    // f(2,3) = 2+3 = 5
    // min_f = 5, max_f = 6, goodness = 1.
    //
    // Let's calculate this goodness.
    long long min_f_val_case2 = std::min(a0 + a1 + h, a1 + a0 + h); // a1+a2 is not always present if n=2
    if (n > 2) { // If n=2, S2 only has one element, so no a1+a2 type sum.
        min_f_val_case2 = std::min(min_f_val_case2, a1 + elements[2].value);
    }

    long long max_f_val_case2 = std::max(a0 + an_1 + h, an_2 + an_1);

    long long goodness2 = max_f_val_case2 - min_f_val_case2;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    // Compare goodness1 and goodness2
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // max_r_for_l[l] stores the maximum r such that the substring s[l...r]
    // does NOT contain any 3-AP.
    // Initialize with n-1, meaning s[l...n-1] is assumed to be bad initially.
    // This will be updated to a smaller value if a 3-AP is found.
    std::vector<int> max_r_for_l(n);
    for (int i = 0; i < n; ++i) {
        max_r_for_l[i] = n - 1;
    }

    // Iterate through all possible starting positions x for a 3-AP
    for (int x = 0; x < n; ++x) {
        // Iterate through possible common differences k
        // The maximum k is such that x + 2k < n, so 2k < n - x, k < (n - x) / 2
        // We only need to check small k values.
        // If k >= 3, then x+2k >= x+6.
        // If s_x = s_{x+k} = s_{x+2k}, then this 3-AP makes any substring
        // s[l...r] with l <= x and r >= x+2k "good".
        // This means that for any l <= x, the maximum r for which s[l...r]
        // is "bad" must be less than x+2k.
        // So, max_r_for_l[l] must be updated to min(max_r_for_l[l], x+2k - 1).
        // This update applies to all l from 0 to x.

        // For k=1: x, x+1, x+2
        if (x + 2 < n && s[x] == s[x+1] && s[x] == s[x+2]) {
            // This 3-AP starts at x and ends at x+2.
            // It makes any substring s[l...r] with l <= x and r >= x+2 "good".
            // So, for any l from 0 to x, the maximum r for which s[l...r] is "bad"
            // must be at most x+2-1 = x+1.
            for (int l = 0; l <= x; ++l) {
                max_r_for_l[l] = std::min(max_r_for_l[l], x + 1);
            }
        }
        // For k=2: x, x+2, x+4
        if (x + 4 < n && s[x] == s[x+2] && s[x] == s[x+4]) {
            // This 3-AP starts at x and ends at x+4.
            // For any l from 0 to x, max_r_for_l[l] must be at most x+4-1 = x+3.
            for (int l = 0; l <= x; ++l) {
                max_r_for_l[l] = std::min(max_r_for_l[l], x + 3);
            }
        }
        // For k=3: x, x+3, x+6
        if (x + 6 < n && s[x] == s[x+3] && s[x] == s[x+6]) {
            // This 3-AP starts at x and ends at x+6.
            // For any l from 0 to x, max_r_for_l[l] must be at most x+6-1 = x+5.
            for (int l = 0; l <= x; ++l) {
                max_r_for_l[l] = std::min(max_r_for_l[l], x + 5);
            }
        }
    }

    // Calculate the number of bad pairs (l, r)
    // For each l, any r such that l <= r <= max_r_for_l[l] forms a bad pair.
    for (int l = 0; l < n; ++l) {
        if (max_r_for_l[l] >= l) { // Ensure r is not less than l
            bad_pairs += (max_r_for_l[l] - l + 1);
        }
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

