    // So the new string is `s[0] + s[1...n-2] + s[0]`.
    // This is `s[0] + s.substr(1, n-2) + s[0]`.
    // This string is a palindrome if and only if `s.substr(1, n-2)` is a palindrome.
    // `s.substr(1, n-2)` is `s[1...n-2]`.
    // Since `s` is a palindrome, `s[1...n-2]` is also a palindrome.
    // So, `s[n-1] + s[1...n-2] + s[0]` is always a palindrome.
    // Is this new string different from `s`?
    // `s = s[0] + s[1...n-2] + s[n-1]`
    // `s_new = s[n-1] + s[1...n-2] + s[0]`
    // Since `s[0] == s[n-1]`, `s_new` is actually identical to `s`.
    // This specific reordering doesn't work.

    // Let's reconsider the general case for k=2.
    // If `s` is not all same characters, and `k=1` doesn't work, then `k=2` is the answer.
    // Why?
    // Consider `s = "abacaba"`. `n=7`.
    // `s[0...n-1]` is "abacaba".
    // `s[0...n-2]` is "abacab".
    // `s[1...n-1]` is "bacaba".
    // Neither "abacab" nor "bacaba" are palindromes.
    //
    // If `s` is not all same characters, then `s.substr(0, n-1)` is not a palindrome.
    // (Proof: If `s.substr(0, n-1)` is a palindrome, then `s[0] == s[n-2]`, `s[1] == s[n-3]`, etc.
    // Since `s` is a palindrome, `s[0] == s[n-1]`, `s[1] == s[n-2]`, etc.
    // Combining these, `s[0] == s[n-1]` and `s[0] == s[n-2]`, so `s[n-1] == s[n-2]`.
    // Similarly, `s[1] == s[n-2]` and `s[1] == s[n-3]`, so `s[n-2] == s[n-3]`.
    // Continuing this, all characters must be the same. This contradicts our assumption that `s` is not all same characters.)
    //
    // So, if `s` is not all same characters, then `s.substr(0, n-1)` is not a palindrome.
    // This means `s[0...n-2]` is not a palindrome.
    //
    // Consider the string `s_new = s[n-1] + s[0...n-2]`.
    // This is formed by one cut (between `s[n-2]` and `s[n-1]`) and swapping `s[n-1]` to the front.
    // This is a `k=1` operation.
    // We know `s_new != s` (otherwise `k=1` would have been found).
    // We also know `s_new` is not a palindrome (otherwise `k=1` would have been found).
    //
    // The problem states that if `s` is not all same characters, then `k=2` is always possible.
    // This is a known property for palindromes.
    // If a palindrome `s` is not composed of all identical characters, then `s` can be cut into two pieces `A` and `B` such that `B+A` is a palindrome different from `s`, OR `s` can be cut into three pieces `A, B, C` such that `CBA` is a palindrome different from `s`.
    // The first case is `k=1`. If `k=1` fails, then the second case implies `k=2`.
    //
    // The logic is:
    // 1. If all characters in `s` are the same, it's "Impossible".
    // 2. Otherwise, try `k=1`. If a valid `s'` is found, output 1.
    // 3. If `k=1` fails, then `k=2` is always the answer.
    //
    // The proof for why `k=2` is always possible if `s` is not all same characters and `k=1` fails:
    // If `s` is not all same characters, then `s.substr(0, n-1)` is not a palindrome.
    // (As shown above, if `s.substr(0, n-1)` were a palindrome, then all characters of `s` would be the same.)
    //
    // Let `s = s_0 s_1 ... s_{n-1}`.
    // Consider the string `s' = s_1 s_2 ... s_{n-1} s_0`.
    // This is formed by one cut (between `s_0` and `s_1`) and reordering.
    // We know `s'` is not `s` (otherwise `k=1` would have found it).
    // We know `s'` is not a palindrome (otherwise `k=1` would have found it).
    //
    // Now consider `k=2`.
    // Cut `s` into `s_0`, `s_1...s_{n-2}`, `s_{n-1}`.
    // Reorder to `s_1...s_{n-2} + s_0 + s_{n-1}`.
    // This is `s.substr(1, n-2) + s[0] + s[n-1]`.
    // Since `s` is a palindrome, `s[0] == s[n-1]`.
    // So this is `s.substr(1, n-2) + s[0] + s[0]`.
    // This is not necessarily a palindrome.
    //
    // A simpler argument for k=2:
    // If `s` is not all same characters, then `s.substr(0, n-1)` is not a palindrome.
    // Let `s_prefix = s.substr(0, n-1)`.
    // Let `s_suffix = s.substr(1, n-1)`.
    // Since `s` is a palindrome, `s_prefix` is `reverse(s_suffix)`.
    // Since `s_prefix` is not a palindrome, `s_suffix` is not a palindrome.
    //
    // Consider `s = "nolon"`. `n=5`.
    // `k=1` check:
    // `i=1`: "olon" + "n" = "olonn". Not palindrome.
    // `i=2`: "lon" + "no" = "lonno". Not palindrome.
    // `i=3`: "on" + "nol" = "onnol". Not palindrome.
    // `i=4`: "n" + "nolo" = "nnolo". Not palindrome.
    // `k=1` fails.
    // All chars not same. So `k=2` is the answer.
    // Example given: `no|l|on` -> `on|l|no`. This is `s[3..4] + s[2] + s[0..1]`.
    // `s[3..4]` is "on". `s[2]` is "l". `s[0..1]` is "no".
    // "on" + "l" + "no" = "onlno". This is a palindrome.
    // And "onlno" != "nolon". So `k=2` works.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

// Function to check if all target tracks can be covered within time T
bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    // `covered_until` stores the maximum track index covered by heads processed so far.
    // Initialize to a value smaller than any possible track index.
    long long covered_until = -2e18; // A sufficiently small number, e.g., smaller than 1 - 10^10 - 10^10

    // `p_idx` is the index of the current target track we are trying to cover.
    int p_idx = 0;

    // Iterate through each head
    for (int i = 0; i < n; ++i) {
        // If all target tracks are already covered, we are done.
        if (p_idx == m) {
            return true;
        }

        // Calculate the range this head can cover.
        long long head_left_reach = h[i] - T;
        long long head_right_reach = h[i] + T;

        // If the current head's range starts after the last covered point,
        // it means there's a gap. We need to ensure this gap doesn't contain any
        // target tracks.
        // If p[p_idx] is greater than covered_until, it means p[p_idx] is not yet covered.
        // We need to use the current head to cover p[p_idx].
        // The current head must be able to reach p[p_idx].
        // If p[p_idx] is to the left of head_left_reach, this head cannot cover it.
        // This implies that the previous heads (or this head if it's the first)
        // failed to cover p[p_idx].
        // In this case, we must advance p_idx until p[p_idx] is within or to the right
        // of head_left_reach.
        // This is effectively saying: if there's a gap between `covered_until` and `head_left_reach`,
        // and `p[p_idx]` falls into this gap, then it's impossible.
        // However, a simpler approach is to just ensure `p[p_idx]` is covered.
        // If `p[p_idx]` is not covered by previous heads (i.e., `p[p_idx] > covered_until`),
        // then this head must cover it.
        // The earliest track this head can cover is `head_left_reach`.
        // If `p[p_idx]` is to the left of `head_left_reach`, it's impossible to cover `p[p_idx]`
        // with this head or any subsequent head (since `h` is sorted, subsequent heads are even further right).
        // So, if `p[p_idx] > covered_until` and `p[p_idx] < head_left_reach`, it's impossible.
        // This condition is implicitly handled by the loop below.

        // Find the first target track `p[p_idx]` that is not yet covered by previous heads.
        // `p[p_idx]` must be greater than `covered_until`.
        // If `p[p_idx]` is to the left of `head_left_reach`, this head cannot cover it.
        // This means we need to use this head to cover `p[p_idx]` if `p[p_idx]` is not covered.
        // The current head can cover tracks from `head_left_reach` to `head_right_reach`.
        // We want to cover `p[p_idx]`.
        // If `p[p_idx]` is already covered (i.e., `p[p_idx] <= covered_until`), we advance `p_idx`.
        while (p_idx < m && p[p_idx] <= covered_until) {
            p_idx++;
        }
        if (p_idx == m) { // All tracks covered
            return true;
        }

        // Now, `p[p_idx]` is the first uncovered target track.
        // This head must cover `p[p_idx]`.
        // If `p[p_idx]` is to the left of `head_left_reach`, this head cannot cover it.
        // Since `h` is sorted, subsequent heads are even further right, so they also can't cover `p[p_idx]`.
        // Thus, it's impossible to cover all tracks.
        if (p[p_idx] < head_left_reach) {
            return false;
        }

        // If this head can cover `p[p_idx]`, we use it to cover `p[p_idx]` and extend coverage as far right as possible.
        // The new `covered_until` will be `head_right_reach`.
        covered_until = head_right_reach;
    }

    // After iterating through all heads, check if all target tracks are covered.
    // Advance `p_idx` for any remaining tracks that might be covered by the final `covered_until`.
    while (p_idx < m && p[p_idx] <= covered_until) {
        p_idx++;
    }

    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    // Binary search for the minimum time T
    long long low = 0;
    // The maximum possible distance between a head and a target track is roughly 10^10.
    // So, T can be up to 10^10.
    long long high = 2e10; // Max possible difference between p_i and h_i
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor ^= a;
    }

    // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor ^ b1 ^ b2 ^ b3)
    // Let S = current_sum and X = current_xor.
    // We want S' = 2 * X'.
    // S' = S + b1 + b2 + b3
    // X' = X ^ b1 ^ b2 ^ b3

    // Strategy: Append two numbers.
    // Let b1 = X.
    // Then X' = X ^ X ^ b2 = b2.
    // The equation becomes S + X + b2 = 2 * b2.
    // S + X = b2.
    // So, if we append X and (S + X), the array becomes good.
    // The appended elements are X and (S + X).
    // Number of elements to append: 2.
    // The elements are current_xor and (current_sum + current_xor).

    std::cout << 2 << std::endl;
    std::cout << current_xor << " " << (current_sum + current_xor) << std::endl;
}

