    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using a large constant for 'infinity' to detect cycles.
// Since y can go up to 2*10^5 * 10^9 = 2*10^14, a long long is needed.
// A value like 3 * 10^14 is safe for infinity.
const long long INF = 300000000000000LL; 

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // a_val[0] is unused, a_val[1] will be 'i' for each run.
    // a_val[2] to a_val[n] are the given values.
    std::vector<long long> a_val(n + 1);
    for (int k = 2; k <= n; ++k) {
        std::cin >> a_val[k];
    }

    // dp_y[k] stores the final y value if the program starts with x=k, y=0
    // and the first operation is step_sub (x = x - a[x], y = y + a[x]).
    // dp_y[k] = -1 if it never terminates.
    // dp_y[k] = INF if it's currently being computed (cycle detection).
    std::vector<long long> dp_y(n + 1, 0);

    // dp_x_final[k] stores the final x value if the program starts with x=k, y=0
    // and the first operation is step_sub.
    // This is needed to determine if it terminates or where it goes next.
    std::vector<long long> dp_x_final(n + 1, 0);

    // Iterate k from 1 to n.
    // For each k, we want to compute the result of starting at (k, 0) and
    // performing step_sub.
    // This means x becomes k - a[k], y becomes a[k].
    // The next step would be step_add.
    // We can compute this iteratively or recursively.
    // Since the problem structure is a DAG (or DAG with cycles),
    // we can use dynamic programming with cycle detection.
    // The states are (x, y_offset) where y_offset is the accumulated y from previous steps.
    // However, the problem structure is simpler:
    // From (x, y), we go to (x+a[x], y+a[x]), then to (x+a[x]-a[x+a[x]], y+a[x]+a[x+a[x]]).
    // The key observation is that the *next* state (x_next, y_next) only depends on the *current* x.
    // The y value is cumulative.
    // Let's define a function `solve(current_x)` that returns a pair `(final_x, final_y_increment)`
    // if the program starts at `current_x` and performs `step_add` then `step_sub` repeatedly.
    // `final_y_increment` is the total `y` added *from this point onwards*.

    // We need to compute dp_y[k] and dp_x_final[k] for k from 1 to n.
    // These values represent the outcome if the program is at state (k, current_y)
    // and the *next* operation is `step_sub`.
    // So, x becomes k - a[k], y becomes current_y + a[k].
    // The subsequent operations would be `step_add`, `step_sub`, etc.
    // This is exactly what we need for the main loop.

    // Initialize dp_y and dp_x_final for states that terminate immediately after step_sub.
    // For x_curr, if x_curr - a_val[x_curr] <= 0 or x_curr - a_val[x_curr] > n,
    // then dp_y[x_curr] = a_val[x_curr] and dp_x_final[x_curr] = x_curr - a_val[x_curr].
    // This is not quite right. The dp state should be for the *next* step.
    // Let's define `dp_y[k]` as the total `y` accumulated *from the point where x becomes k*
    // and the *next operation is step_add*.
    // And `dp_x_final[k]` as the final `x` value.

    // We can compute these values by iterating backwards or using memoized recursion.
    // Since `a[k]` can be large, `k + a[k]` or `k - a[k]` can jump far.
    // Memoized recursion is safer.

    // `memo_y[k]` stores the total `y` accumulated from state `k` (where `x=k` and next op is `step_add`).
    // `memo_x_final[k]` stores the final `x` value from state `k`.
    // `visited[k]` is used for cycle detection: 0 = unvisited, 1 = visiting, 2 = visited.
    std::vector<long long> memo_y(n + 1, 0);
    std::vector<long long> memo_x_final(n + 1, 0);
    std::vector<int> visited(n + 1, 0);

    // Function to compute (final_x, total_y_increment) starting from x_curr,
    // where the next operation is step_add.
    // Returns (final_x, total_y_increment).
    // If non-terminating, returns (0, -1).
    auto compute_path = [&](int start_x, auto& self_ref) -> std::pair<long long, long long> {
        if (start_x <= 0 || start_x > n) {
            return {start_x, 0}; // Terminated, no further y increment
        }
        if (visited[start_x] == 1) { // Cycle detected
            return {0, -1}; // Indicate non-termination
        }
        if (visited[start_x] == 2) { // Already computed
            return {memo_x_final[start_x], memo_y[start_x]};
        }

        visited[start_x] = 1; // Mark as visiting

        long long current_a = a_val[start_x];

        // Step 2: x = x + a[x], y = y + a[x]
        long long x_after_add = start_x + current_a;
        long long y_increment_add = current_a;

        // Check termination after step_add
        if (x_after_add <= 0 || x_after_add > n) {
            visited[start_x] = 2; // Mark as visited
            memo_x_final[start_x] = x_after_add;
            memo_y[start_x] = y_increment_add;
            return {x_after_add, y_increment_add};
        }

        // Step 3: y = y + a[x], x = x - a[x] (using a[x_after_add])
        long long a_after_add = a_val[x_after_add];
        long long x_after_sub = x_after_add - a_after_add;
        long long y_increment_sub = a_after_add;

        // Now, from (x_after_sub, y_increment_add + y_increment_sub), the next operation is step_add.
        // Recursively call for the next state.
        std::pair<long long, long long> next_result = self_ref(x_after_sub, self_ref);

        long long final_x = next_result.first;
        long long total_y_increment = y_increment_add + y_increment_sub;

        if (next_result.second == -1) { // Non-terminating path
            final_x = 0; // Indicate non-termination
            total_y_increment = -1;
        } else {
            total_y_increment += next_result.second;
        }

        visited[start_x] = 2; // Mark as visited
        memo_x_final[start_x] = final_x;
        memo_y[start_x] = total_y_increment;
        return {final_x, total_y_increment};
    };

    // Precompute for all possible starting x values (1 to n)
    // This fills memo_y, memo_x_final, and visited.
    for (int k = 1; k <= n; ++k) {
        if (visited[k] == 0) {
            compute_path(k, compute_path);
        }
    }

    // Now, for each i from 1 to n-1:
    // The sequence is i, a_2, a_3, ..., a_n.
    // This means a_val[1] = i.
    for (int i = 1; i < n; ++i) {
        a_val[1] = i; // Set a_val[1] for the current run

        // Initial state: x = 1, y = 0.
        // First operation is step_add.
        long long current_a = a_val[1];
        long long x_after_add = 1 + current_a;
        long long y_total = current_a;

        // Check termination after step_add
        if (x_after_add <= 0 || x_after_add > n) {
            std::cout << y_total << "\n";
            continue;
        }

        // Next operation is step_sub.
        long long a_after_add = a_val[x_after_add];
        long long x_after_sub = x_after_add - a_after_add;
        y_total += a_after_add;

        // Now, from (x_after_sub, y_total), the next operation is step_add.
        // We can use the precomputed results from `memo_y` and `memo_x_final`.
        // Note: `memo_y[k]` and `memo_x_final[k]` are computed assuming `a_val[1]` is fixed.
        // Since `a_val[1]` changes for each `i`, we cannot directly use the precomputed values for `k=1`.
        // However, for `k > 1`, `a_val[k]` is fixed.
        // The `compute_path` function was called with the *original* `a_val` array.
        // This means `memo_y[k]` and `memo_x_final[k]` are valid for `k > 1`.
        // For `k=1`, `compute_path(1, ...)` would have used the `a_val[1]` that was set *during* its call.
        // This implies we need to re-run `compute_path` for `start_x = 1` for each `i`.
        // But `compute_path` also depends on `a_val[x_after_add]` which might be `a_val[1]`.
        // This means the entire DP table might be invalidated if `a_val[1]` changes.

        // Let's re-evaluate the DP state.
        // The `a_val` array is fixed for `a_2, ..., a_n`. Only `a_1` changes.
        // `compute_path(k, ...)` depends on `a_val[k]` and `a_val[k + a_val[k]]`.
        // If `k > 1`, `a_val[k]` is fixed.
        // If `k + a_val[k] > 1`, `a_val[k + a_val[k]]` is fixed.
        // The only case where `a_val[1]` affects `compute_path(k, ...)` for `k > 1` is if `k + a_val[k] == 1`.
        // But `k > 1` and `a_val[k] >= 1`, so `k + a_val[k] >= 1 + 1 = 2`.
        // So `k + a_val[k]` will never be 1.
        // This means `compute_path(k, ...)` for `k > 1` is independent of `a_val[1]`.
        // The precomputed `memo_y[k]` and `memo_x_final[k]` for `k > 1` are valid.

        // For the current run with `a_val[1] = i`:
        // We are at `(x_after_sub, y_total)`.
        // The next step is `step_add` from `x_after_sub`.
        long long final_x_from_sub;
        long long y_increment_from_sub;

        if (x_after_sub <= 0 || x_after_sub > n) {
            final_x_from_sub = x_after_sub;
            y_increment_from_sub = 0;
        } else {
            // If x_after_sub is 1, we need to compute it on the fly because a_val[1] is 'i'.
            // If x_after_sub > 1, we can use the precomputed values.
            if (x_after_sub == 1) {
                // This is the tricky part. We need to compute `compute_path(1, ...)`
                // with the current `a_val[1] = i`.
                // This means we need to re-run the logic of `compute_path` for `start_x = 1`.
                // But `compute_path` uses `visited` and `memo` arrays.
                // If we just call `compute_path(1, ...)` it will use the old `visited[1]` and `memo_y[1]`.
                // We need a fresh computation for `start_x = 1` for each `i`.
                // This means we cannot use the `visited` and `memo` arrays for `start_x = 1`.
                // We need to simulate `compute_path(1, ...)` for each `i`.

                // Let's simulate the path starting from x_after_sub, with a_val[1] = i.
                // This simulation needs to handle cycles and use memoized results for x > 1.
                // To avoid recomputing for x > 1, we can use the existing memo_y/x_final for those.
                // For x = 1, we need to be careful.

                // Path simulation:
                long long current_x_sim = x_after_sub;
                long long current_y_sim_increment = 0;

                // To detect cycles involving x=1, we need a temporary visited set for this run.
                std::vector<bool> temp_visited_in_run(n + 1, false);
                bool cycle_detected_in_run = false;

                while (current_x_sim > 0 && current_x_sim <= n) {
                    if (current_x_sim == 1) {
                        if (temp_visited_in_run[1]) { // Cycle involving x=1
                            cycle_detected_in_run = true;
                            break;
                        }
                        temp_visited_in_run[1] = true;

                        // Step 2: x = x + a[x], y = y + a[x]
                        long long a_at_1 = a_val[1]; // This is 'i'
                        long long x_after_add_1 = current_x_sim + a_at_1;
                        current_y_sim_increment += a_at_1;

                        if (x_after_add_1 <= 0 || x_after_add_1 > n) {
                            current_x_sim = x_after_add_1; // Terminate
                            break;
                        }

                        // Step 3: y = y + a[x], x = x - a[x]
                        long long a_at_x_after_add_1 = a_val[x_after_add_1];
                        long long x_after_sub_1 = x_after_add_1 - a_at_x_after_add_1;
                        current_y_sim_increment += a_at_x_after_add_1;
                        current_x_sim = x_after_sub_1;
                    } else { // current_x_sim > 1, use precomputed values
                        if (memo_y[current_x_sim] == -1) { // Precomputed path leads to cycle
                            cycle_detected_in_run = true;
                            break;
                        }
                        current_y_sim_increment += memo_y[current_x_sim];
                        current_x_sim = memo_x_final[current_x_sim];
                        break; // Path resolved, either terminated or went into a cycle (handled by memo_y == -1)
                    }
                }

                if (cycle_detected_in_run) {
                    final_x_from_sub = 0; // Indicate non-termination
                    y_increment_from_sub = -1;
                } else {
                    final_x_from_sub = current_x_sim;
                    y_increment_from_sub = current_y_sim_increment;
                }

            } else { // x_after_sub > 1, use precomputed values
                final_x_from_sub = memo_x_final[x_after_sub];
                y_increment_from_sub = memo_y[x_after_sub];
            }
        }

        if (y_increment_from_sub == -1) { // Non-terminating path
            std::cout << -1 << "\n";
        } else {
            y_total += y_increment_from_sub;
            std::cout << y_total << "\n";
        }
    }

    return 0;
}

