#include <iostream>
#include <cmath>
#include <algorithm>

long long solve() {
    long long a, b;
    std::cin >> a >> b;

    if (a == b) {
        return 0;
    }

    long long diff = std::abs(a - b);
    long long count = 0;

    // Greedy approach for denominations 5, 2, 1
    // This works because 5 = 2*2 + 1, and 2 = 1*1 + 1.
    // Any remainder after taking 5s can be optimally handled by 2s and 1s.
    // For example, if diff % 5 is 1, 2, 3, 4:
    // 1: one 1
    // 2: one 2
    // 3: one 2, one 1
    // 4: two 2s
    // This is always optimal.

    count += diff / 5;
    diff %= 5;

    if (diff == 4) {
        // 4 can be made by two 2s (2 presses)
        // or one 5 and one 1 (2 presses)
        // The greedy choice of two 2s is optimal.
        count += 2; // two 2s
    } else if (diff == 3) {
        // 3 can be made by one 2 and one 1 (2 presses)
        count += 2; // one 2, one 1
    } else if (diff == 2) {
        // 2 can be made by one 2 (1 press)
        count += 1; // one 2
    } else if (diff == 1) {
        // 1 can be made by one 1 (1 press)
        count += 1; // one 1
    }
    // If diff is 0, nothing to add.

    return count;
}

