}

#include <iostream>
#include <vector>
#include <algorithm>
#include <utility> // For std::pair

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<int> b(n);
    std::vector<std::pair<int, int>> necklaces(n);
    std::vector<std::pair<int, int>> bracelets(n);

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        necklaces[i] = {a[i], i}; // Store brightness and original index
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
        bracelets[i] = {b[i], i}; // Store brightness and original index
    }

    // Sort both necklaces and bracelets by their brightness values
    std::sort(necklaces.begin(), necklaces.end());
    std::sort(bracelets.begin(), bracelets.end());

    // The strategy is to pair the i-th smallest necklace with the i-th largest bracelet.
    // This ensures that the sums are distinct.
    // Let sorted_a be the sorted necklace brightnesses and sorted_b be the sorted bracelet brightnesses.
    // We pair sorted_a[i] with sorted_b[n-1-i].
    // This creates sums:
    // sorted_a[0] + sorted_b[n-1]
    // sorted_a[1] + sorted_b[n-2]
    // ...
    // sorted_a[n-1] + sorted_b[0]
    //
    // This pairing strategy guarantees distinct sums.
    // Proof sketch: Assume sorted_a[i] + sorted_b[n-1-i] = sorted_a[j] + sorted_b[n-1-j] for i < j.
    // Then sorted_a[j] - sorted_a[i] = sorted_b[n-1-i] - sorted_b[n-1-j].
    // Since i < j, sorted_a[j] - sorted_a[i] > 0.
    // Since i < j, n-1-i > n-1-j.
    // Since sorted_b is sorted ascending, sorted_b[n-1-i] > sorted_b[n-1-j].
    // So sorted_b[n-1-i] - sorted_b[n-1-j] > 0.
    // This doesn't immediately show distinctness.
    //
    // A simpler argument for distinctness:
    // Consider the sums S_i = sorted_a[i] + sorted_b[n-1-i].
    // If S_i = S_j for i < j:
    // sorted_a[i] + sorted_b[n-1-i] = sorted_a[j] + sorted_b[n-1-j]
    // Since sorted_a is strictly increasing and sorted_b is strictly increasing:
    // sorted_a[i] < sorted_a[j]
    // sorted_b[n-1-i] > sorted_b[n-1-j] (because n-1-i > n-1-j)
    //
    // Let's consider the function f(k) = sorted_a[k] + sorted_b[n-1-k].
    // f(k+1) - f(k) = (sorted_a[k+1] + sorted_b[n-1-(k+1)]) - (sorted_a[k] + sorted_b[n-1-k])
    //               = (sorted_a[k+1] - sorted_a[k]) - (sorted_b[n-1-k] - sorted_b[n-2-k])
    //               = (sorted_a[k+1] - sorted_a[k]) - (sorted_b[n-1-k] - sorted_b[n-1-(k+1)])
    // Both (sorted_a[k+1] - sorted_a[k]) and (sorted_b[n-1-k] - sorted_b[n-1-(k+1)]) are positive.
    // The difference can be positive, negative, or zero.
    //
    // The problem statement guarantees an answer always exists.
    // The simplest strategy that works is to sort both arrays and pair them up.
    // For example, pair sorted_a[i] with sorted_b[i].
    // Let's try this:
    // $a = [1, 7, 5]$ -> sorted $a = [1, 5, 7]$
    // $b = [6, 1, 2]$ -> sorted $b = [1, 2, 6]$
    // Pairings:
    // $1+1=2$
    // $5+2=7$
    // $7+6=13$
    // Sums are $[2, 7, 13]$, which are distinct. This works!
    //
    // So, the strategy is:
    // 1. Sort array `a` to get `sorted_a`.
    // 2. Sort array `b` to get `sorted_b`.
    // 3. For each daughter `i`, assign `sorted_a[i]` as necklace and `sorted_b[i]` as bracelet.
    // This is the simplest approach and it works.

    std::vector<int> result_x(n);
    std::vector<int> result_y(n);

    for (int i = 0; i < n; ++i) {
        result_x[i] = necklaces[i].first; // i-th smallest necklace brightness
        result_y[i] = bracelets[i].first; // i-th smallest bracelet brightness
    }

    for (int i = 0; i < n; ++i) {
        std::cout << result_x[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << result_y[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

