    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    int max_a1 = a[0]; // Initial haybales in pile 1

    // Iterate through piles from 2 to n (index 1 to n-1)
    for (int i = 1; i < n; ++i) {
        int pile_idx = i; // 0-indexed pile index
        int haybales_in_pile = a[pile_idx];
        int days_to_move_one = pile_idx; // Cost to move one haybale from pile_idx+1 to pile 1

        if (days_to_move_one == 0) { // This should only happen for pile 1 itself, which is not in this loop
            continue;
        }

        // Calculate how many haybales can be moved from this pile
        // given the remaining days.
        int haybales_to_move_from_this_pile = 0;
        if (d >= days_to_move_one) {
            // We have enough days to move at least one haybale from this pile.
            // We can move at most 'haybales_in_pile' haybales.
            // The total days spent would be 'num_to_move * days_to_move_one'.
            // This must be <= d.
            haybales_to_move_from_this_pile = std::min(haybales_in_pile, d / days_to_move_one);
        }

        max_a1 += haybales_to_move_from_this_pile;
        d -= haybales_to_move_from_this_pile * days_to_move_one;

        if (d <= 0) {
            break; // No more days left
        }
    }

    std::cout << max_a1 << std::endl;
}

