    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n >= 2, we can construct a number.
        // The strategy is to use '2' as the first digit,
        // and '3' for all subsequent digits, except the last one.
        // The last digit will be '9'.
        // This forms a number like 233...39.
        //
        // Let's check divisibility:
        // 1. Divisibility by 2: The number ends in 9 (odd), so it's not divisible by 2.
        // 2. Divisibility by 3: The sum of digits is 2 + (n-2)*3 + 9.
        //    Sum = 2 + 3n - 6 + 9 = 3n + 5.
        //    For the number to be divisible by 3, 3n + 5 must be divisible by 3.
        //    This means 5 must be divisible by 3, which is false.
        //    So, the number is not divisible by 3.
        // 3. Divisibility by 9: Since the number is not divisible by 3, it cannot be divisible by 9.
        //
        // All digits are 2, 3, 9. None of them are 0.
        // The number has n digits.
        // This construction works for n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 2; ++i) {
            std::cout << '3';
        }
        std::cout << '9' << std::endl;
    }
}

