#include <vector>
#include <algorithm> // For std::min

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        if (n <= 1) {
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        int min_suffix_price = a[n - 1]; // Minimum price from current position to the end

        // Iterate from right to left, starting from the second to last element
        // a[n-1] can never be a bad price because there are no days after it.
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix_price) {
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_suffix_price, it means a[i] is
                // the new minimum for the suffix ending at i.
                min_suffix_price = a[i];
            }
        }
        std::cout << bad_prices_count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any p[i] is n-1. If so, it should be n.
    // This happens if the original p[i] was n.
    // In that case, max_{j!=i} min(p[i], p[j]) = max_{j!=i} p[j] = n-1.
    // If no p[i] is n-1, it means the largest value in the permutation (n)
    // was not assigned to any p[i] by the max_val_in_row logic.
    // This implies that the actual value n was never the maximum in any row,
    // which means it was never p[i] for any i.
    // This can only happen if n is not present in the permutation, which is
    // impossible as it's a permutation of 1 to n.
    // So, there must be at least one p[i] that should be n.
    // The logic max_{j!=i} min(p[i], p[j]) correctly identifies p[i]
    // unless p[i] is the largest element (n).
    // If p[i] is n, then max_{j!=i} min(n, p[j]) = max_{j!=i} p[j] = n-1.
    // So, if any p[i] is n-1, it should be n.
    // If all p[i] are less than n-1, then the largest value in the permutation
    // (n) must have been assigned to some p[i] by the max_val_in_row logic.
    // This means that the largest value in the permutation (n) was not
    // correctly identified as n, but rather as n-1.
    // So, we need to find if n is missing from the set of values {p[0], ..., p[n-1]}.
    // If it is, then one of the values that is n-1 should be n.
    // Since the problem guarantees a solution, there will be exactly one such case.

    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n is not found, it means the actual value n was represented as n-1
        // in the `p` array by our logic.
        // We need to find one such n-1 and change it to n.
        // Since there's a guaranteed solution, there will be exactly one such case.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

