            // So `stairs_n` will not exceed `1.5 * 10^9`.
            // `2 * stairs_n + 1` will not exceed `3 * 10^9`.
            // `stairs_n + 1` will not exceed `1.5 * 10^9`.
            // The product `(2 * stairs_n + 1) * (stairs_n + 1)` will not exceed `(3 * 10^9) * (1.5 * 10^9) = 4.5 * 10^18`.
            // This fits in `long long`. So no overflow check is strictly needed for the intermediate products.

            stairs_n = 2 * stairs_n + 1;
            cost_n = stairs_n * (stairs_n + 1) / 2;
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the triangle from the apex down to the i-th cut
        // should be i times the area of a single piece.
        // Area_i = i * (Total_Area / n)
        // Total_Area = h/2
        // Area_i = i * (h / (2n))
        // Also, Area_i = x_i^2 / (2h)
        // So, x_i^2 / (2h) = i * h / (2n)
        // x_i^2 = i * h^2 / n
        // x_i = sqrt(i * h^2 / n)
        // x_i = h * sqrt(i / n)
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest difference we want to generate is k.
                       // This means we need numbers up to k+1 to generate difference k.
                       // For example, to get difference k, we can use 1 and k+1.

    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
    }

    // After generating k distinct differences (1 to k),
    // the remaining elements should be filled in increasing order
    // to ensure no new distinct differences are introduced.
    // The last number used was either 'left-1' or 'right+1'.
    // The next number to use is 'left' if 'left' is the smaller unused number.
    // The numbers remaining are 'left', 'left+1', ..., 'right'.
    // Since we want to avoid new differences, we just append them in increasing order.
    // The current 'left' is the smallest unused number.
    // The current 'right' is the largest unused number.
    // The numbers used so far are 1, 2, ..., left-1 and right+1, ..., k+1.
    // The remaining numbers are left, left+1, ..., right.
    // We should append them in increasing order to minimize new differences.
    // The last element placed was p[k].
    // The next element p[k+1] should be 'left' (which is the smallest available number).
    // This will create a difference |p[k] - left|.
    // If p[k] was 'left-1', then |(left-1) - left| = 1.
    // If p[k] was 'right+1', then |(right+1) - left|. This could be large.
    // However, the problem statement implies that we only need k distinct differences.
    // The strategy of alternating between smallest and largest available numbers
    // for the first k+1 elements (p[0] to p[k]) guarantees differences 1 to k.
    // For example, if k=2, n=3:
    // p[0] = 1 (left=2)
    // p[1] = 3 (right=2)
    // p[2] = 2 (left=3)
    // Permutation: 1 3 2. Differences: |1-3|=2, |3-2|=1. Distinct: {1,2}. Correct.
    //
    // If k=2, n=5:
    // p[0] = 1 (left=2)
    // p[1] = 3 (right=2)
    // p[2] = 2 (left=3)
    // Permutation so far: 1 3 2.
    // Remaining numbers to place: 4, 5.
    // The smallest available number is 'left' which is 3.
    // But we have already used 1, 2, 3.
    // The numbers used are 1, 2, ..., left-1 and right+1, ..., k+1.
    // The numbers available for the rest of the permutation are (k+1)+1, ..., n.
    // So, the next number to place is k+2.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // Fill remaining elements in increasing order
                      // starting from the next available number after k+1.
                      // The numbers 1 to k+1 have been used in p[0]...p[k].
                      // So the next number is k+2.
                      // p[k+1] = k+2, p[k+2] = k+3, ..., p[n-1] = n.
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

