int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long count = n / m;

        if (count == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // The last digits of m, 2m, 3m, ... form a cycle.
        // The cycle length is at most 10, because (k*m)%10 depends on (k%10) and (m%10).
        // More precisely, (k*m)%10 is periodic with period 10.
        // For example, (1*m)%10, (2*m)%10, ..., (10*m)%10, (11*m)%10 = (1*m)%10.
        // So we can precompute the sum of last digits for one full cycle (10 terms).

        std::vector<long long> cycle_last_digits(10);
        long long sum_of_cycle = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_last_digits[i - 1] = (static_cast<long long>(i) * m) % 10;
            sum_of_cycle += cycle_last_digits[i - 1];
        }

        // Number of full cycles of 10 terms
        long long num_full_cycles = count / 10;
        long long remaining_terms = count % 10;

        long long total_sum = num_full_cycles * sum_of_cycle;

        // Add sum for remaining terms
        for (int i = 0; i < remaining_terms; ++i) {
            total_sum += cycle_last_digits[i];
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

