int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            double discriminant = d * d - 4.0 * d;
            // Since d >= 4, discriminant >= 0, so sqrt is always real.
            double sqrt_discriminant = std::sqrt(discriminant);

            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // Both a and b must be non-negative.
            // Since d >= 4, d + sqrt_discriminant is positive. So a1 is positive.
            // For b1, we need d - sqrt_discriminant >= 0.
            // d >= sqrt(d^2 - 4d)
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true for d >= 0.
            // So both a1 and b1 are non-negative.

            std::cout << std::fixed << std::setprecision(9) << "Y " << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2;

    // Cost to make the median element equal to s
    operations += std::abs(a[mid_idx] - s);

    // Adjust elements to the left of the median
    // These elements must be <= s
    for (int i = 0; i < mid_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Adjust elements to the right of the median
    // These elements must be >= s
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int left_ptr = 0; // Pointer for elements to be "beaten" (from sorted_a)
    int right_ptr = 0; // Pointer for elements to "beat" (from sorted_a)

    while (right_ptr < n) {
        // We are trying to find an element a[right_ptr]
        // that is strictly greater than a[left_ptr].
        // If a[right_ptr] > a[left_ptr], we can form a pair.
        // This means we can place a[right_ptr] at a position
        // where a[left_ptr] originally stood, and satisfy the condition.
        // Both pointers then advance, as a[left_ptr] is "beaten"
        // and a[right_ptr] is "used".
        if (a[right_ptr] > a[left_ptr]) {
            count++;
            left_ptr++;
            right_ptr++;
        } else {
            // If a[right_ptr] <= a[left_ptr], a[right_ptr] cannot beat a[left_ptr].
            // We need a larger element to beat a[left_ptr].
            // So, we try the next available element from the sorted array
            // to be the "beating" element.
            // a[left_ptr] remains to be beaten.
            right_ptr++;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

