// Function to determine if Box 1 can be the special box
bool can_be_box1(long long A, long long B, long long C, long long D) {
    // Box 1: value <= -1
    // Requires a negative final product with magnitude >= 1.

    // Case 1: Final product is negative.
    // This means an odd number of negative values were multiplied.
    // The initial count of negative values is A + B.
    // If (A + B) is odd, the final product is negative.
    // If (A + B) is even, the final product is positive.

    // Case 2: Final product has magnitude >= 1.
    // This requires careful analysis of magnitudes.
    // Let's count the number of values with magnitude >= 1 (from Box 1 and Box 4)
    // and values with magnitude < 1 (from Box 2 and Box 3).
    // Let N_ge1 = A + D (count of values with magnitude >= 1)
    // Let N_lt1 = B + C (count of values with magnitude < 1)

    // If N_ge1 == 0, then all initial values have magnitude < 1.
    // The product of any number of values all with magnitude < 1 will always have magnitude < 1.
    // So, if A+D == 0, the final product cannot be in Box 1 or Box 4.
    // It must be in Box 2 or Box 3.
    if (A + D == 0) {
        return false;
    }

    // If A+D > 0, it's possible to get magnitude >= 1.
    // We need an odd number of negative values for a negative result.
    if ((A + B) % 2 == 1) { // Final product is negative
        // If A+D > 0, we can always arrange multiplications to keep magnitude >= 1
        // or make it >= 1 if we have enough values.
        // The only way to guarantee magnitude < 1 is if all values are < 1.
        // Since A+D > 0, we have at least one value with magnitude >= 1.
        // We can always ensure the final product has magnitude >= 1.
        // For example, multiply all values from B and C together first.
        // This results in a value with magnitude < 1.
        // Then multiply this with a value from A or D.
        // If we have A+D >= 1, we can always make the final product magnitude >= 1.
        // The only exception is if we have exactly one value with magnitude >= 1 (A+D=1)
        // and many values with magnitude < 1 (B+C > 0).
        // In this case, if we multiply the single large value by many small values,
        // the magnitude might drop below 1.
        // However, the problem states "you do not know their fun values".
        // This implies we can pick specific values.
        // For example, if A=1, B=1, C=1, D=0.
        // A: {-2}, B: {-0.5}, C: {0.5}
        // (-2) * (-0.5) = 1 (Box 4)
        // 1 * 0.5 = 0.5 (Box 3)
        // This sequence leads to Box 3.
        // But we can also do:
        // (-0.5) * 0.5 = -0.25 (Box 2)
        // (-2) * (-0.25) = 0.5 (Box 3)
        // Still Box 3.

        // The crucial insight is that if A+D > 0, we can always pick values such that
        // the final product has magnitude >= 1.
        // For example, if we have one value X with |X| >= 1, and many values Y_i with |Y_i| < 1.
        // We can choose Y_i values very close to 1 or -1.
        // E.g., X = -2, Y_1 = -0.9, Y_2 = -0.9.
        // (-2) * (-0.9) = 1.8 (Box 4)
        // 1.8 * (-0.9) = -1.62 (Box 1)
        // So, if A+D > 0, we can always achieve magnitude >= 1.
        return true;
    }
    return false;
}

// Function to determine if Box 2 can be the special box
bool can_be_box2(long long A, long long B, long long C, long long D) {
    // Box 2: -1 < value < 0
    // Requires a negative final product with magnitude < 1.

    // Case 1: Final product is negative.
    // This means an odd number of negative values were multiplied.
    // If (A + B) is odd, the final product is negative.
    // If (A + B) is even, the final product is positive.
    if ((A + B) % 2 == 0) {
        return false; // Must be negative
    }

    // Case 2: Final product has magnitude < 1.
    // This is possible if A+D == 0 (all initial values have magnitude < 1).
    // Or, if A+D > 0, we can choose values such that the magnitude drops below 1.
    // For example, if we have one value X with |X| >= 1, and many values Y_i with |Y_i| < 1.
    // We can choose Y_i values very close to 0.
    // E.g., X = -2, Y_1 = -0.1, Y_2 = -0.1.
    // (-2) * (-0.1) = 0.2 (Box 3)
    // 0.2 * (-0.1) = -0.02 (Box 2)
    // So, if A+D > 0, we can achieve magnitude < 1.

    // The only case where it's impossible to get magnitude < 1 is if there's only one toy
    // and that toy is in Box 1 or Box 4.
    // If A+B+C+D == 1:
    if (A + B + C + D == 1) {
        if (B == 1) return true; // If the single toy is in Box 2, it's the super toy.
        return false; // Otherwise, it's not in Box 2.
    }

    // If A+B+C+D > 1:
    // We need (A+B) to be odd.
    // We can always achieve magnitude < 1.
    // If A+D == 0, then all values are already < 1, so the product will be < 1.
    // If A+D > 0, we can pick values from B and C to be very small (e.g., 0.001).
    // Then multiply all A, B, C, D values. The final product will be very small.
    // So, if (A+B) is odd, Box 2 is always possible.
    return true;
}

// Function to determine if Box 3 can be the special box
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // Box 3: 0 < value < 1
    // Requires a positive final product with magnitude < 1.

    // Case 1: Final product is positive.
    // This means an even number of negative values were multiplied.
    // If (A + B) is even, the final product is positive.
    // If (A + B) is odd, the final product is negative.
    if ((A + B) % 2 == 1) {
        return false; // Must be positive
    }

    // Case 2: Final product has magnitude < 1.
    // Similar to Box 2, we can always achieve magnitude < 1 if A+B+C+D > 1.
    // If A+B+C+D == 1:
    if (A + B + C + D == 1) {
        if (C == 1) return true; // If the single toy is in Box 3, it's the super toy.
        return false; // Otherwise, it's not in Box 3.
    }

    // If A+B+C+D > 1:
    // We need (A+B) to be even.
    // We can always achieve magnitude < 1.
    // If A+D == 0, then all values are already < 1, so the product will be < 1.
    // If A+D > 0, we can pick values from B and C to be very small (e.g., 0.001).
    // Then multiply all A, B, C, D values. The final product will be very small.
    // So, if (A+B) is even, Box 3 is always possible.
    return true;
}

// Function to determine if Box 4 can be the special box
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // Box 4: value >= 1
    // Requires a positive final product with magnitude >= 1.

    // Case 1: Final product is positive.
    // This means an even number of negative values were multiplied.
    // If (A + B) is even, the final product is positive.
    // If (A + B) is odd, the final product is negative.
    if ((A + B) % 2 == 1) {
        return false; // Must be positive
    }

    // Case 2: Final product has magnitude >= 1.
    // This requires A+D > 0. If A+D == 0, all initial values have magnitude < 1,
    // so the product will always have magnitude < 1.
    if (A + D == 0) {
        return false;
    }

    // If A+D > 0, we can always arrange multiplications to keep magnitude >= 1.
    // For example, multiply all values from B and C together first.
    // This results in a value with magnitude < 1.
    // Then multiply this with a value from A or D.
    // If we have A+D >= 1, we can always make the final product magnitude >= 1.
    // We can choose values from A and D to be very large (e.g., 1000).
    // We can choose values from B and C to be very close to 1 (e.g., 0.99).
    // Then the product will be large.
    // So, if (A+B) is even and A+D > 0, Box 4 is always possible.
    return true;
}

