struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    std::sort(a_elements.begin(), a_elements.end(), compareElements);
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    std::vector<long long> result_a(m);

    // The problem statement guarantees A_i >= B_j for all i, j.
    // This implies that A_i >= B_j for all i, j after sorting as well,
    // if we consider the original values.
    // However, for the pairing, we need to match sorted A with sorted B.
    // The optimal strategy is to pair the largest A_i with the largest B_j,
    // the second largest A_i with the second largest B_j, and so on.
    // This means sorting A in ascending order and B in ascending order,
    // then pairing a_elements[i] with b_elements[i] (after sorting).
    // The value of F(n, k) is (n+1)/(k+1).
    // To maximize sum((A_i+1)/(B_i+1)), we want to pair large A_i with small B_i.
    // So, sort A in descending order and B in ascending order.
    // Or, sort A in ascending order and B in descending order.
    // Let's re-evaluate the pairing.
    // We want to maximize sum (A'_i + 1) / (B_i + 1).
    // Let x_i = A'_i + 1 and y_i = B_i + 1. We want to maximize sum x_i / y_i.
    // This is a rearrangement inequality type problem.
    // To maximize sum(x_i / y_i), we should pair largest x_i with smallest y_i,
    // second largest x_i with second smallest y_i, etc.
    // So, sort A_i in descending order and B_i in ascending order.

    // A_elements is already sorted ascending.
    // We need to sort B_elements in descending order for pairing.
    // Or, equivalently, iterate A_elements from largest to smallest,
    // and B_elements from smallest to largest.
    // Since a_elements is sorted ascending, a_elements[m-1] is largest, a_elements[m-2] is second largest, etc.
    // Since b_elements is sorted ascending, b_elements[0] is smallest, b_elements[1] is second smallest, etc.
    // So, we pair a_elements[m-1-i] with b_elements[i].
    // The result should be stored in the original index of b_elements[i].

    for (int i = 0; i < m; ++i) {
        // a_elements[m - 1 - i] is the i-th largest A value (0-indexed)
        // b_elements[i] is the i-th smallest B value (0-indexed)
        // We assign the (m-1-i)-th largest A value to the original position of the i-th smallest B value.
        result_a[b_elements[i].original_index] = a_elements[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

