        std::cout << "Yes\n";
        return;
    }

    // Check if a peak can exist at index k.
    // For the left part (a_1 < ... < a_k), we need a_i >= i-1 for 1 <= i <= k.
    // For the right part (a_k > ... > a_n), we need a_i >= n-i for k <= i <= n.
    // Combining these, for a peak at index k, we need:
    // a_i >= i-1 for 1 <= i <= k
    // a_i >= n-i for k <= i <= n
    // And specifically for a_k, we need a_k >= k-1 AND a_k >= n-k.
    // The condition a_k > a_{k+1} and a_k > a_{k-1} (if they exist)
    // is implicitly handled by the strict inequalities.
    // For example, if a_k = k-1 and a_{k-1} = k-2, then k-1 > k-2 holds.
    // If a_k = n-k and a_{k+1} = n-(k+1), then n-k > n-(k+1) holds.
    // The only problematic case is if k-1 == n-k, which means a_k must be at least this value.
    // But if k-1 == n-k, then a_k must be strictly greater than both a_{k-1} and a_{k+1}.
    // This is not true. The conditions are $b_1 < \ldots < b_k$ and $b_k > \ldots > b_n$.
    // The minimal values are $b_i = i-1$ for $i \le k$ and $b_i = n-i$ for $i \ge k$.
    // For $b_k$, it must be $b_k \ge k-1$ and $b_k \ge n-k$.
    // If we choose $b_k = \max(k-1, n-k)$, then $b_k$ is the smallest possible value for $b_k$.
    // Then $b_{k-1}$ must be $b_k-1$, $b_{k-2}$ must be $b_k-2$, etc.
    // And $b_{k+1}$ must be $b_k-1$, $b_{k+2}$ must be $b_k-2$, etc.
    // This means $b_i = b_k - (k-i)$ for $i < k$ and $b_i = b_k - (i-k)$ for $i > k$.
    // For this to be valid, we need $b_i \ge 0$.
    // For $i < k$, $b_k - (k-i) \ge 0 \implies b_k \ge k-i$. The smallest $k-i$ is $1$ (for $i=k-1$).
    // For $i > k$, $b_k - (i-k) \ge 0 \implies b_k \ge i-k$. The smallest $i-k$ is $1$ (for $i=k+1$).
    // The most restrictive is $b_k \ge k-1$ (for $i=1$) and $b_k \ge n-k$ (for $i=n$).
    // So we need $a_i \ge \min(i-1, n-i)$ for all $i$.
    // This is not quite right.
    // The conditions are:
    // For $i=0 \ldots k-1$: $a_i \ge i$.
    // For $i=k \ldots n-1$: $a_i \ge n-1-i$.
    // We need to find if there exists a $k$ such that $a_i \ge i$ for $i < k$ and $a_i \ge n-1-i$ for $i > k$.
    // And $a_k$ must be large enough to be a peak.
    // The crucial observation is that we need to find a $k$ such that $a_i \ge i$ for $i \in [0, k-1]$
    // and $a_i \ge n-1-i$ for $i \in [k+1, n-1]$.
    // For $a_k$, we need $a_k \ge k-1$ (if $k>0$) and $a_k \ge n-k$ (if $k<n-1$).
    // The minimum value for $a_k$ is $\max(k-1, n-k)$.
    // If $a_k$ is large enough, we can always make it a peak.
    // The actual conditions are:
    // $a_0 \ge 0$
    // $a_1 \ge 1$
    // ...
    // $a_{k-1} \ge k-1$
    // $a_k \ge k$ (this is wrong, $a_k$ can be $k-1$ if $k-1$ is the peak value)
    // $a_k \ge n-1-k$ (this is wrong, $a_k$ can be $n-k$ if $n-k$ is the peak value)

    // Let's re-evaluate the minimum values for a sharpened array.
    // For a peak at index `k` (0-indexed):
    // $b_0 < b_1 < \ldots < b_k$
    // $b_k > b_{k+1} > \ldots > b_{n-1}$
    // The smallest possible values for $b_i$ are:
    // $b_i = i$ for $0 \le i \le k$.
    // $b_i = n-1-i$ for $k \le i \le n-1$.
    // This implies $b_k = k$ and $b_k = n-1-k$. This is only possible if $k = n-1-k$.
    // This is not how it works. The values $i$ and $n-1-i$ are just lower bounds.
    // The actual values are $b_i = b_k - (k-i)$ for $i < k$ and $b_i = b_k - (i-k)$ for $i > k$.
    // And $b_k$ must be chosen such that $b_i \ge 0$ for all $i$.
    // This means $b_k \ge k$ (to make $b_0 \ge 0$) and $b_k \ge n-1-k$ (to make $b_{n-1} \ge 0$).
    // So, we need to be able to set $b_k \ge \max(k, n-1-k)$.
    // And for $i < k$, we need $a_i \ge b_k - (k-i)$.
    // And for $i > k$, we need $a_i \ge b_k - (i-k)$.
    // This is too complex.

    // Simpler approach:
    // For each $i$ from $0$ to $n-1$, we need $a_i \ge i$ to satisfy the increasing part up to $a_i$.
    // Let $L_i = i$. If $a_i < L_i$, we cannot make $a_i$ part of an increasing sequence $0, 1, \ldots, L_i$.
    // For each $i$ from $0$ to $n-1$, we need $a_i \ge n-1-i$ to satisfy the decreasing part from $a_i$ to $a_{n-1}$.
    // Let $R_i = n-1-i$. If $a_i < R_i$, we cannot make $a_i$ part of a decreasing sequence $R_i, R_i-1, \ldots, 0$.

    // We need to find if there exists a peak $k$ (0-indexed) such that:
    // 1. For all $i < k$, $a_i \ge i$. (Can form $0, 1, \ldots, k-1$)
    // 2. For all $i > k$, $a_i \ge n-1-i$. (Can form $n-1-k, n-2-k, \ldots, 0$)
    // 3. For $a_k$, we need $a_k \ge k$ AND $a_k \ge n-1-k$.
    // This is because $a_k$ must be at least $k$ to allow $a_0, \ldots, a_{k-1}$ to be $0, \ldots, k-1$.
    // And $a_k$ must be at least $n-1-k$ to allow $a_{k+1}, \ldots, a_{n-1}$ to be $n-2-k, \ldots, 0$.
    // So, for a peak at index $k$, we need $a_k \ge \max(k, n-1-k)$.
    // And for all other $i$, $a_i \ge \min(i, n-1-i)$. This is not quite right.

    // Let's define two arrays:
    // `pref_min_val[i]` = minimum value $a_i$ must have if it's part of the increasing prefix $0, 1, \ldots, i$.
    // `suff_min_val[i]` = minimum value $a_i$ must have if it's part of the decreasing suffix $i, i-1, \ldots, 0$.
    // `pref_min_val[i] = i`
    // `suff_min_val[i] = n-1-i`

    // We need to find if there exists an index $k$ (0-indexed) such that:
    // $a_i \ge i$ for all $0 \le i \le k$.
    // $a_i \ge n-1-i$ for all $k \le i \le n-1$.
    // If such a $k$ exists, then we can construct a sharpened array.
    // For example, set $b_i = i$ for $i \le k$ and $b_i = n-1-i$ for $i \ge k$.
    // Then $b_k = k$ and $b_k = n-1-k$. This is only possible if $k = n-1-k$.
    // This is the core issue. The peak value $b_k$ must be strictly greater than $b_{k-1}$ and $b_{k+1}$.
    // If $b_k = k$ and $b_{k-1} = k-1$, then $b_k > b_{k-1}$ holds.
    // If $b_k = n-1-k$ and $b_{k+1} = n-1-(k+1)$, then $b_k > b_{k+1}$ holds.
    // So, we need $a_i \ge i$ for $i \le k$ and $a_i \ge n-1-i$ for $i \ge k$.
    // This means for $a_k$, we need $a_k \ge k$ AND $a_k \ge n-1-k$.
    // So $a_k \ge \max(k, n-1-k)$.
    // If this condition holds for some $k$, then we can construct the array:
    // $b_i = i$ for $i < k$.
    // $b_i = n-1-i$ for $i > k$.
    // $b_k = \max(k, n-1-k)$.
    // This array $b$ is sharpened.
    // We need to check if $a_i \ge b_i$ for all $i$.
    // For $i < k$: $a_i \ge i$.
    // For $i > k$: $a_i \ge n-1-i$.
    // For $i = k$: $a_k \ge \max(k, n-1-k)$.

    // So, the condition is:
    // There exists $k \in [0, n-1]$ such that:
    // For all $i \in [0, k]$, $a_i \ge i$.
    // For all $i \in [k, n-1]$, $a_i \ge n-1-i$.

    // Let's check this condition.
    // We can iterate $k$ from $0$ to $n-1$.
    // For each $k$, check the two conditions.
    // This would be $O(N^2)$, too slow for $N=3 \cdot 10^5$.

    // We can optimize this.
    // Find the maximum $L$ such that $a_i \ge i$ for all $i \in [0, L-1]$.
    // If $a_0 < 0$, then $L=0$. Otherwise, $L$ is the first index where $a_L < L$.
    // So $L$ is the length of the longest prefix $a_0, \ldots, a_{L-1}$ that can be $0, \ldots, L-1$.
    // Find the maximum $R$ such that $a_i \ge n-1-i$ for all $i \in [n-R, n-1]$.
    // If $a_{n-1} < 0$, then $R=0$. Otherwise, $R$ is the first index from the right where $a_{n-1-R} < R$.
    // So $R$ is the length of the longest suffix $a_{n-R}, \ldots, a_{n-1}$ that can be $R-1, \ldots, 0$.

    // Let's define `left_ok[i]` as true if $a_0, \ldots, a_i$ can be $0, \ldots, i$.
    // `left_ok[i] = (a_i >= i)` and `left_ok[i-1]` (if $i>0$).
    // This is equivalent to `left_ok[i] = (a_j >= j for all j <= i)`.
    // We can compute the maximum `i` for which `left_ok[i]` is true. Let this be `max_left_idx`.
    // `max_left_idx` is the largest `i` such that $a_j \ge j$ for all $j \le i$.
    // If $a_0 < 0$, then `max_left_idx = -1`.

    // Similarly, define `right_ok[i]` as true if $a_i, \ldots, a_{n-1}$ can be $n-1-i, \ldots, 0$.
    // `right_ok[i] = (a_i >= n-1-i)` and `right_ok[i+1]` (if $i<n-1$).
    // This is equivalent to `right_ok[i] = (a_j >= n-1-j for all j >= i)`.
    // We can compute the minimum `i` for which `right_ok[i]` is true. Let this be `min_right_idx`.
    // `min_right_idx` is the smallest `i` such that $a_j \ge n-1-j$ for all $j \ge i$.
    // If $a_{n-1} < 0$, then `min_right_idx = n`.

    // We need to find if there exists a $k$ such that:
    // $a_j \ge j$ for all $j \le k$ (i.e., $k \le \text{max_left_idx}$)
    // $a_j \ge n-1-j$ for all $j \ge k$ (i.e., $k \ge \text{min_right_idx}$)
    // So we need to find if there is any $k$ such that $\text{min_right_idx} \le k \le \text{max_left_idx}$.
    // This means we need to check if $\text{min_right_idx} \le \text{max_left_idx}$.

    int max_left_idx = -1;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            max_left_idx = i;
        } else {
            break;
        }
    }

    int min_right_idx = n;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            min_right_idx = i;
        } else {
            break;
        }
    }

    if (min_right_idx <= max_left_idx) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

