void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();

    int countR = 0;
    int countP = 0;
    int countS = 0;

    for (char ch : s) {
        if (ch == 'R') {
            countR++;
        } else if (ch == 'P') {
            countP++;
        } else { // ch == 'S'
            countS++;
        }
    }

    char dominant_bot_move;
    if (countR >= countP && countR >= countS) {
        dominant_bot_move = 'R';
    } else if (countP >= countR && countP >= countS) {
        dominant_bot_move = 'P';
    } else { // countS is maximum
        dominant_bot_move = 'S';
    }

    char our_winning_move;
    if (dominant_bot_move == 'R') {
        our_winning_move = 'P'; // Paper beats Rock
    } else if (dominant_bot_move == 'P') {
        our_winning_move = 'S'; // Scissors beats Paper
    } else { // dominant_bot_move == 'S'
        our_winning_move = 'R'; // Rock beats Scissors
    }

    for (int i = 0; i < n; ++i) {
        std::cout << our_winning_move;
    }
    std::cout << std::endl;
}

