// Function to check if a subarray is a permutation of its length
// `arr` is the full array
// `start_idx` is the 0-based starting index of the subarray
// `len` is the length of the subarray
// Returns true if arr[start_idx...start_idx+len-1] is a permutation of 1 to len
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len <= 0) { // A permutation must have positive length
        return false;
    }
    if (start_idx + len > arr.size()) { // Subarray out of bounds
        return false;
    }

    std::vector<bool> seen(len + 1, false); // seen[0] is unused, indices 1 to len
    int max_val = 0;

    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > len || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }

    // All numbers from 1 to len must be present exactly once.
    // If max_val is not equal to len, it means some number is missing.
    // This check is redundant if we iterate 1 to len and check seen[i]
    // but max_val check is faster if a large number is missing.
    // A more robust check is to ensure all `seen[1...len]` are true.
    // However, the current logic (val > len || seen[val]) and max_val check
    // combined with the loop structure ensures this.
    // If all numbers are within [1, len] and no duplicates, and there are `len` numbers,
    // then they must be 1 to len.
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    int max_val_overall = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] > max_val_overall) {
            max_val_overall = a[i];
        }
    }

    std::vector<std::pair<int, int>> results;

    // Precompute prefix maximums
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i-1], a[i]);
    }

    // Precompute suffix maximums
    std::vector<int> suffix_max(n);
    suffix_max[n-1] = a[n-1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i+1], a[i]);
    }

    // Precompute prefix counts
    std::vector<int> prefix_counts(n + 1, 0); // counts[0] unused
    std::vector<bool> prefix_seen(n + 1, false); // seen[0] unused
    int current_prefix_distinct = 0;
    int current_prefix_max = 0;

    // Precompute suffix counts
    std::vector<int> suffix_counts(n + 1, 0); // counts[0] unused
    std::vector<bool> suffix_seen(n + 1, false); // seen[0] unused
    int current_suffix_distinct = 0;
    int current_suffix_max = 0;

    // Iterate through all possible split points l1
    // l1 goes from 1 to n-1
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check if first part is a permutation of length l1
        // This check can be optimized using prefix sums/counts
        // A segment [0...l1-1] is a permutation of length l1 if:
        // 1. All elements are distinct.
        // 2. All elements are <= l1.
        // 3. The maximum element is l1.
        // 4. There are l1 elements. (Guaranteed by loop)

        // Check if the first l1 elements form a permutation of length l1
        bool p1_is_perm = false;
        if (prefix_max[l1-1] == l1) { // Max element must be l1
            // Check for distinctness and range [1, l1]
            // This requires iterating or using a frequency array/set.
            // We can use the precomputed `prefix_seen` and `current_prefix_distinct`
            // to check this efficiently.
            // The `is_permutation` function already does this.
            // For optimization, we can build `prefix_is_perm` array.
            // This is the core optimization.

            // To check if a prefix of length `l1` is a permutation:
            // 1. Max value in prefix must be `l1`.
            // 2. All values must be distinct.
            // 3. All values must be within `[1, l1]`.
            // We can maintain a `seen` array and `distinct_count` for prefixes.
            // Let's use a more direct approach for `is_permutation` for now,
            // and then optimize if TLE.
            // The `is_permutation` function is O(len), so total O(N^2) without optimization.
            // With N=200,000, N^2 is too slow.
            // We need O(N) or O(N log N).

            // Let's precompute `is_prefix_perm[i]` and `is_suffix_perm[i]`
            // `is_prefix_perm[i]` means `a[0...i]` is a permutation of length `i+1`.
            // `is_suffix_perm[i]` means `a[i...n-1]` is a permutation of length `n-i`.
        }
    }

    // Optimized approach: Precompute `is_prefix_perm` and `is_suffix_perm`
    std::vector<bool> is_prefix_perm(n + 1, false); // is_prefix_perm[k] means a[0...k-1] is perm of length k
    std::vector<bool> is_suffix_perm(n + 1, false); // is_suffix_perm[k] means a[n-k...n-1] is perm of length k

    std::vector<bool> seen_p(n + 1, false);
    int distinct_count_p = 0;
    int max_val_p = 0;
    for (int k = 1; k <= n; ++k) { // k is length
        int val = a[k-1];
        if (val > k || seen_p[val]) { // If val is too large for current length k, or duplicate
            // This prefix cannot be a permutation, nor can any longer prefix
            // unless the max_val_p check is done carefully.
            // If val > k, it cannot be a permutation of length k.
            // If seen_p[val], it's a duplicate.
            // In both cases, this prefix is not a permutation.
            // And any longer prefix will also have this issue or worse.
            // So we can break or just let is_prefix_perm[k] remain false.
            // However, max_val_p might still be k-1, so we need to be careful.
            // The condition for a prefix of length k to be a permutation is:
            // 1. All elements a[0...k-1] are distinct.
            // 2. All elements a[0...k-1] are <= k.
            // 3. The maximum element in a[0...k-1] is k.
            // 4. There are k elements.
            // We can track distinct_count_p and max_val_p.
            // If val is a duplicate or val > k, then this prefix is not a permutation.
            // And any subsequent prefix will also not be a permutation.
            // So we can stop.
            break; // Optimization: if a prefix fails, all longer prefixes fail.
        }
        seen_p[val] = true;
        distinct_count_p++;
        if (val > max_val_p) {
            max_val_p = val;
        }

        if (distinct_count_p == k && max_val_p == k) {
            is_prefix_perm[k] = true;
        }
    }

    std::fill(seen_p.begin(), seen_p.end(), false); // Reset for suffix
    distinct_count_p = 0;
    max_val_p = 0;
    for (int k = 1; k <= n; ++k) { // k is length
        int val = a[n-k]; // Element from the end
        if (val > k || seen_p[val]) {
            break; // Optimization: if a suffix fails, all longer suffixes fail.
        }
        seen_p[val] = true;
        distinct_count_p++;
        if (val > max_val_p) {
            max_val_p = val;
        }

        if (distinct_count_p == k && max_val_p == k) {
            is_suffix_perm[k] = true;
        }
    }

    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

