        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor ^= a;
    }

    // Condition: current_sum = 2 * current_xor
    // If it's already good, append 0 elements.
    if (current_sum == 2 * current_xor) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
        return;
    }

    // We need to append elements. The problem guarantees a solution with at most 3 elements.
    // Let's try to append two elements.
    // We want to find b1, b2 such that:
    // (current_sum + b1 + b2) = 2 * (current_xor ^ b1 ^ b2)

    // A common strategy for these problems is to make the XOR sum equal to the sum.
    // Let's try to make the final XOR sum equal to current_xor.
    // This means we want b1 ^ b2 = 0, so b1 = b2.
    // Let b1 = b2 = X.
    // Then the equation becomes:
    // (current_sum + X + X) = 2 * (current_xor ^ X ^ X)
    // (current_sum + 2X) = 2 * current_xor
    // current_sum + 2X = 2 * current_xor
    // 2X = 2 * current_xor - current_sum
    // X = current_xor - current_sum / 2
    // This requires (2 * current_xor - current_sum) to be non-negative and even.
    // This is not guaranteed.

    // A simpler strategy that always works:
    // Append two elements:
    // 1. current_xor (let's call it X_0)
    // 2. current_sum + current_xor (let's call it S_0 + X_0)
    //
    // Let's verify this.
    // New sum S' = current_sum + X_0 + (S_0 + X_0) = 2 * S_0 + 2 * X_0
    // New XOR X' = current_xor ^ X_0 ^ (S_0 + X_0)
    // Since current_xor ^ X_0 = 0,
    // X' = 0 ^ (S_0 + X_0) = S_0 + X_0
    //
    // We need to check if S' = 2 * X'.
    // Is (2 * S_0 + 2 * X_0) = 2 * (S_0 + X_0)?
    // Yes, it is.
    //
    // So, we can always append two elements: current_xor and (current_sum + current_xor).
    // These values can be large, up to 10^9 * 10^5 + 10^9 ~ 10^14 + 10^9, which fits in long long.
    // The problem states $a_i \le 10^9$, $n \le 10^5$.
    // Max sum $S_0 \approx 10^5 \cdot 10^9 = 10^{14}$.
    // Max XOR $X_0 \approx 2^{30}$ (since $10^9 < 2^{30}$).
    // So $S_0 + X_0$ can be up to $10^{14} + 2^{30}$, which fits in `long long`.

    std::cout << 2 << std::endl;
    std::cout << current_xor << " " << (current_sum + current_xor) << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

