int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long b_count = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % MOD;
        } else { // s[i] == 'a'
            // This 'a' will interact with all 'b's to its right.
            // Each 'b' to its right will cause this 'a' to move past it,
            // generating a new 'b'.
            // The number of steps for this 'a' is equal to the current b_count.
            total_steps = (total_steps + b_count) % MOD;

            // After this 'a' moves past all 'b's to its right,
            // it effectively generates b_count new 'b's to its left.
            // These new 'b's will be available for 'a's further to the left.
            b_count = (b_count * 2) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

