#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <algorithm>

// Function to convert a number to its parity pattern string
// The pattern is always 18 characters long, padded with '0's on the left.
std::string get_parity_pattern(long long n) {
    std::string pattern_str = "";
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern_str += '0';
            } else {
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Pad with leading zeros to make it 18 characters long
    while (pattern_str.length() < 18) {
        pattern_str += '0';
    }
    // The digits were appended from right to left, so they are already in the correct order
    // (rightmost digit of number corresponds to leftmost char in pattern_str)
    // However, the problem statement implies pattern is read from right to left.
    // "parity of the i-th from the right digit in decimal notation matches the i-th from the right digit of the pattern."
    // This means if we have a number 123 and pattern 101,
    // 3 (odd) matches 1 (rightmost of pattern)
    // 2 (even) matches 0 (second from right of pattern)
    // 1 (odd) matches 1 (third from right of pattern)
    // My `pattern_str` is built as "3's parity, 2's parity, 1's parity".
    // So for 123, it would be "101".
    // For 92, it would be "01". Padded to 18: "010000000000000000".
    // The map key should be this string.
    return pattern_str;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each parity pattern string
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            pattern_counts[get_parity_pattern(a)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            pattern_counts[get_parity_pattern(a)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with leading zeros to 18 characters
            // The problem states "if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
            // and "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // This means both the number's pattern and the query pattern should be effectively compared as if they are of max length.
            // My `get_parity_pattern` function already produces a 18-char string.
            // The query pattern `s` needs to be processed similarly.
            // Example: s = "010". This means rightmost is 0, second is 1, third is 0.
            // My `get_parity_pattern` for 92 (01) would be "01...".
            // So the query pattern needs to be reversed and padded.
            // No, the problem says "i-th from the right digit of the pattern".
            // So if s = "010", s[0] is the leftmost, s[2] is the rightmost.
            // The pattern string in the map is built from right to left of the number.
            // So for number 123, pattern is "101".
            // For query "010", it means rightmost digit of number should be even (0), second from right odd (1), third from right even (0).
            // So the query pattern "010" should be matched against "010" (reversed and padded).
            // Let's re-evaluate `get_parity_pattern` and query pattern.
            // `get_parity_pattern(92)`: 2 is even (0), 9 is odd (1). Result: "01". Padded: "01000...".
            // Query `s = "010"`.
            // The problem says: "Integer x matches the pattern s, if the parity of the i-th from the right digit in decimal notation matches the i-th from the right digit of the pattern."
            // This means:
            // x_rightmost_parity == s_rightmost_char
            // x_second_rightmost_parity == s_second_rightmost_char
            // etc.
            // If s = "010", s_rightmost_char is '0', s_second_rightmost_char is '1', s_third_rightmost_char is '0'.
            // My `get_parity_pattern` for 92 is "01" (0 for 2, 1 for 9).
            // To match "010", I need to compare "01" with "010".
            // The pattern string stored in the map is `get_parity_pattern(a)`.
            // For `a=92`, this is "01" (then padded to 18 chars: "01000...").
            // For query `s="010"`, I need to convert this `s` into the same format.
            // `s` is given as "010". This means `s[0]` is the leftmost, `s[2]` is the rightmost.
            // So `s_rightmost_char` is `s[s.length()-1]`.
            // `s_second_rightmost_char` is `s[s.length()-2]`.
            // To match the format of `get_parity_pattern`, I need to reverse `s` and then pad it.
            std::reverse(s.begin(), s.end());
            while (s.length() < 18) {
                s += '0';
            }
            std::cout << pattern_counts[s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let 'i' be the number of items taken from the left (0 <= i <= n)
    // Then 'n - i' items are taken from the right.
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += (prefix_sum[i] - prefix_sum[0]) * l;

        // Energy for items taken from the right
        // The items taken from the right are w[n-j], ..., w[n-1]
        // Their sum is prefix_sum[n] - prefix_sum[n-j]
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add penalty based on the difference in counts
        if (i > j) { // More items from left
            if (i - 1 > j) { // At least two more items from left
                current_energy += (long long)(i - j - 1) * Ql;
            }
        } else if (j > i) { // More items from right
            if (j - 1 > i) { // At least two more items from right
                current_energy += (long long)(j - i - 1) * Qr;
            }
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric> // For std::accumulate with bitwise OR

int main() {
    // Optimize C++ standard streams for competitive programming.
    // This unties cin/cout from C's stdio and disables synchronization,
    // potentially speeding up I/O operations.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Declare a 2D vector to store the matrix b.
    // Using long long for elements to match problem constraints (up to 10^9)
    // and to be safe, although int is sufficient for 10^9.
    std::vector<std::vector<int>> b(n, std::vector<int>(n));

    // Read the matrix b from standard input.
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> b[i][j];
        }
    }

    // Declare a vector to store the restored sequence a.
    std::vector<int> a(n);

    // Iterate through each element a_i that needs to be restored.
    for (int i = 0; i < n; ++i) {
        // Initialize a_i to 0.
        // We will bitwise OR all b_ij (for j != i) into a_i.
        // The property is that a_i = (a_i & a_1) | (a_i & a_2) | ... | (a_i & a_n)
        // where the term (a_i & a_i) is effectively ignored.
        // This simplifies to a_i = OR_{j != i} (a_i & a_j).
        // Since b_ij = a_i & a_j, we have a_i = OR_{j != i} b_ij.
        int current_a_i = 0;

        // Iterate through all columns j for the current row i.
        for (int j = 0; j < n; ++j) {
            // If j is not equal to i (i.e., not the diagonal element),
            // then b_ij contains a_i & a_j.
            // Bitwise OR this value into current_a_i.
            if (i != j) {
                current_a_i |= b[i][j];
            }
        }
        // Store the computed value for a_i.
        a[i] = current_a_i;
    }

    // Print the restored sequence a, separated by spaces.
    for (int i = 0; i < n; ++i) {
        std::cout << a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_score = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            // Mr. Chanek's turn
            if (n % 2 != 0) {
                // N is odd. Must take 1.
                chanek_score += 1;
                n -= 1;
            } else {
                // N is even. Can take 1 or N/2.
                // If N/2 is odd, taking N/2 leaves an odd number for opponent.
                // If N/2 is even, taking N/2 leaves an even number for opponent.
                // Taking 1 leaves an odd number for opponent.

                // Strategy: If N is even, and N/2 is odd, taking N/2 is good.
                // It gives Chanek N/2 coins, and leaves an odd number for opponent.
                // Opponent will then be forced to take 1.
                // If N/2 is even, taking N/2 is also good. It gives Chanek N/2 coins.
                // The only case where taking 1 might be better is if N is very small,
                // or if taking N/2 leads to a situation where the opponent gets a lot.

                // Let's analyze the options for even N:
                // Option 1: Take 1 coin.
                //   Chanek gets 1. Remaining N-1 (odd). Opponent takes 1.
                //   This path is generally worse if N is large, as 1 is small.
                // Option 2: Take N/2 coins.
                //   Chanek gets N/2. Remaining N/2.
                //   This is generally better as N/2 is larger.

                // The only time taking 1 might be better than N/2 is if N/2 is 2.
                // If N=4:
                //   Take 1: Chanek gets 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                //     Chanek: 1+1 = 2. Opponent: 1+1 = 2.
                //   Take N/2 (2): Chanek gets 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                //     Chanek: 2+1 = 3. Opponent: 1 = 1.
                // So for N=4, taking N/2 is better.

                // What if N/2 is 1? This means N=2.
                // If N=2:
                //   Take 1: Chanek gets 1. N=1. Opponent takes 1. N=0.
                //     Chanek: 1. Opponent: 1.
                //   Take N/2 (1): Chanek gets 1. N=1. Opponent takes 1. N=0.
                //     Chanek: 1. Opponent: 1.
                // Both are same.

                // The only special case is when N is a power of 2, and N/2 is also a power of 2,
                // and this continues until N becomes 2.
                // Example: N = 2^k.
                // If N is a power of 2, and N > 2:
                //   Taking N/2 leaves N/2, which is also a power of 2.
                //   Taking 1 leaves N-1, which is odd.
                //   If Chanek takes N/2, opponent faces N/2.
                //   If Chanek takes 1, opponent faces N-1 (odd), so opponent takes 1.
                //   Then Chanek faces N-2 (even).

                // Consider N = 2^k for k >= 2.
                // Chanek's turn. N is even.
                // Option A: Take 1. Chanek gets 1. N becomes 2^k-1 (odd).
                //   Opponent's turn. N is odd. Opponent takes 1. Opponent gets 1. N becomes 2^k-2 (even).
                //   Chanek's turn. N is even.
                // Option B: Take N/2. Chanek gets 2^(k-1). N becomes 2^(k-1) (even).
                //   Opponent's turn. N is even.

                // If N is a power of 2, and N > 2:
                // Chanek takes N/2. Chanek gets N/2. N becomes N/2.
                // Opponent takes N/2. Opponent gets N/2. N becomes N/2.
                // This continues until N becomes 2.
                // At N=2, Chanek takes 1. Chanek gets 1. N=1.
                // Opponent takes 1. Opponent gets 1. N=0.
                // Total for Chanek: N/2 + N/8 + ... + 1.
                // Total for Opponent: N/4 + N/16 + ... + 1.
                // This is a geometric series.
                // If N = 2^k:
                // Chanek gets 2^(k-1) + 2^(k-3) + ... + 2^1 (if k is even) or 2^0 (if k is odd)
                // Opponent gets 2^(k-2) + 2^(k-4) + ... + 2^0 (if k is even) or 2^1 (if k is odd)

                // This pattern is for when both players always take N/2.
                // But what if one player decides to take 1?
                // If N is a power of 2, say N=2^k.
                // Chanek's turn.
                // If Chanek takes 1: Chanek gets 1. N becomes 2^k-1.
                //   Opponent's turn. N is odd. Opponent takes 1. Opponent gets 1. N becomes 2^k-2.
                //   Chanek's turn. N is even.
                // If Chanek takes N/2: Chanek gets N/2. N becomes 2^(k-1).
                //   Opponent's turn. N is even.

                // The key insight is that if N is even, taking N/2 is almost always better
                // because it gives a larger immediate gain. The only exception is if N/2 is 1, i.e., N=2.
                // If N=2, taking 1 or N/2 both yield 1 coin.
                // If N is even and N > 2:
                //   If Chanek takes N/2, he gets N/2.
                //   If Chanek takes 1, he gets 1.
                //   N/2 is always greater than 1 for N > 2.
                //   So, Chanek should always take N/2 if N is even and N > 2.
                //   If N=2, he can take 1 or N/2, both give 1. Let's say he takes N/2.

                // So the greedy strategy for Chanek is:
                // If N is odd, take 1.
                // If N is even, take N/2. (This covers N=2 as well, taking 1 coin).

                // Let's re-evaluate this greedy strategy.
                // If N is even:
                //   Option 1: Take 1. Chanek gets 1. N becomes N-1.
                //     Opponent faces N-1 (odd). Opponent takes 1. Opponent gets 1. N becomes N-2.
                //     Chanek faces N-2 (even).
                //   Option 2: Take N/2. Chanek gets N/2. N becomes N/2.
                //     Opponent faces N/2 (even or odd).

                // Consider N=6 (example case):
                // Chanek's turn, N=6. Even.
                //   Option 1: Take 1. Chanek gets 1. N=5.
                //     Opponent's turn, N=5. Odd. Opponent takes 1. Opponent gets 1. N=4.
                //     Chanek's turn, N=4. Even.
                //       Chanek takes N/2 (2). Chanek gets 2. N=2.
                //       Opponent's turn, N=2. Even. Opponent takes N/2 (1). Opponent gets 1. N=1.
                //       Chanek's turn, N=1. Odd. Chanek takes 1. Chanek gets 1. N=0.
                //     Total Chanek: 1+2+1 = 4. Total Opponent: 1+1 = 2.
                //   Option 2: Take N/2 (3). Chanek gets 3. N=3.
                //     Opponent's turn, N=3. Odd. Opponent takes 1. Opponent gets 1. N=2.
                //     Chanek's turn, N=2. Even. Chanek takes N/2 (1). Chanek gets 1. N=1.
                //     Opponent's turn, N=1. Odd. Opponent takes 1. Opponent gets 1. N=0.
                //   Total Chanek: 3+1 = 4. Total Opponent: 1+1 = 2.
                // Both options yield 4 for Chanek. The example output is 4.
                // This suggests that taking N/2 is the optimal move for Chanek when N is even.

                // Let's test N=5 (example case):
                // Chanek's turn, N=5. Odd. Chanek takes 1. Chanek gets 1. N=4.
                // Opponent's turn, N=4. Even. Opponent takes N/2 (2). Opponent gets 2. N=2.
                // Chanek's turn, N=2. Even. Chanek takes N/2 (1). Chanek gets 1. N=1.
                // Opponent's turn, N=1. Odd. Opponent takes 1. Opponent gets 1. N=0.
                // Total Chanek: 1+1 = 2. Total Opponent: 2+1 = 3.
                // This matches the example output 2.

                // The greedy strategy seems to be:
                // If N is odd, take 1.
                // If N is even:
                //   If N is a power of 2 (and N > 2), taking N/2 leads to a symmetric game where opponent also takes N/2.
                //   This means Chanek gets N/2 + N/8 + ...
                //   If Chanek takes 1, opponent takes 1, then Chanek faces N-2.
                //   This is a complex comparison.

                // Let's consider the case where N is even.
                // Chanek wants to maximize his score. Opponent wants to maximize their score.
                // If N is even, Chanek has two choices:
                // 1. Take 1. Chanek gets 1. Remaining N-1.
                // 2. Take N/2. Chanek gets N/2. Remaining N/2.

                // If N is not a power of 2, and N is even:
                // N = 2^k * M, where M is odd and M > 1.
                // If Chanek takes N/2: Chanek gets N/2. Remaining N/2 = 2^(k-1) * M.
                //   Opponent faces N/2. If N/2 is odd (k=1, M>1), opponent takes 1.
                //   If N/2 is even (k>1), opponent takes N/4.
                // If Chanek takes 1: Chanek gets 1. Remaining N-1 (odd).
                //   Opponent faces N-1 (odd). Opponent takes 1. Opponent gets 1. Remaining N-2.
                //   Chanek faces N-2 (even).

                // The crucial observation might be that if N is even and not a power of 2,
                // then N/2 is either odd (if N = 2 * odd) or even but not a power of 2 (if N = 2^k * odd, k>1).
                // In these cases, taking N/2 is generally better because it gives a larger chunk.
                // The opponent will then face N/2. If N/2 is odd, opponent takes 1.
                // If N/2 is even and not a power of 2, opponent takes N/4.
                // This seems to lead to a situation where players keep taking N/2 until N becomes odd.

                // The only tricky case is when N is a power of 2.
                // Let N = 2^k.
                // If Chanek takes N/2: Chanek gets N/2. N becomes 2^(k-1).
                //   Opponent faces 2^(k-1). Opponent takes 2^(k-2). N becomes 2^(k-2).
                //   This continues until N=2.
                //   Chanek gets N/2 + N/8 + N/32 + ...
                //   Opponent gets N/4 + N/16 + N/64 + ...
                //   The last two terms are 1 for Chanek and 1 for Opponent (from N=2 and N=1).
                //   Total Chanek: (2^k)/2 + (2^k)/8 + ... + 1.
                //   Total Opponent: (2^k)/4 + (2^k)/16 + ... + 1.
                //   Sum of geometric series:
