long long solve() {
    long long p, q;
    std::cin >> p >> q;

    if (p % q != 0) {
        return p;
    }

    // p is divisible by q. We need to find a divisor x of p such that x is not divisible by q.
    // We want the largest such x.
    // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
    // For x to not be divisible by q, there must be at least one prime factor fi of q
    // such that the exponent of fi in x's prime factorization is less than ai.

    // We iterate through prime factors of q.
    // For each prime factor f of q, we try to remove enough factors of f from p
    // such that the resulting number p' is not divisible by q.
    // The largest such p' will be our answer.

    long long max_x = 0;
    long long temp_q = q;

    // Find prime factors of q
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            // i is a prime factor of q
            long long current_p = p;
            while (current_p % i == 0 && current_p % q == 0) {
                current_p /= i;
            }
            max_x = std::max(max_x, current_p);

            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }

    // If temp_q > 1, it means temp_q itself is a prime factor (the largest one)
    if (temp_q > 1) {
        long long i = temp_q; // This is a prime factor
        long long current_p = p;
        while (current_p % i == 0 && current_p % q == 0) {
            current_p /= i;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

