    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool possible = false;

    for (char pivot_char = '0'; pivot_char <= '9'; ++pivot_char) {
        std::vector<char> s1_digits;
        std::vector<char> s2_digits;
        std::string current_coloring(n, ' ');
        bool current_coloring_valid = true;
        char last_s1_digit = '0'; // Smallest possible digit
        char last_s2_digit = '0'; // Smallest possible digit

        for (int i = 0; i < n; ++i) {
            char digit = s[i];
            if (digit < pivot_char) {
                // Must be color 1
                if (digit < last_s1_digit) {
                    current_coloring_valid = false;
                    break;
                }
                current_coloring[i] = '1';
                last_s1_digit = digit;
                s1_digits.push_back(digit);
            } else if (digit > pivot_char) {
                // Must be color 2
                if (digit < last_s2_digit) {
                    current_coloring_valid = false;
                    break;
                }
                current_coloring[i] = '2';
                last_s2_digit = digit;
                s2_digits.push_back(digit);
            } else { // digit == pivot_char
                // Can be color 1 or 2
                // Try to put it in color 2 if possible, to keep color 1 digits small
                if (digit >= last_s2_digit) {
                    current_coloring[i] = '2';
                    last_s2_digit = digit;
                    s2_digits.push_back(digit);
                } else if (digit >= last_s1_digit) {
                    current_coloring[i] = '1';
                    last_s1_digit = digit;
                    s1_digits.push_back(digit);
                } else {
                    current_coloring_valid = false;
                    break;
                }
            }
        }

        if (current_coloring_valid) {
            // Check the final combined sequence
            // The individual sequences s1_digits and s2_digits are already checked for non-decreasing property
            // We only need to check the transition from s1_digits to s2_digits
            if (!s1_digits.empty() && !s2_digits.empty()) {
                if (s1_digits.back() > s2_digits.front()) {
                    current_coloring_valid = false;
                }
            }
        }

        if (current_coloring_valid) {
            result = current_coloring;
            possible = true;
            break; 
        }
    }

    if (possible) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 1 means can move left (x-1). If f1=0, cannot move left.
            // If robot is at (x,y) and cannot move left (f1=0),
            // then any target X must be >= x.
            // Because if X < x, robot needs to move left, but can't.
            // So it stops at x. Thus, X must be >= x.
            if (f1 == 0) { // Cannot move left
                min_x = std::max(min_x, x);
            }

            // f3 = 1 means can move right (x+1). If f3=0, cannot move right.
            // If robot is at (x,y) and cannot move right (f3=0),
            // then any target X must be <= x.
            // Because if X > x, robot needs to move right, but can't.
            // So it stops at x. Thus, X must be <= x.
            if (f3 == 0) { // Cannot move right
                max_x = std::min(max_x, x);
            }

            // f4 = 1 means can move down (y-1). If f4=0, cannot move down.
            // If robot is at (x,y) and cannot move down (f4=0),
            // then any target Y must be >= y.
            // Because if Y < y, robot needs to move down, but can't.
            // So it stops at y. Thus, Y must be >= y.
            if (f4 == 0) { // Cannot move down
                min_y = std::max(min_y, y);
            }

            // f2 = 1 means can move up (y+1). If f2=0, cannot move up.
            // If robot is at (x,y) and cannot move up (f2=0),
            // then any target Y must be <= y.
            // Because if Y > y, robot needs to move up, but can't.
            // So it stops at y. Thus, Y must be <= y.
            if (f2 == 0) { // Cannot move up
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

