            continue;
        }

        // Calculate the parity of the target point (abs_n, abs_m)
        // and the parity of the number of moves k.
        // A move changes the sum of coordinates by an odd amount (e.g., (x+1, y+0) sum changes by 1, (x+1, y+1) sum changes by 2).
        // However, a simpler parity check is on the coordinates themselves.
        // Each move changes the parity of x or y or both.
        // The parity of (x+y) changes by 1 for axial moves, and by 0 or 2 for diagonal moves.
        // So, (x+y) parity changes by (dx+dy) mod 2.
        // (dx+dy) mod 2 is 1 for axial moves, 0 for diagonal moves.
        // So, (x_final + y_final) - (x_initial + y_initial) has the same parity as (number of axial moves).
        // (abs_n + abs_m) - (0 + 0) has the same parity as (k - D).
        // So, (abs_n + abs_m) and (k - D) must have the same parity.
        // This means (abs_n + abs_m) and k must have the same parity as D.
        // Or, (abs_n + abs_m) and k must have the same parity if D is even.
        // Or, (abs_n + abs_m) and k must have different parity if D is odd.
        // This is equivalent to (abs_n + abs_m) % 2 == k % 2.

        // Let's consider the parity of (abs_n - abs_m).
        // Each diagonal move changes both coordinates by +/- 1, so (x-y) parity is unchanged.
        // Each axial move changes one coordinate by +/- 1, so (x-y) parity is flipped.
        // So, (abs_n - abs_m) must have the same parity as (number of axial moves).
        // (abs_n - abs_m) % 2 == (k - D) % 2.
        // This means (abs_n - abs_m) % 2 == k % 2 if D is even.
        // This means (abs_n - abs_m) % 2 != k % 2 if D is odd.
        // This is equivalent to (abs_n - abs_m) % 2 == (k % 2 - D % 2 + 2) % 2.

        // A simpler way:
        // The minimum number of moves to reach (abs_n, abs_m) is abs_n.
        // This path uses abs_m diagonal moves and (abs_n - abs_m) axial moves.
        // Total moves = abs_m + (abs_n - abs_m) = abs_n.
        // The remaining k - abs_n moves must be "wasted" moves.
        // Each wasted move must be paired with another wasted move to return to the same parity.
        // For example, (x,y) -> (x+1,y) -> (x,y). This uses 2 axial moves.
        // Or (x,y) -> (x+1,y+1) -> (x,y). This uses 2 diagonal moves.
        // Or (x,y) -> (x+1,y) -> (x+1,y+1) -> (x,y+1) -> (x,y). This uses 2 axial, 2 diagonal.
        // The key is that each pair of wasted moves changes the coordinates by (0,0).
        // A pair of moves like (x,y) -> (x+1,y) -> (x,y) uses 2 axial moves.
        // A pair of moves like (x,y) -> (x+1,y+1) -> (x,y) uses 2 diagonal moves.
        // A pair of moves like (x,y) -> (x+1,y) -> (x,y+1) -> (x,y) is not a pair of wasted moves.
        // A pair of moves that results in (0,0) displacement is (x,y) -> (x+dx, y+dy) -> (x,y).
        // This means (dx,dy) and (-dx,-dy) are the two moves.
        // If (dx,dy) is diagonal, then (-dx,-dy) is also diagonal. So 2 diagonal moves.
        // If (dx,dy) is axial, then (-dx,-dy) is also axial. So 2 axial moves.
        // So, any "wasted" moves must come in pairs of the same type (2 diagonal or 2 axial).
        // This means the number of wasted moves (k - abs_n) must be even.
        // If (k - abs_n) is odd, it's impossible.

        if ((k - abs_n) % 2 != 0) {
            std::cout << -1 << "\n";
            continue;
        }

        // If we reach here, it's possible.
        // We want to maximize diagonal moves.
        // The minimum path uses abs_m diagonal moves and (abs_n - abs_m) axial moves.
        // Total moves = abs_n.
        // We have (k - abs_n) additional moves to make.
        // These additional moves must be made in pairs that cancel out.
        // Each such pair can be either two diagonal moves (e.g., (1,1) then (-1,-1))
        // or two axial moves (e.g., (1,0) then (-1,0)).
        // To maximize diagonal moves, we should use diagonal pairs for these additional moves.
        // So, we add (k - abs_n) diagonal moves.
        // Total diagonal moves = abs_m + (k - abs_n).
        // This is the maximum possible.

        std::cout << abs_m + (k - abs_n) << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1}^{b-1} r
    // sum_r = (b-1) * b / 2
    // Since b can be up to 10^7, (b-1)*b can be up to 10^14, which fits in long long.
    // We need to perform division by 2.
    // If b is even, b/2 is integer.
    // If b is odd, (b-1) is even, (b-1)/2 is integer.
    // So, one of (b-1) or b is even, ensuring (b-1)*b is divisible by 2.
    // We need to compute this modulo MOD.
    // (X * Y / 2) % MOD = (X % MOD * Y % MOD * inv(2) % MOD) % MOD
    // inv(2) mod 10^9+7 is (10^9+8)/2 = 500000004
    long long inv2 = 500000004; // (MOD + 1) / 2

    long long sum_r_term = (b - 1);
    if (sum_r_term < 0) sum_r_term = 0; // If b=1, then b-1=0, sum is 0.

    long long sum_r = (sum_r_term % MOD * (b % MOD)) % MOD;
    sum_r = (sum_r * inv2) % MOD;

    // Calculate sum_k = sum_{k=1}^{a} (k * b + 1)
    // sum_k = sum_{k=1}^{a} (k * b) + sum_{k=1}^{a} 1
    // sum_k = b * sum_{k=1}^{a} k + a
    // sum_{k=1}^{a} k = a * (a + 1) / 2
    long long sum_k_inner_term = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_inner_term = (sum_k_inner_term * inv2) % MOD;

    long long sum_k = (b % MOD * sum_k_inner_term) % MOD;
    sum_k = (sum_k + (a % MOD)) % MOD;

    // Total sum = (sum_r * sum_k) % MOD
    long long total_sum = (sum_r * sum_k) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        adj[s[i]].insert(s[i+1]);
        adj[s[i+1]].insert(s[i]);
    }

    // Check for impossible cases: a character having more than 2 distinct neighbors
    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited;
    char current_char = '\0';

    // Find a starting character (one with only one neighbor, or any if all have two)
    for (const auto& pair : adj) {
        if (pair.second.size() == 1) {
            current_char = pair.first;
            break;
        }
    }

    // If no char has 1 neighbor, it means all chars in 's' have 2 neighbors.
    // This implies a cycle or a single path where all internal nodes have 2 neighbors.
    // If it's a cycle, it's impossible to embed in a line.
    // If it's a path, we can pick any character to start.
    // The problem statement guarantees no adjacent equal characters, so s.length() >= 1.
    // If s.length() == 1, adj is empty, current_char remains '\0'.
    // If s.length() > 1 and no char has 1 neighbor, it means all chars in 's' have 2 neighbors.
    // This implies a path or cycle. If it's a path, we can start anywhere.
    // If it's a cycle, it's impossible.
    // Let's pick the first character of s if current_char is still '\0'.
    if (current_char == '\0' && !s.empty()) {
        current_char = s[0];
    } else if (s.empty()) { // Empty string case, though constraints say |s| >= 1
        // This case should not happen based on constraints, but for robustness
        // Any layout is fine.
        std::cout << "YES\n";
        for (char c = 'a'; c <= 'z'; ++c) {
            std::cout << c;
        }
        std::cout << "\n";
        return;
    }


    // Build the main path
    if (current_char != '\0') { // Only if there's at least one character from 's'
        while (current_char != '\0' && visited.find(current_char) == visited.end()) {
            layout_str += current_char;
            visited.insert(current_char);

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (visited.find(neighbor) == visited.end()) {
                    next_char = neighbor;
                    break;
                }
            }
            current_char = next_char;
        }
    }

    // Check if all characters from 's' that have neighbors are included in the path
    // This implicitly checks for cycles: if a cycle exists, and we started from a node
    // with 2 neighbors, we would traverse the cycle and end up back at the start,
    // but current_char would become '\0' only if the path ends.
    // If we started from a node with 1 neighbor, we would traverse the path.
    // If there are multiple disjoint paths required by 's', this logic will fail.
    // Example: s = "ab", adj = {a:{b}, b:{a}}. layout_str = "ab".
    // Example: s = "abac", adj = {a:{b,c}, b:{a}, c:{a}}. layout_str = "bac".
    // The current logic builds one path. If there are multiple components in the graph
    // formed by 's', this will only find one.
    // However, the problem states "for each pair of adjacent characters in s, they should be adjacent on the keyboard".
    // This implies that all characters involved in 's' must form a single contiguous block on the keyboard.
    // If the graph formed by 's' has multiple connected components, it's impossible.
    // E.g., s = "ab" and "cd" (not possible in one string, but conceptually).
    // The current logic correctly handles this: if adj[char].size() > 0 and char is not in layout_str, it's an issue.
    for (const auto& pair : adj) {
        if (visited.find(pair.first) == visited.end()) {
            std::cout << "NO\n"; // Found a character from 's' not in the constructed path
            return;
        }
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            layout_str += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        solve();
    }
    return 0;
}

