#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and_mask = 1023; // All bits 0-9 are 1
    int current_or_mask = 0;    // All bits 0-9 are 0
    int current_xor_mask = 0;   // All bits 0-9 are 0

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_and_mask &= x;
            current_or_mask &= x;
            current_xor_mask &= x;
        } else if (op_char == '|') {
            current_and_mask |= x;
            current_or_mask |= x;
            current_xor_mask |= x;
        } else if (op_char == '^') {
            current_and_mask ^= x;
            current_or_mask ^= x;
            current_xor_mask ^= x;
        }
    }

    std::vector<std::pair<char, int>> result_ops;

    // Determine the final AND constant
    // If a bit is 0 in current_and_mask, it must be 0 in the output.
    // If a bit is 1 in current_and_mask, it means it was never forced to 0 by an '&' operation.
    // So, the effective AND constant is current_and_mask.
    // This operation must be applied first to ensure bits forced to 0 stay 0.
    // If current_and_mask is 1023 (all ones), then no effective '&' operation is needed.
    if (current_and_mask != 1023) {
        result_ops.push_back({'&', current_and_mask});
    }

    // Determine the final OR constant
    // If a bit is 1 in current_or_mask, it must be 1 in the output.
    // If a bit is 0 in current_or_mask, it means it was never forced to 1 by an '|' operation.
    // This operation should be applied after '&' to ensure bits forced to 1 stay 1.
    // If current_or_mask is 0 (all zeros), then no effective '|' operation is needed.
    if (current_or_mask != 0) {
        result_ops.push_back({'|', current_or_mask});
    }

    // Determine the final XOR constant
    // If a bit is 1 in current_xor_mask, it means it was flipped an odd number of times.
    // If a bit is 0 in current_xor_mask, it means it was flipped an even number of times.
    // This operation should be applied last to flip bits as needed.
    // If current_xor_mask is 0 (all zeros), then no effective '^' operation is needed.
    if (current_xor_mask != 0) {
        result_ops.push_back({'^', current_xor_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

// Function to compute Z-array for a string
// Z[i] is the length of the longest common prefix of s and s[i...]
std::vector<int> compute_z_array(const std::string& s) {
    int n = s.length();
    std::vector<int> z(n);
    z[0] = n; // Conventionally, z[0] is n
    int l = 0, r = 0;
    for (int i = 1; i < n; ++i) {
        if (i <= r) {
            z[i] = std::min(r - i + 1, z[i - l]);
        }
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            ++z[i];
        }
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int L = s.length();

    // Precompute Z-arrays for all cyclic shifts of s
    // z_arrays[i] stores the Z-array for s[i...L-1] + s[0...i-1]
    std::vector<std::vector<int>> z_arrays(L);
    for (int i = 0; i < L; ++i) {
        std::string shifted_s = s.substr(i) + s.substr(0, i);
        z_arrays[i] = compute_z_array(shifted_s);
    }

    double total_win_prob = 0.0;

    // Iterate over all possible initial shifts k_true (Kolya's choice)
    for (int k_true = 0; k_true < L; ++k_true) {
        char t0_char = s[k_true]; // The first character Vasya learns

        // Group possible k values by t0_char
        // For a given t0_char, find all k' such that s[k'] == t0_char
        std::vector<int> possible_k_indices;
        for (int k_prime = 0; k_prime < L; ++k_prime) {
            if (s[k_prime] == t0_char) {
                possible_k_indices.push_back(k_prime);
            }
        }

        // If only one k' matches t0_char, Vasya wins immediately for this k_true
        if (possible_k_indices.size() == 1) {
            total_win_prob += 1.0;
            continue;
        }

        // Vasya needs to choose an optimal position p to query t_p
        // Iterate over all possible query positions p (1 to L-1)
        double max_win_prob_for_k_true = 0.0;
        for (int p = 1; p < L; ++p) {
            // For a fixed p, count how many k' values are uniquely determined
            // by (t0_char, t_p_char)

            // t_p_char is s[(p + k_true) % L]
            char tp_char = s[(p + k_true) % L];

            // Map to store counts of (t0_char, t_p_char) pairs
            // For each k' in possible_k_indices, calculate its (t0_char, t_p_char) pair
            // and count how many k' map to the same pair.
            // A k' is uniquely determined if its pair count is 1.
            std::map<char, int> tp_char_counts;
            for (int k_prime : possible_k_indices) {
                tp_char_counts[s[(p + k_prime) % L]]++;
            }

            // Calculate win probability for this specific p
            double current_p_win_count = 0;
            for (int k_prime : possible_k_indices) {
                if (tp_char_counts[s[(p + k_prime) % L]] == 1) {
                    // This k_prime is uniquely determined by (t0_char, t_p_char)
                    // If k_prime is the true k_true, Vasya wins.
                    // We are interested in the case where k_prime == k_true.
                    // If s[(p + k_true) % L] has a count of 1, then k_true is uniquely determined.
                    // This means Vasya wins for this k_true and this p.
                    if (s[(p + k_true) % L] == tp_char && tp_char_counts[tp_char] == 1) {
                        current_p_win_count = 1.0; // Vasya wins for this k_true
                        break;
                    }
                }
            }
            max_win_prob_for_k_true = std::max(max_win_prob_for_k_true, current_p_win_count);
        }
        total_win_prob += max_win_prob_for_k_true;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

