    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;

        int max_gap = 0;
        int last_r_pos = 0; // Position of the last 'R' cell encountered, or 0 for the start.
                            // This is 0-indexed for string, but represents cell number.
                            // So, if s[i] is 'R', it means cell i+1 is 'R'.
                            // last_r_pos stores the cell number.

        // Iterate through the string s (cells 1 to n)
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // If we find an 'R' at cell i+1, it means we can jump from last_r_pos
                // to this cell i+1. The gap is (i+1) - last_r_pos.
                // We need d to be at least this gap.
                max_gap = std::max(max_gap, (i + 1) - last_r_pos);
                last_r_pos = i + 1; // Update last_r_pos to the current 'R' cell
            }
        }

        // After iterating through all cells, we need to consider the jump from the
        // last 'R' cell (or cell 0 if no 'R's) to the target cell n+1.
        // The gap is (n+1) - last_r_pos.
        max_gap = std::max(max_gap, (int)s.length() + 1 - last_r_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_s = 0;
    int initial_b = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s++;
        } else {
            initial_b++;
        }
    }

    int target_diff = initial_s - initial_b;

    // Calculate prefix sums for the left side (jars 1 to n)
    // `left_diff[k]` stores the difference (S-B) for jars 1 to k.
    // We are interested in the suffix of the left side, i.e., jars 1 to (n-k_eaten).
    // This means we eat k_eaten jars from the left, starting from jar n, then n-1, ..., n-k_eaten+1.
    // The remaining jars are 1, ..., n-k_eaten.
    // Let's define `left_balance[k]` as the balance (S-B) of the first `k` jars (1 to k).
    // So, `left_balance[0] = 0`.
    // `left_balance[k]` for `k` from 1 to `n`.
    std::vector<int> left_balance(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        left_balance[i + 1] = left_balance[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right side (jars n+1 to 2n)
    // `right_balance[k]` stores the balance (S-B) of the last `k` jars (2n-k+1 to 2n).
    // We are interested in the prefix of the right side, i.e., jars (n+k_eaten+1) to 2n.
    // This means we eat k_eaten jars from the right, starting from jar n+1, then n+2, ..., n+k_eaten.
    // The remaining jars are n+k_eaten+1, ..., 2n.
    // Let's define `right_balance[k]` as the balance (S-B) of the last `k` jars (2n-k+1 to 2n).
    // So, `right_balance[0] = 0`.
    // `right_balance[k]` for `k` from 1 to `n`.
    std::vector<int> right_balance(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        right_balance[i + 1] = right_balance[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars eaten from the left to achieve a certain balance.
    // `left_eaten_map[balance]` = `k_eaten_left`
    // `k_eaten_left` is the number of jars eaten from the left (n, n-1, ..., n-k_eaten_left+1).
    // The remaining jars are 1, ..., n-k_eaten_left.
    // The balance of these remaining jars is `left_balance[n - k_eaten_left]`.
    std::map<int, int> left_eaten_map;
    for (int k_eaten_left = 0; k_eaten_left <= n; ++k_eaten_left) {
        int current_balance = left_balance[n - k_eaten_left];
        if (left_eaten_map.find(current_balance) == left_eaten_map.end()) {
            left_eaten_map[current_balance] = k_eaten_left;
        }
    }

    int min_jars_eaten = 2 * n; // Initialize with max possible

    // Iterate through all possible numbers of jars eaten from the right.
    // `k_eaten_right` is the number of jars eaten from the right (n+1, n+2, ..., n+k_eaten_right).
    // The remaining jars are n+k_eaten_right+1, ..., 2n.
    // The balance of these remaining jars is `right_balance[n - k_eaten_right]`.
    for (int k_eaten_right = 0; k_eaten_right <= n; ++k_eaten_right) {
        int current_right_balance = right_balance[n - k_eaten_right];

        // We need (S_L - B_L) + (S_R - B_R) = 0
        // So, (S_L - B_L) = -(S_R - B_R)
        // The required balance from the left side is -current_right_balance.
        int required_left_balance = -current_right_balance;

        if (left_eaten_map.count(required_left_balance)) {
            int k_eaten_left = left_eaten_map[required_left_balance];
            min_jars_eaten = std::min(min_jars_eaten, k_eaten_left + k_eaten_right);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for sums to prevent overflow
using ll = long long;

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // a_val[0] is unused, a_val[1] will be set by the loop, a_val[2]...a_val[n] are read
    std::vector<ll> a_val(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> a_val[i];
    }

    // dp_y[i] stores the total y accumulated when starting at x=i and performing the first step (x+a[i], y+a[i]),
    // then the second step (x-a[new_x], y+a[new_x]), and then continuing from the new x.
    // dp_y[i] = a[i] + a[i+a[i]] + dp_y[i+a[i]-a[i+a[i]]]
    // dp_y[i] = a[i] + a[next_x_after_first_step] + dp_y[final_x_after_two_steps]
    // dp_y[i] stores the total y accumulated from state (i, 0) until termination.
    std::vector<ll> dp_y(n + 1, 0);
    // dp_x[i] stores the final x value when starting at x=i and performing the first step (x+a[i], y+a[i]),
    // then the second step (x-a[new_x], y+a[new_x]), and then continuing from the new x.
    // dp_x[i] = dp_x[i+a[i]-a[i+a[i]]]
    // dp_x[i] stores the final x value from state (i, 0) until termination.
    std::vector<ll> dp_x(n + 1, 0);

    // visited[i] is used for cycle detection during DP calculation.
    // 0: not visited
    // 1: currently in recursion stack (visiting)
    // 2: finished visiting (computed)
    std::vector<int> visited(n + 1, 0);

    // Function to compute dp_y[start_x] and dp_x[start_x] using memoization and cycle detection
    auto solve = [&](int start_x, auto& self) -> void {
        if (start_x <= 0 || start_x > n) {
            // Base case: program terminates
            dp_y[start_x] = 0; // No more y accumulated
            dp_x[start_x] = start_x; // Final x is the terminating x
            visited[start_x] = 2;
            return;
        }

        if (visited[start_x] == 2) {
            // Already computed
            return;
        }
        if (visited[start_x] == 1) {
            // Cycle detected
            dp_y[start_x] = -1; // Mark as non-terminating
            dp_x[start_x] = -1; // Mark as non-terminating
            visited[start_x] = 2;
            return;
        }

        visited[start_x] = 1; // Mark as currently visiting

        ll current_a = a_val[start_x];
        ll x_after_step2 = start_x + current_a; // x after first part of step 2

        // Check termination condition after step 2
        if (x_after_step2 <= 0 || x_after_step2 > n) {
            dp_y[start_x] = current_a;
            dp_x[start_x] = x_after_step2;
            visited[start_x] = 2;
            return;
        }

        ll a_at_x_after_step2 = a_val[x_after_step2];
        ll x_after_step3 = x_after_step2 - a_at_x_after_step2; // x after step 3

        // Recursively solve for the next state
        self(x_after_step3, self);

        if (dp_y[x_after_step3] == -1) {
            // If the subsequent path leads to a cycle, this path also leads to a cycle
            dp_y[start_x] = -1;
            dp_x[start_x] = -1;
        } else {
            dp_y[start_x] = current_a + a_at_x_after_step2 + dp_y[x_after_step3];
            dp_x[start_x] = dp_x[x_after_step3];
        }
        visited[start_x] = 2; // Mark as computed
    };

    // For each possible initial a_val[1]
    for (int i = 1; i < n; ++i) {
        a_val[1] = i; // Set a_1 for this run

        // Reset visited and dp arrays for each run.
        // This is too slow. The DP state depends only on a_val[x] for x > 1.
        // Only a_val[1] changes. We can compute dp_y[1] directly.
        // The values dp_y[2]...dp_y[n] are constant across runs.
        // So we only need to compute dp_y[1] for each i.
        // The recursive calls for dp_y[1] will use precomputed values for x > 1.

        // Reset visited for x=1 only, as other states are independent of a_val[1]
        visited[1] = 0; 
        dp_y[1] = 0;
        dp_x[1] = 0;

        // Compute dp_y[1]
        solve(1, solve);

        std::cout << dp_y[1] << "\n";
    }

    return 0;
}

#include <iostream>
