// Function to solve a single query
void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substring_count = 0;

    // Max length for which 2^L-1 is still relatively small (e.g., < 2*10^5 + 60)
    // log2(2*10^5 + 60) is approx log2(200060) which is approx 17.6
    // So, L up to 18-20 is fine for direct binary conversion.
    // Let's pick a safe upper bound, say 20.
    // For L=18, 2^18 = 262144.
    // For L=19, 2^19 = 524288.
    // For L=20, 2^20 = 1048576.
    // The maximum possible length of a substring is N.
    // If a substring has length L, its value is at most 2^L-1.
    // We need L = value.
    // If L > 20, then 2^L-1 is much larger than L.
    // For example, if L=20, max value is 1048575.
    // If L=18, max value is 262143.
    // The maximum possible length of a substring is N = 2*10^5.
    // So, if L > 18, then 2^L-1 > N.
    // The condition is len = val.
    // If len > 18, then val must be > 18.
    // If s[l] == '0', then val is at most 2^(len-1)-1.
    // If s[l] == '1', then val is at most 2^len-1.
    // The maximum length of a substring is N.
    // The maximum value of a substring is N.
    // So, we only care about substrings whose value is at most N.
    // If a substring has length L, its value is at most 2^L-1.
    // If L is large, say L=20, then 2^L-1 is 1048575.
    // But we need value <= N <= 2*10^5.
    // So, we only need to consider substrings whose length L is such that 2^L-1 >= L and L <= N.
    // The maximum L for which 2^L-1 is around 2*10^5 is L=18 (2^18-1 = 262143).
    // So, we only need to check substrings of length up to about 18-20.
    // Let's use a constant MAX_LEN_CHECK for this. A value like 20 is safe.
    const int MAX_LEN_CHECK = 20; // Max length to check for direct binary conversion

    // Precompute prefix sums of '0's
    std::vector<int> prefix_zeros(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_zeros[i + 1] = prefix_zeros[i] + (s[i] == '0');
    }

    for (int i = 0; i < n; ++i) {
        // Case 1: Substring starts with '1'
        if (s[i] == '1') {
            long long current_val = 0;
            for (int j = i; j < std::min(n, i + MAX_LEN_CHECK); ++j) {
                current_val = (current_val << 1) | (s[j] - '0');
                int len = j - i + 1;
                if (current_val == len) {
                    good_substring_count++;
                }
            }
        }
        // Case 2: Substring starts with '0'
        // For substrings starting with '0', we need to handle leading zeros.
        // The value f(0...01...) is the value of 1...
        // The length is the total length including leading zeros.
        // Let's iterate through possible lengths `len`.
        // The actual binary value `val` must be `len`.
        // The substring is s[i...j]. Length is `len = j-i+1`.
        // The value `val` is `f(s[i...j])`.
        // We need `len = val`.
        // Since `s[i] == '0'`, `val` must be formed by `s[k...j]` where `s[k]` is the first '1'.
        // If there is no '1', `val` is 0.
        // If `val = 0`, then `len = 0`, which is impossible for a non-empty substring.
        // So, `val` must be positive. This means there must be at least one '1'.

        // Iterate `j` from `i` to `n-1`.
        // `s[i...j]` is the current substring.
        // `len = j-i+1`.
        // `val` is the decimal value of `s[i...j]`.
        // We need `len = val`.

        // If `s[i] == '0'`, we can have many leading zeros.
        // The actual binary value `val` is determined by the first '1' and subsequent digits.
        // Let `k` be the index of the first '1' in `s[i...j]`.
        // If no '1' exists, `val = 0`. Then `len = 0` is required, impossible.
        // So, `k` must exist.
        // `val = f(s[k...j])`.
        // `len = j-i+1`.
        // We need `j-i+1 = f(s[k...j])`.

        // Iterate `j` from `i` to `n-1`.
        // `s[i...j]` is the substring.
        // `len = j-i+1`.
        // `val` is the decimal value of `s[i...j]`.
        // We need `len = val`.

        // The maximum value of `len` is `n`.
        // The maximum value of `val` is `n`.
        // If `s[i] == '0'`, then `val` is at most `2^(len-1)-1`.
        // If `len` is large, `val` can be much smaller than `len`.
        // Example: `s = 00001000`, `n=8`.
        // `i=0, s[0]='0'`.
        // `j=0, s[0]='0'`. `len=1`. `val=0`. `1 != 0`.
        // `j=1, s[0..1]='00'`. `len=2`. `val=0`. `2 != 0`.
        // ...
        // `j=4, s[0..4]='00001'`. `len=5`. `val=1`. `5 != 1`.
        // `j=5, s[0..5]='000010'`. `len=6`. `val=2`. `6 != 2`.
        // `j=6, s[0..6]='0000100'`. `len=7`. `val=4`. `7 != 4`.
        // `j=7, s[0..7]='00001000'`. `len=8`. `val=8`. `8 == 8`. Good!

        // The key observation for `s[i] == '0'`:
        // Let `k` be the index of the first '1' after `i`.
        // If no '1' exists from `i` onwards, then all substrings `s[i...j]` have value 0,
        // and `len > 0`, so no good substrings.
        // If `k` exists, then for any `j >= k`, the value `f(s[i...j])` is `f(s[k...j])`.
        // The length is `j-i+1`.
        // We need `j-i+1 = f(s[k...j])`.
        // Let `num_leading_zeros = k-i`.
        // Then `j-i+1 = num_leading_zeros + (j-k+1)`.
        // We need `num_leading_zeros + (j-k+1) = f(s[k...j])`.
        // Let `len_suffix = j-k+1`.
        // We need `num_leading_zeros + len_suffix = f(s[k...j])`.

        // Iterate `k` from `i` to `n-1`.
        // If `s[k] == '1'`:
        //   `num_leading_zeros = k-i`.
        //   Now, for `j` from `k` to `min(n-1, k + MAX_LEN_CHECK - 1)`:
        //     `current_val_suffix = f(s[k...j])`.
        //     `len_suffix = j-k+1`.
        //     `total_len = num_leading_zeros + len_suffix`.
        //     If `total_len == current_val_suffix`, then `s[i...j]` is good.
        // This covers the case where `s[k...j]` is short.

        // What if `s[k...j]` is long?
        // `f(s[k...j])` can be up to `2^MAX_LEN_CHECK - 1`.
        // `total_len` can be up to `n`.
        // We need `total_len = f(s[k...j])`.
        // `f(s[k...j])` must be at most `n`.
        // So, `f(s[k...j])` must be at most `2*10^5`.
        // This means `j-k+1` (length of suffix) must be at most `MAX_LEN_CHECK`.
        // So, the previous loop `j` from `k` to `min(n-1, k + MAX_LEN_CHECK - 1)` is sufficient.

        // Let's refine the logic for `s[i] == '0'`.
        // We are looking for `s[i...j]` such that `j-i+1 = f(s[i...j])`.
        // Let `k` be the index of the first '1' in `s` starting from `i`.
        // If no '1' exists, `f(s[i...j]) = 0`, but `j-i+1 > 0`, so no match.
        // If `k` exists:
        //   `num_leading_zeros = k-i`.
        //   For `j` from `k` to `n-1`:
        //     `val_suffix = f(s[k...j])`.
        //     `len_suffix = j-k+1`.
        //     `total_len = num_leading_zeros + len_suffix`.
        //     We need `total_len = val_suffix`.
        //     Since `val_suffix` can be at most `n`, `len_suffix` can be at most `MAX_LEN_CHECK`.
        //     So, `j` only needs to go up to `k + MAX_LEN_CHECK - 1`.
        //     This is already covered by the `s[i] == '1'` loop if we consider `i` as `k`.

        // The problem is that `s[i]` can be '0'.
        // If `s[i] == '0'`, we need to find the first '1' at index `k >= i`.
        // If no '1' is found, then `f(s[i...j]) = 0` for all `j`, so no good substrings.
        // If `k` is found, then `f(s[i...j]) = f(s[k...j])`.
        // We need `j-i+1 = f(s[k...j])`.
        // Let `num_zeros_before_first_one = k-i`.
        // Let `len_from_first_one = j-k+1`.
        // We need `num_zeros_before_first_one + len_from_first_one = f(s[k...j])`.
        // Let `val_from_first_one = f(s[k...j])`.
        // We need `num_zeros_before_first_one + len_from_first_one = val_from_first_one`.

        // Iterate `k` from `i` to `n-1`.
        // If `s[k] == '1'`:
        //   `num_zeros_before_first_one = k-i`.
        //   `current_val_from_first_one = 0`.
        //   For `j` from `k` to `min(n-1, k + MAX_LEN_CHECK - 1)`:
        //     `current_val_from_first_one = (current_val_from_first_one << 1) | (s[j] - '0');`
        //     `len_from_first_one = j-k+1;`
        //     `total_len = num_zeros_before_first_one + len_from_first_one;`
        //     If `total_len == current_val_from_first_one`:
        //       `good_substring_count++;`
        //   Break from inner loop (found first '1' for this `i`, move to next `i`).
        // This logic is correct.

        // Let's combine.
        // For each starting position `i`:
        //   `current_val = 0` (this will be `f(s[k...j])` where `k` is first '1')
        //   `first_one_idx = -1`
        //   For `j` from `i` to `n-1`:
        //     If `s[j] == '1'` and `first_one_idx == -1`:
        //       `first_one_idx = j`
        //     If `first_one_idx != -1`:
        //       `current_val = (current_val << 1) | (s[j] - '0');`
        //       If `current_val > n + MAX_LEN_CHECK`: // Optimization: if val gets too big, it can't be equal to len
        //                                              // len is at most n. num_leading_zeros is at most n.
        //                                              // len_from_first_one is at most MAX_LEN_CHECK.
        //                                              // So total_len is at most n.
        //                                              // If current_val_from_first_one > n, it can't be equal to total_len.
        //                                              // A tighter bound: current_val_from_first_one > n is enough.
        //                                              // But we need to be careful with `total_len = num_leading_zeros + len_from_first_one`.
        //                                              // `num_leading_zeros` can be up to `n`.
        //                                              // `len_from_first_one` can be up to `MAX_LEN_CHECK`.
        //                                              // So `total_len` can be up to `n + MAX_LEN_CHECK`.
        //                                              // If `current_val_from_first_one` exceeds `n + MAX_LEN_CHECK`, then break.
        //         break;
        //       `total_len = (j - i + 1);`
        //       If `current_val == total_len`:
        //         `good_substring_count++;`
        //     Else (`first_one_idx == -1`, meaning `s[i...j]` are all '0's):
        //       `current_val` remains 0.
        //       `total_len = (j - i + 1);`
        //       If `current_val == total_len` (i.e., `0 == total_len`), this is impossible as `total_len >= 1`.
        //       So, no good substrings if all are '0's.

        // This combined approach is correct.
        // The inner loop for `j` will run at most `MAX_LEN_CHECK` times after `first_one_idx` is set.
        // Before `first_one_idx` is set, it iterates through leading zeros.
        // The number of leading zeros can be up to `n`.
        // This means the inner loop can run `n` times in the worst case (e.g., `000...01`).
        // This is `O(N^2)` in total. Still too slow.

        // Let's rethink.
        // For each `i`, we are looking for `j` such that `j-i+1 = f(s[i...j])`.
        // If `s[i] == '1'`:
        //   Iterate `j` from `i` to `min(n-1, i + MAX_LEN_CHECK - 1)`.
        //   Calculate `val = f(s[i...j])`.
        //   If `val == j-i+1`, increment count.
        //   This is `O(N * MAX_LEN_CHECK)`. This part is fine.

        // If `s[i] == '0'`:
        //   We need to find `j` such that `j-i+1 = f(s[i...j])`.
        //   Let `k` be the index of the first '1' after `i`.
        //   If no '1' exists, no good substrings.
        //   If `k` exists, then `f(s[i...j]) = f(s[k...j])`.
        //   We need `j-i+1 = f(s[k...j])`.
        //   Let `num_leading_zeros = k-i`.
        //   Let `len_suffix = j-k+1`.
        //   We need `num_leading_zeros + len_suffix = f(s[k...j])`.
        //   Let `val_suffix = f(s[k...j])`.
        //   We need `num_leading_zeros + len_suffix = val_suffix`.
        //   This means `val_suffix - len_suffix = num_leading_zeros`.

        // For a fixed `k` (index of first '1'):
        //   Iterate `j` from `k` to `min(n-1, k + MAX_LEN_CHECK - 1)`.
        //   Calculate `val_suffix = f(s[k...j])`.
        //   `len_suffix = j-k+1`.
        //   `target_num_zeros = val_suffix - len_suffix`.
        //   If `target_num_zeros >= 0`:
        //     We need to find `i` such that `k-i = target_num_zeros`.
        //     This means `i = k - target_num_zeros`.
        //     If `i >= 0` and `s[i...k-1]` are all '0's, then `s[i...j]` is a good substring.
        //     The condition `s[i...k-1]` are all '0's is equivalent to `prefix_zeros[k] - prefix_zeros[i] == k-i`.
        //     Which is `prefix_zeros[k] - prefix_zeros[k - target_num_zeros] == target_num_zeros`.

        // This is the correct approach.
        // Iterate `k` from `0` to `n-1`.
        // If `s[k] == '1'`:
        //   `current_val_suffix = 0`.
        //   For `j` from `k` to `min(n-1, k + MAX_LEN_CHECK - 1)`:
        //     `current_val_suffix = (current_val_suffix << 1) | (s[j] - '0');`
        //     `len_suffix = j-k+1;`
        //     `target_num_zeros = current_val_suffix - len_suffix;`
        //     If `target_num_zeros >= 0`:
        //       `i = k - target_num_zeros;`
        //       If `i >= 0`:
        //         // Check if s[i...k-1] are all zeros.
        //         // This is true if prefix_zeros[k] - prefix_zeros[i] == target_num_zeros.
        //         if (prefix_zeros[k] - prefix_zeros[i] == target_num_zeros) {
        //           good_substring_count++;
        //         }
        //     // Optimization: if current_val_suffix gets too large, it can't be equal to total_len.
        //     // total_len = num_leading_zeros + len_suffix.
        //     // num_leading_zeros can be up to n. len_suffix is at most MAX_LEN_CHECK.
        //     // So total_len can be up to n + MAX_LEN_CHECK.
        //     // If current_val_suffix > n + MAX_LEN_CHECK, then it can't be equal to total_len.
        //     // A tighter bound: current_val_suffix > n is enough, because target_num_zeros must be <= n.
        //     // If current_val_suffix > n, then target_num_zeros = current_val_suffix - len_suffix > n - MAX_LEN_CHECK.
        //     // If n is large, this might still be valid.
        //     // The condition `target_num_zeros >= 0` is important.
        //     // The maximum value of `target_num_zeros` is `k`.
        //     // So `i` must be `k - target_num_zeros >= 0`.
        //     // `current_val_suffix` can be at most `2^MAX_LEN_CHECK - 1`.
        //     // `len_suffix` is at most `MAX_LEN_CHECK`.
        //     // So `target_num_zeros` is at most `2^MAX_LEN_CHECK - 1`.
        //     // If `current_val_suffix` exceeds `n + MAX_LEN_CHECK`, then `target_num_zeros` will also exceed `n`.
        //     // So `i = k - target_num_zeros` would be negative or `target_num_zeros` would be too large.
        //     // The `current_val_suffix > n + MAX_LEN_CHECK` check is a good optimization.
        //     if (current_val_suffix > n + MAX_LEN_CHECK) { // n is max possible total_len
        //         break;
        //     }
        // }

        // This approach is `O(N * MAX_LEN_CHECK)`.
        // `N = 2 * 10^5`, `MAX_LEN_CHECK = 20`.
        // `2 * 10^5 * 20 = 4 * 10^6`. This is efficient enough.

    for (int k = 0; k < n; ++k) { // k is the index of the first '1' in the effective binary number
        if (s[k] == '1') {
            long long current_val_suffix = 0;
            for (int j = k; j < std::min(n, k + MAX_LEN_CHECK); ++j) { // j is the end of the substring
                current_val_suffix = (current_val_suffix << 1) | (s[j] - '0');
                int len_suffix = j - k + 1;

                long long target_num_zeros = current_val_suffix - len_suffix;

                if (target_num_zeros >= 0) {
                    int i = k - static_cast<int>(target_num_zeros); // i is the start of the substring
                    if (i >= 0) {
                        // Check if s[i...k-1] are all zeros
                        // This is true if the count of zeros in s[i...k-1] is equal to its length (k-i)
                        if (prefix_zeros[k] - prefix_zeros[i] == target_num_zeros) {
                            good_substring_count++;
                        }
                    }
                }
                // Optimization: if current_val_suffix exceeds the maximum possible total_len,
                // then target_num_zeros will be too large, or it will be negative.
                // Max total_len is n.
                // If current_val_suffix > n, then current_val_suffix - len_suffix > n - MAX_LEN_CHECK.
                // If n is large, this might still be a valid target_num_zeros.
                // The actual upper bound for total_len is n.
                // So if current_val_suffix > n, then current_val_suffix cannot be equal to total_len.
                // This is a safe break condition.
                if (current_val_suffix > n) {
                    break;
                }
            }
        }
    }

    std::cout << good_substring_count << "\n";
}

