int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (only endpoints)
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_zero_run(n); // length of consecutive zeros to the left, including current
    std::vector<int> right_zero_run(n); // length of consecutive zeros to the right, including current
    std::vector<int> left_one_run(n); // length of consecutive ones to the left, including current
    std::vector<int> right_one_run(n); // length of consecutive ones to the right, including current

    // Calculate left runs
    left_zero_run[0] = (a[0] == 0);
    left_one_run[0] = (a[0] == 1);
    for (int i = 1; i < n; ++i) {
        left_zero_run[i] = (a[i] == 0) ? (left_zero_run[i - 1] + 1) : 0;
        left_one_run[i] = (a[i] == 1) ? (left_one_run[i - 1] + 1) : 0;
    }

    // Calculate right runs
    right_zero_run[n - 1] = (a[n - 1] == 0);
    right_one_run[n - 1] = (a[n - 1] == 1);
    for (int i = n - 2; i >= 0; --i) {
        right_zero_run[i] = (a[i] == 0) ? (right_zero_run[i + 1] + 1) : 0;
        right_one_run[i] = (a[i] == 1) ? (right_one_run[i + 1] + 1) : 0;
    }

    int max_k = 0;
    std::vector<int> final_b = a;

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // Current element is 0. It can become 1 if it's part of a 010 pattern that flips to 011 or 110.
                         // More precisely, if a[i-1]=1 and a[i+1]=1, then a[i] becomes 1.
                         // This means a 0 surrounded by 1s.
            if (a[i - 1] == 1 && a[i + 1] == 1) {
                // This 0 will flip to 1.
                // The number of steps for this 0 to flip is determined by the minimum distance to a 0 on either side.
                // The 0 at index i will flip to 1 if the 1s from its left and right propagate to meet at i.
                // The 1 at index j (j < i) propagates to j+k in k steps.
                // The 1 at index j (j > i) propagates to j-k in k steps.
                // For a[i] to become 1, we need a 1 to propagate from left to i and a 1 from right to i.
                // The 1 from left is at index i - left_one_run[i-1]. It needs left_one_run[i-1] steps to reach i-1.
                // The 1 from right is at index i + right_one_run[i+1]. It needs right_one_run[i+1] steps to reach i+1.
                // The actual 1s are at a[i-1] and a[i+1].
                // The 1 at a[i-1] is part of a run of 1s ending at i-1. Its length is left_one_run[i-1].
                // The 1 at a[i+1] is part of a run of 1s starting at i+1. Its length is right_one_run[i+1].
                // The 0 at index i is surrounded by 1s.
                // The 1s propagate inwards. The 0 at i will become 1 after min(left_one_run[i-1], right_one_run[i+1]) steps.
                // This is incorrect. The 1s propagate from the ends of the 0-block.
                // Consider a block of 0s: ...1 0 0 0 1...
                // The 0s at the ends of the block flip first.
                // The 0 at index i is part of a block of 0s.
                // The length of the 0-block containing a[i] is left_zero_run[i] + right_zero_run[i] - 1.
                // The distance from i to the left 1 is left_zero_run[i].
                // The distance from i to the right 1 is right_zero_run[i].
                // The number of steps for a[i] to flip is ceil(min(left_zero_run[i], right_zero_run[i]) / 2.0).
                // This is because the 1s propagate one step per iteration.
                // If a[i] is 0, and a[i-1]=1, a[i+1]=1, then a[i] becomes 1 in 1 step.
                // If a[i] is 0, and a[i-1]=0, a[i+1]=1, and a[i-2]=1, then a[i-1] becomes 1 in 1 step.
