struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize initial_a[j] to a very large value.
    // This represents the upper bound for A_0[j] + current_delta[j].
    // We want to find A_0[j] such that A_0[j] + current_delta[j] <= M_j for all j.
    // So, A_0[j] <= M_j - current_delta[j].
    // We want to maximize A_0[j] to satisfy the equality condition for type 2 ops.
    // The initial upper bound for A_0[j] is effectively infinity.
    // A_0[j] + current_delta[j] <= 10^9 (absolute value constraint)
    // So A_0[j] <= 10^9 - current_delta[j].
    // Since current_delta[j] can be negative, 10^9 is a safe upper bound for A_0[j].
    // We use LLONG_MAX as an initial upper bound for A_0[j] + current_delta[j]
    // and then refine it with type 2 operations.
    std::vector<long long> initial_a_plus_delta_upper_bound(n, LLONG_MAX);

    // Calculate the upper bounds for A_0[j] + current_delta[j]
    // based on type 2 operations.
    std::vector<long long> current_delta_sum(n, 0);
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_delta_sum[j] += op.val;
            }
        } else { // type 2
            for (int j = op.l; j <= op.r; ++j) {
                initial_a_plus_delta_upper_bound[j] = std::min(initial_a_plus_delta_upper_bound[j], op.val);
            }
        }
    }

