            // So current_delta_sum[j] is within [-5*10^7, 5*10^7].
            // M_j_final is within [-5*10^7, 5*10^7] or 0.
            // Thus a0[j] = M_j_final - current_delta_sum[j] will be within
            // [-5*10^7 - 5*10^7, 5*10^7 - (-5*10^7)] = [-10^8, 10^8].
            // This is well within [-10^9, 10^9]. So this check is not strictly necessary
            // for the given constraints, but good practice.
        }
    }

    // Verify the solution
    std::vector<long long> current_a(a0);
    std::fill(current_delta_sum.begin(), current_delta_sum.end(), 0); // Reset for verification

    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_a[j] += op.val;
                current_delta_sum[j] += op.val; // Keep track of total delta for each element
            }
        } else { // type 2
            long long max_val = LLONG_MIN;
            for (int j = op.l; j <= op.r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        // The initial array element A_0[i] is what we calculated.
        // The value of A_0[i] + (sum of all d_k that affect i) should be initial_a_plus_delta_upper_bound[i].
        // So, A_0[i] = initial_a_plus_delta_upper_bound[i] - (sum of all d_k that affect i).
        // This is exactly what we stored in a0[i].
        std::cout << a0[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    int value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_goodness;
    std::vector<int> partition(n);

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // f values are a_i + a_j.
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // Goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    // This is always a valid partition if n >= 2.
    min_goodness = (long long)elements[n - 1].value + elements[n - 2].value - ((long long)elements[0].value + elements[1].value);
    for (int i = 0; i < n; ++i) {
        partition[elements[i].original_index] = 1;
    }

    // Case 2: At least one element in each subsequence.
    // This means there will be f values of type a_i + a_j + h.
    // The minimum possible f value is a_1 + a_2.
    // The maximum possible f value is a_{n-1} + a_n + h.
    // The goodness would be (a_{n-1} + a_n + h) - (a_1 + a_2).
    // This is generally larger than Case 1 if h > 0.
    // However, we can try to make the min_f and max_f values closer.

    // Consider a partition where elements[0] is in S1 and elements[1] is in S2.
    // Or elements[0] is in S1 and elements[n-1] is in S2.
    // Or elements[n-1] is in S1 and elements[n-2] is in S2.

    // Let's try to put elements[0] in S1 and elements[1] in S2.
    // All other elements can go to S1.
    // S1 = {elements[0], elements[2], ..., elements[n-1]}
    // S2 = {elements[1]}
    //
    // f values:
    // 1. elements[0] + elements[k] (k >= 2) in S1: min elements[0]+elements[2], max elements[0]+elements[n-1]
    // 2. No pairs in S2 (if S2 has only one element)
    // 3. elements[0] + elements[1] + h (elements[0] in S1, elements[1] in S2)
    // 4. elements[k] + elements[1] + h (k >= 2, elements[k] in S1, elements[1] in S2): min elements[2]+elements[1]+h, max elements[n-1]+elements[1]+h
    //
    // Overall min_f: elements[0] + elements[2] (if n >= 3) or elements[0] + elements[1] + h (if n=2)
    // Overall max_f: elements[n-1] + elements[1] + h
    //
    // If n=2: S1={elements[0]}, S2={elements[1]}. Only f(elements[0], elements[1]) = elements[0]+elements[1]+h. Goodness is 0.
    // This is covered by the general logic below.
    //
    // If n >= 3:
    // min_f = std::min((long long)elements[0].value + elements[2].value, (long long)elements[0].value + elements[1].value + h);
    // max_f = (long long)elements[n-1].value + elements[1].value + h;
    //
    // This specific partition strategy:
    // elements[0] in S1, elements[1] in S2, elements[2...n-1] in S1.
    //
    // The minimum possible sum of two elements is elements[0].value + elements[1].value.
    // The maximum possible sum of two elements is elements[n-1].value + elements[n-2].value.
    //
    // Let's consider the values that can be formed:
    // A = elements[0].value + elements[1].value
    // B = elements[0].value + elements[n-1].value
    // C = elements[n-2].value + elements[n-1].value
    //
    // If we put all elements in one group, min_f = A, max_f = C. Goodness = C - A.
    //
    // If we put elements[0] in group 1, and elements[1]...elements[n-1] in group 2.
    // S1 = {elements[0]}
    // S2 = {elements[1], ..., elements[n-1]}
    //
    // f values:
    // 1. No pairs in S1.
    // 2. Pairs in S2: min elements[1]+elements[2], max elements[n-2]+elements[n-1].
    // 3. Pairs across S1 and S2: elements[0]+elements[k]+h for k=1...n-1.
    //    min elements[0]+elements[1]+h, max elements[0]+elements[n-1]+h.
    //
    // Overall min_f = std::min((long long)elements[1].value + elements[2].value, (long long)elements[0].value + elements[1].value + h); (if n >= 3)
    // Overall max_f = std::max((long long)elements[n-2].value + elements[n-1].value, (long long)elements[0].value + elements[n-1].value + h); (if n >= 3)
    //
    // If n=2: S1={elements[0]}, S2={elements[1]}. min_f = max_f = elements[0]+elements[1]+h. Goodness = 0.
    // This is a special case.
    if (n == 2) {
        long long current_goodness = 0;
        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            partition[elements[0].original_index] = 1;
            partition[elements[1].original_index] = 2;
        }
    } else { // n >= 3
        // Strategy 1: elements[0] in S1, elements[1] in S2, elements[2...n-1] in S1.
        // S1 = {elements[0], elements[2], ..., elements[n-1]}
        // S2 = {elements[1]}
        //
        // min_f:
        //   - From S1: elements[0].value + elements[2].value
        //   - From S1-S2: elements[0].value + elements[1].value + h
        //   - From S1-S2: elements[k].value + elements[1].value + h (k >= 2)
        // The smallest of these is elements[0].value + elements[2].value.
        //
        // max_f:
        //   - From S1: elements[n-2].value + elements[n-1].value
        //   - From S1-S2: elements[n-1].value + elements[1].value + h
        // The largest of these is elements[n-1].value + elements[1].value + h.
        //
        // So, min_f = std::min((long long)elements[0].value + elements[2].value, (long long)elements[0].value + elements[1].value + h);
        // max_f = (long long)elements[n-1].value + elements[1].value + h;
        //
        // This is the strategy from the first sample output.
        long long current_min_f = std::min((long long)elements[0].value + elements[2].value, (long long)elements[0].value + elements[1].value + h);
        long long current_max_f = (long long)elements[n-1].value + elements[1].value + h;
        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            partition[elements[0].original_index] = 1;
            partition[elements[1].original_index] = 2;
            for (int i = 2; i < n; ++i) {
                partition[elements[i].original_index] = 1;
            }
        }

        // Strategy 2: elements[0] in S1, elements[1...n-1] in S2.
        // S1 = {elements[0]}
        // S2 = {elements[1], ..., elements[n-1]}
        //
        // min_f:
        //   - From S2: elements[1].value + elements[2].value
        //   - From S1-S2: elements[0].value + elements[1].value + h
        //
        // max_f:
        //   - From S2: elements[n-2].value + elements[n-1].value
        //   - From S1-S2: elements[0].value + elements[n-1].value + h
        //
        current_min_f = std::min((long long)elements[1].value + elements[2].value, (long long)elements[0].value + elements[1].value + h);
        current_max_f = std::max((long long)elements[n-2].value + elements[n-1].value, (long long)elements[0].value + elements[n-1].value + h);
        current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            partition[elements[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                partition[elements[i].original_index] = 2;
            }
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> min_r_for_l(n + 2, n + 1); // min_r_for_l[i] stores the minimum r such that [i, r] contains a bad triplet.
                                                // Initialize with n+1, meaning no bad triplet starting at or before i.
                                                // Using 1-based indexing for convenience with problem statement.
                                                // min_r_for_l[0] is unused. min_r_for_l[n+1] is unused.

    // Iterate through all possible x and k to find bad triplets.
    // For each bad triplet (x, k), it covers the range [x, x+2k].
    // This means any (l, r) such that l <= x and x+2k <= r is a valid pair.
    // We are interested in the smallest r for a given l.
    // Specifically, for each x, the range [x, x+2k] implies that for any l <= x,
    // the minimum r required is at most x+2k.
    // So, min_r_for_l[l] = min(min_r_for_l[l], x+2k) for all l <= x.

    for (int x = 0; x < n; ++x) { // x is 0-indexed
        // k can be 1, 2, 3, 4, 5, 6.
        // If k >= 7, then 2k >= 14.
        // If s_x = s_{x+k} = s_{x+2k} for k >= 7, then x+2k >= x+14.
        // This means the minimum length of the segment [x, x+2k] is 15.
        // If we have a bad triplet (x, k) with k >= 7, then the segment [x, x+2k]
        // is at least 15 characters long.
        // Any such segment [x, x+2k] must contain a shorter bad triplet.
        // For example, if s_x = s_{x+k} = s_{x+2k}, then consider the substring s[x...x+2k].
        // If k >= 7, then this substring is long enough to contain a bad triplet with k' <= 6.
        // For example, if s_x = s_{x+k} = s_{x+2k}, then s_x, s_{x+1}, ..., s_{x+6}
        // and s_{x+k}, s_{x+k+1}, ..., s_{x+k+6} and s_{x+2k}, s_{x+2k+1}, ..., s_{x+2k+6}
        // are parts of the string.
        // The crucial observation is that if s_x = s_{x+k} = s_{x+2k} for k >= 7,
        // then there must exist some x' and k' <= 6 such that s_{x'} = s_{x'+k'} = s_{x'+2k'}
        // and x <= x' and x'+2k' <= x+2k.
        // This is because if a string of length L has no such pattern for k' <= 6,
        // then it cannot have such a pattern for k >= 7 either.
        // The maximum length of a pattern for k' <= 6 is 2*6+1 = 13.
        // If a string of length 14 or more contains a pattern for k >= 7,
        // it must contain a pattern for k' <= 6.
        // This is a known property for "square-free" strings or similar patterns.
        // For example, if s_x = s_{x+k} = s_{x+2k}, then consider the string s[x...x+2k].
        // If k >= 7, then this string has length at least 15.
        // It is known that any binary string of length 14 or more must contain a "square" (XX) or "cube" (XXX)
        // or a pattern like s_i = s_{i+k} = s_{i+2k} for some k <= 6.
        // More precisely, if s_x = s_{x+k} = s_{x+2k} for k >= 7, then the segment s[x...x+2k]
        // is long enough that it must contain a "shorter" bad triplet.
        // The maximum length of a pattern s_i = s_{i+k'} = s_{i+2k'} for k' <= 6 is 13 (when k'=6).
        // If we have a pattern for k >= 7, say s_x = s_{x+k} = s_{x+2k}, then the length is at least 15.
        // Any interval [x, x+2k] of length >= 15 that contains a bad triplet for k >= 7
        // must also contain a bad triplet for some k' <= 6.
        // This means we only need to check k from 1 to 6.
        for (int k = 1; k <= 6; ++k) { // k is 1-indexed
            if (x + 2 * k < n) { // Check if x+2k is within bounds (0-indexed)
                if (s[x] == s[x + k] && s[x] == s[x + 2 * k]) {
                    // Found a bad triplet at (x, k) covering [x, x+2k] (0-indexed)
                    // Convert to 1-indexed: [x+1, x+2k+1]
                    // For any l' from 1 to x+1, the minimum r' is at most x+2k+1.
                    // We want to update min_r_for_l[l'] for l' from 1 to x+1.
                    // The current value min_r_for_l[x+1] is the minimum r' for l'=x+1.
                    // We update min_r_for_l[x+1] = min(min_r_for_l[x+1], x+2k+1).
                    // This is because for l'=x+1, the segment [x+1, x+2k+1] is covered.
                    min_r_for_l[x + 1] = std::min(min_r_for_l[x + 1], x + 2 * k + 1);
                }
            }
        }
    }

    // Propagate minimum r values:
    // If min_r_for_l[i] is the minimum r for l=i, then for l=i-1,
    // the minimum r is at most min_r_for_l[i].
    // So, min_r_for_l[i-1] = min(min_r_for_l[i-1], min_r_for_l[i]).
    // This ensures that min_r_for_l[i] stores the minimum r such that [i, r] contains a bad triplet,
    // considering all bad triplets starting at or after i.
    for (int i = n; i >= 1; --i) {
        min_r_for_l[i] = std::min(min_r_for_l[i], min_r_for_l[i + 1]);
    }

    long long total_valid_pairs = 0;
    for (int l = 1; l <= n; ++l) {
        // For a fixed l, we need to count r such that l <= r <= n and [l, r] contains a bad triplet.
        // If min_r_for_l[l] <= n, it means there is at least one bad triplet starting at or after l.
        // The smallest r that makes [l, r] valid is min_r_for_l[l].
        // Any r such that min_r_for_l[l] <= r <= n will also make [l, r] valid.
        // The number of such r values is n - min_r_for_l[l] + 1.
        if (min_r_for_l[l] <= n) {
            total_valid_pairs += (n - min_r_for_l[l] + 1);
        }
    }

    std::cout << total_valid_pairs << std::endl;

    return 0;
}

