#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem asks for a different permutation p' with the same fingerprint.
    // Reversing the permutation p always yields a permutation p' with the same fingerprint.
    // This is because the set of adjacent sums {p_i + p_{i+1}} will be the same
    // as the set of adjacent sums for the reversed permutation {p_{n-i+1} + p_{n-i}}.
    // For example, if p = [p1, p2, p3], sums are {p1+p2, p2+p3}.
    // Reversed p' = [p3, p2, p1], sums are {p3+p2, p2+p1}.
    // These sets are identical, so their sorted versions (fingerprints) will be identical.
    // The reversed permutation is different from the original unless the original
    // permutation is a palindrome (p_i = p_{n-i+1} for all i).
    // However, a permutation of distinct integers from 1 to n cannot be a palindrome
    // unless n=1 (which is not allowed, n>=2) or n=0.
    // For n >= 2, p_1 and p_n must be distinct. If p_1 = p_n, then p is not a permutation
    // because elements must be distinct.
    // Therefore, p_1 != p_n, which means the reversed permutation p' will always be
    // different from p.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

