struct Item {
    int value;
    int original_index;
};

bool compareItems(const Item& a, const Item& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<Item> a_items(n);
        std::vector<Item> b_items(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a_items[i].value;
            a_items[i].original_index = i;
        }
        for (int i = 0; i < n; ++i) {
            std::cin >> b_items[i].value;
            b_items[i].original_index = i;
        }

        std::sort(a_items.begin(), a_items.end(), compareItems);
        std::sort(b_items.begin(), b_items.end(), compareItems);

        std::vector<int> x(n);
        std::vector<int> y(n);

        for (int i = 0; i < n; ++i) {
            x[a_items[i].original_index] = a_items[i].value;
            y[a_items[i].original_index] = b_items[n - 1 - i].value;
        }

        for (int i = 0; i < n; ++i) {
            std::cout << x[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << y[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

