#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    int max_a1 = a[0]; // Initial haybales in pile 1

    // Iterate through piles from 2 to n (index 1 to n-1)
    for (int i = 1; i < n; ++i) {
        int pile_idx = i; // 0-indexed pile index
        int pile_num = i + 1; // 1-indexed pile number

        int cost_per_haybale = pile_num - 1; // Days to move one haybale from pile_num to pile 1

        if (d >= cost_per_haybale) {
            // We can afford to move at least one haybale from this pile
            int haybales_in_current_pile = a[pile_idx];

            // Calculate how many haybales we can move from this pile
            // based on remaining days
            int haybales_to_move = std::min(haybales_in_current_pile, d / cost_per_haybale);

            max_a1 += haybales_to_move;
            d -= haybales_to_move * cost_per_haybale;
        } else {
            // Not enough days to move even one haybale from this pile
            // Since costs increase with pile index, we can't move from subsequent piles either.
            break; 
        }
    }

    std::cout << max_a1 << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

