    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        std::map<int, int> counts;
        for (int i = 0; i < n; ++i) {
            int s_val;
            std::cin >> s_val;
            if (s_val <= 2048) {
                counts[s_val]++;
            }
        }

        int current_sum = 0;
        for (auto const& [val, count] : counts) {
            // Add the contribution of 'val' to the current_sum.
            // Each 'val' contributes 'val * count' to the total sum
            // if we were to combine them all into a single number.
            // However, we are interested in how much of the target 2048
            // can be formed.
            // We can think of it as: we have 'count' pieces of 'val'.
            // We can combine pairs of 'val' to form '2*val'.
            // This is equivalent to adding 'val * count' to a running sum,
            // but only up to 2048.
            // For example, if we have three 512s, we can make one 1024 and have one 512 left.
            // This is equivalent to adding 512*3 = 1536 to the current_sum.
            // If current_sum exceeds 2048, it means we have enough to form 2048.
            current_sum += val * count;
        }

        if (current_sum >= 2048) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }
    return 0;
}

