int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1. If so, it should be n.
    // This handles the case where n is the largest value in the permutation.
    // If p[k] = n, then max(min(p[k], p[j])) for j!=k is max(p[j] for j!=k) which is n-1.
    // So, if n is present in the permutation, one of the p[i] values computed above will be n-1.
    // All other p[i] values will be correct.
    // We need to find the maximum value in the computed p and if it's n-1, change it to n.
    int max_p_val = 0;
    for (int val : p) {
        if (val > max_p_val) {
            max_p_val = val;
        }
    }

    if (max_p_val == n - 1) {
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; // Only one such element should be changed
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
