void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_suffix_price = a[n - 1]; // Initialize with the last price

    // Iterate from right to left, excluding the last element
    // For each a[i], we need to know if there's any a[j] < a[i] for j > i.
    // This is equivalent to checking if a[i] > min(a[i+1], ..., a[n-1]).
    // min_suffix_price stores min(a[i+1], ..., a[n-1]) when we are at index i.
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix_price) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix_price, it means a[i] is
            // either equal to or less than the current minimum in the suffix.
            // In this case, a[i] itself becomes the new minimum for the suffix
            // starting from i.
            min_suffix_price = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

