        int max_gap = 0;
        int last_R_pos = -1; // Represents the position of the last 'R' or the starting cell 0.
                             // If last_R_pos = -1, it means the frog is at cell 0.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current cell i is an 'R' cell.
                // The gap between the previous 'R' (or 0) and this 'R' is (i - last_R_pos).
                // The frog must be able to jump over all 'L' cells between last_R_pos and i.
                // The distance required for this jump is (i - last_R_pos).
                // For example, if last_R_pos = 0 and current 'R' is at i=2,
                // and s[1] is 'L', the frog must jump from 0 to 2.
                // The jump distance is 2.
                max_gap = std::max(max_gap, i - last_R_pos);
                last_R_pos = i;
            }
        }

        // After iterating through the string, consider the jump from the last 'R' cell
        // (or cell 0 if no 'R's) to the target cell n+1.
        // The distance for this final jump is (n + 1 - last_R_pos).
        max_gap = std::max(max_gap, n + 1 - last_R_pos);

        std::cout << max_gap << "\n";
