    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams k must satisfy:
        // 1. k <= c (at least k coders needed)
        // 2. k <= m (at least k mathematicians needed)
        // 3. 3 * k <= c + m + x (total students needed)
        // So, k <= min(c, m, (c + m + x) / 3)
        // This gives an upper bound for k.
        // Let's check if this upper bound is always achievable.
        // The minimum number of coders and mathematicians required is k each.
        // The remaining students are (c - k) coders, (m - k) mathematicians, and x no-specialization students.
        // The total number of remaining students is (c - k) + (m - k) + x.
        // Each team needs 3 members. k teams need 3k members.
        // k members are coders, k members are mathematicians.
        // The remaining k members for the k teams must be filled from the remaining students.
        // The remaining students are (c - k) + (m - k) + x.
        // We need to fill k slots.
        // The total number of students available for these k slots is (c - k) + (m - k) + x.
        // This sum must be at least k.
        // (c - k) + (m - k) + x >= k
        // c + m + x - 2k >= k
        // c + m + x >= 3k
        // This condition is already covered by k <= (c + m + x) / 3.
        // So, the maximum number of teams is indeed min(c, m, (c + m + x) / 3).
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

