#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number to use in the zigzag part to generate k distinct differences

    // Generate k distinct differences using a zigzag pattern
    // The numbers used will be from 1 to k+1.
    // The differences generated will be k, k-1, ..., 1.
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) {
            std::cout << left++;
        } else {
            std::cout << right--;
        }
        if (i < n - 1) { // Print space if not the last number
            std::cout << " ";
        }
    }

    // For the remaining n - (k+1) numbers, just append them in increasing order.
    // These numbers are k+2, k+3, ..., n.
    // The differences generated by appending these will all be 1.
    // For example, if the last number printed was X, and the next is X+1, then |X - (X+1)| = 1.
    // If the last number printed was Y, and the next is Y-1, then |Y - (Y-1)| = 1.
    // In our zigzag, the last number printed is either left-1 or right+1.
    // If k is even, the last number printed was right (which is k+1). The next number is k+2. Difference is 1.
    // If k is odd, the last number printed was left (which is (k+1)/2 + 1). The next number is k+2. Difference is > 1.
    // This is incorrect. The last number printed in the zigzag part is either `left-1` or `right+1`.
    // `left` is `(k+1)/2 + 1` if `k+1` is odd (i.e., `k` is even).
    // `right` is `(k+1)/2` if `k+1` is even (i.e., `k` is odd).
    // The numbers used are `1, 2, ..., k+1`.
    // The next number to print is `k+2`.
    // The difference `|last_zigzag_num - (k+2)|` might not be 1.
    // However, the problem states we need *exactly* k distinct differences.
    // The zigzag part `1, k+1, 2, k, 3, k-1, ...` generates differences `k, k-1, ..., 1`.
    // These are `k` distinct differences.
    // Any subsequent differences must not introduce new distinct values.
    // The simplest way to do this is to make all subsequent differences 1.
    // We can achieve this by printing the remaining numbers `k+2, k+3, ..., n` in increasing order.
    // The last number printed from the zigzag part is either `left-1` or `right+1`.
    // `left` is now `(k+1)/2 + 1` (if k is even) or `(k+2)/2` (if k is odd).
    // `right` is now `(k+1)/2` (if k is even) or `(k+1)/2 + 1` (if k is odd).
    // The numbers `k+2, ..., n` are all greater than `k+1`.
    // So, we just append them in increasing order.
    // The difference `|last_zigzag_num - (k+2)|` will be a new difference if `last_zigzag_num` is small.
    // Example: n=5, k=2. Output: 1 3 2. Remaining: 4 5.
    // Differences: |1-3|=2, |3-2|=1. Distinct: {1,2}.
    // Append 4: 1 3 2 4. New diff: |2-4|=2. Still {1,2}.
    // Append 5: 1 3 2 4 5. New diff: |4-5|=1. Still {1,2}.
    // This strategy works. The differences generated by `k+2, k+3, ..., n` are all 1.
    // The difference `|p_{k+1} - p_{k+2}|` (where `p_{k+1}` is the last zigzag number)
    // will be `|p_{k+1} - (k+2)|`.
    // Since `p_{k+1}` is one of `1, ..., k+1`, this difference will be at least `(k+2) - (k+1) = 1`.
    // And at most `(k+2) - 1 = k+1`.
    // All differences `1, ..., k` are already generated.
    // If `|p_{k+1} - (k+2)|` is `k+1`, it's a new difference. This happens if `p_{k+1} = 1`.
    // This happens when `k` is odd, and the last zigzag number is `1`.
    // Example: n=5, k=3. Output: 1 4 2 3. Remaining: 5.
    // Differences: |1-4|=3, |4-2|=2, |2-3|=1. Distinct: {1,2,3}.
    // Append 5: 1 4 2 3 5. New diff: |3-5|=2. Still {1,2,3}.
    // This strategy is correct. The differences `k, k-1, ..., 1` are generated by the zigzag.
    // The remaining numbers `k+2, ..., n` are appended in increasing order.
    // The differences among these are all 1.
    // The difference between the last zigzag number and `k+2` will be `|p_{k+1} - (k+2)|`.
    // `p_{k+1}` is either `(k+1)/2 + 1` (if k is even) or `(k+1)/2` (if k is odd).
    // In both cases, `p_{k+1} <= k+1`.
    // So `|p_{k+1} - (k+2)|` will be `(k+2) - p_{k+1}`.
    // This value will be between `(k+2) - (k+1) = 1` and `(k+2) - 1 = k+1`.
    // Since `1, ..., k` are already present, this new difference will either be one of them, or `k+1`.
    // If it's `k+1`, we have `k+1` distinct differences, which is wrong.
    // This happens if `p_{k+1} = 1`.
    // `p_{k+1} = 1` happens when `k` is odd, and the zigzag ends with `1`.
    // Example: n=5, k=3. Zigzag: 1 4 2 3. `p_4 = 3`. `left=3, right=2`.
    // `p_1=1, p_2=4, p_3=2, p_4=3`.
    // `k=3` is odd. The last number printed is `left++` which is `(k+1)/2 + 1 = (3+1)/2 + 1 = 3`.
    // So `p_{k+1} = 3`.
    // The next number is `k+2 = 5`. Difference `|3-5|=2`. This is fine.

    // The strategy is:
    // 1. Print `1, k+1, 2, k, 3, k-1, ...` until `k+1` numbers are printed.
    //    This generates differences `k, k-1, ..., 1`.
    // 2. Print the remaining numbers `k+2, k+3, ..., n` in increasing order.
    //    This generates differences of 1.
    // This ensures exactly `k` distinct differences.

    for (int i = k + 2; i <= n; ++i) {
        std::cout << i;
        if (i < n) {
            std::cout << " ";
        }
    }
    std::cout << std::endl;

    return 0;
}

