void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n >= 2, we can construct a number.
        // The first digit is 2.
        // The remaining n-1 digits are 3.
        // This forms the number 233...3 (n-1 times 3).
        // Let's check this construction:
        // 1. s > 0: Yes, it's a positive number.
        // 2. s consists of n digits: Yes, 2 followed by n-1 threes.
        // 3. No digit in s equals 0: Digits are 2 and 3, neither is 0.
        // 4. s is not divisible by any of its digits:
        //    Digits are 2 and 3.
        //    Divisibility by 2: The last digit is 3 (odd), so s is not divisible by 2.
        //    Divisibility by 3: The sum of digits is 2 + (n-1)*3.
        //    2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
        //    For s to be divisible by 3, 3n - 1 must be divisible by 3.
        //    3n - 1 = 3*(n-1) + 2.
        //    This sum of digits always leaves a remainder of 2 when divided by 3.
        //    Therefore, s is never divisible by 3.
        // This construction satisfies all conditions for n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << std::endl;
    }
}

