#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `p` such that a[p...n-1] is non-decreasing.
    // This means a[p] <= a[p+1] <= ... <= a[n-1].
    // If the whole array is non-decreasing, p will be 0.
    int p = n - 1;
    while (p > 0 && a[p-1] <= a[p]) {
        p--;
    }

    // If p is 0, the array is already non-decreasing, which is a good array.
    // So, 0 prefix needs to be erased.
    if (p == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    // Now, a[p-1] > a[p].
    // We need to find the rightmost index `q` such that a[q...p-1] is non-increasing.
    // This means a[q] >= a[q+1] >= ... >= a[p-1].
    // The elements a[q...n-1] form the potential suffix.
    int q = p - 1;
    while (q > 0 && a[q-1] >= a[q]) {
        q--;
    }

    // The length of the prefix to erase is `q`.
    // The remaining suffix is a[q...n-1].
    // This suffix has the structure:
    // a[q] >= a[q+1] >= ... >= a[p-1] (non-increasing part)
    // a[p] <= a[p+1] <= ... <= a[n-1] (non-decreasing part)
    // And a[p-1] > a[p] (the "dip" between the two parts).
    // This structure is always a good array.
    std::cout << q << std::endl;
}

