void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');

    // For m=1, the subsegment is [1]. This is always possible.
    // The subsegment is p[pos[1]...pos[1]]. Length 1, min 1, max 1.
    result[0] = '1';

    // Initialize current min and max indices for the window containing 1...k
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // Expand the window to include 'm'
        // 'm' must be either to the left or to the right of the current window
        // [current_min_idx, current_max_idx]
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current window [current_min_idx, current_max_idx]
        // forms a permutation of 1...m.
        // This requires two conditions:
        // 1. The length of the window must be exactly m.
        // 2. The minimum element in the window must be 1.
        // 3. The maximum element in the window must be m.
        // Conditions 2 and 3 are implicitly handled by how current_min_idx and current_max_idx
        // are updated (they always span from 1 to m).
        // So we only need to check the length.
        if (current_max_idx - current_min_idx + 1 == m) {
            result[m - 1] = '1';
        }
    }

    std::cout << result << "\n";
}

