    }

    // Calculate max_val_left[i]: the maximum possible value for a[i]
    // if it were part of a strictly increasing sequence starting from 0.
    // max_val_left[i] = min(a[i], max_val_left[i-1] + 1)
    // Base case: max_val_left[0] = a[0]
    std::vector<long long> max_val_left(n);
    max_val_left[0] = a[0];
    for (int i = 1; i < n; ++i) {
        max_val_left[i] = std::min(a[i], max_val_left[i-1] + 1);
    }

    // Calculate max_val_right[i]: the maximum possible value for a[i]
    // if it were part of a strictly decreasing sequence ending at 0.
    // max_val_right[i] = min(a[i], max_val_right[i+1] + 1)
    // Base case: max_val_right[n-1] = a[n-1]
    std::vector<long long> max_val_right(n);
    max_val_right[n-1] = a[n-1];
    for (int i = n - 2; i >= 0; --i) {
        max_val_right[i] = std::min(a[i], max_val_right[i+1] + 1);
    }

    // Check if there exists a peak k such that
    // max_val_left[k] >= k (from left side)
    // max_val_right[k] >= n-1-k (from right side)
    // And the peak value itself must be non-negative, which is guaranteed by the min operations.
    // The condition for a peak k is that the value at k must be strictly greater than its neighbors.
    // The values we are checking are the maximum possible values for a[i] given the constraints
    // from one side. If max_val_left[i] >= i and max_val_right[i] >= n-1-i,
    // it means we can construct a sequence up to i with value at least i,
    // and a sequence from i down to n-1 with value at least n-1-i.
    // The actual value at peak k would be min(max_val_left[k], max_val_right[k]).
    // We need this value to be >= max(k, n-1-k).
    // More simply, we need to check if min(max_val_left[i], max_val_right[i]) >= 0 for all i.
    // And for a peak k, we need min(max_val_left[k], max_val_right[k]) to be the maximum possible value.
    // The condition for a sharpened array is that there exists a k such that
    // b_i = i for i < k, b_k = k, b_i = k - (i-k) for i > k.
    // This means b_i = i for i <= k and b_i = n-1-i for i >= k.
    // So we need to check if min(max_val_left[i], max_val_right[i]) >= 0 for all i.
    // And for a peak k, we need min(max_val_left[k], max_val_right[k]) >= 0.
    // The actual condition is that for some k, the value at k can be made positive,
    // and the values to its left can be made 0, 1, ..., k-1,
    // and values to its right can be made k-1, k-2, ..., 0.
    // So we need to check if min(max_val_left[i], max_val_right[i]) >= 0 for all i.
    // This is equivalent to checking if max_val_left[i] >= 0 and max_val_right[i] >= 0 for all i.
    // Since a_i >= 0, max_val_left[i] and max_val_right[i] will always be >= 0.
    // The actual condition for a peak k is that the value at k must be at least 0.
    // And the values to its left must be 0, 1, ..., k-1.
    // And the values to its right must be 0, 1, ..., n-1-k.
    // So we need to check if max_val_left[i] >= i and max_val_right[i] >= n-1-i.
    // If there is any i such that max_val_left[i] >= i and max_val_right[i] >= n-1-i,
    // then we can form a sharpened array with peak at i.
    // The value at index i would be min(max_val_left[i], max_val_right[i]).
    // This value must be at least max(i, n-1-i) to satisfy the strict inequalities.
    // No, this is not correct. The values are 0, 1, ..., k-1, k, k-1, ..., 0.
    // So the value at index i (from left) must be at least i.
    // The value at index i (from right) must be at least n-1-i.
    // So we need to check if there exists an index i such that
    // max_val_left[i] >= i AND max_val_right[i] >= n-1-i.
    // If such an i exists, then we can form a sharpened array.
    // The peak value at index i would be min(max_val_left[i], max_val_right[i]).
    // This peak value must be at least max(i, n-1-i) to satisfy the conditions.
    // But we can always decrease it.
    // The minimum value for the peak at index i is max(i, n-1-i).
    // So we need to check if min(max_val_left[i], max_val_right[i]) >= max(i, n-1-i).
    // This is equivalent to max_val_left[i] >= i AND max_val_right[i] >= n-1-i.

    bool possible = false;
    for (int i = 0; i < n; ++i) {
        if (max_val_left[i] >= i && max_val_right[i] >= (n - 1 - i)) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

