        if (a[i] > s) {
            operations += (a[i] - s);
            // a[i] = s; // Not strictly necessary to update a[i] as we only care about cost
        }
    }

    // Ensure elements to the right of the median are >= s.
    // If an element a[i] > s, it's fine.
    // If an element a[i] < s, we must increase it to s.
    // Similarly, it's always optimal to change a[i] to s if a[i] < s.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
            // a[i] = s; // Not strictly necessary to update a[i]
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

