#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

// Custom comparator for pairs (value, original_index)
// Sorts by value in ascending order. If values are equal, original_index is used as a tie-breaker.
struct PairComparator {
    bool operator()(const std::pair<long long, int>& a, const std::pair<long long, int>& b) const {
        if (a.first != b.first) {
            return a.first < b.first;
        }
        return a.second < b.second; // Stable sort by original index
    }
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<std::pair<long long, int>> a_indexed(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_indexed[i].first;
        a_indexed[i].second = i; // Store original index
    }

    std::vector<std::pair<long long, int>> b_indexed(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_indexed[i].first;
        b_indexed[i].second = i; // Store original index
    }

    // Sort A in ascending order of values.
    // If values are equal, original index is used as a tie-breaker.
    std::sort(a_indexed.begin(), a_indexed.end(), PairComparator());

    // Sort B in ascending order of values.
    // If values are equal, original index is used as a tie-breaker.
    std::sort(b_indexed.begin(), b_indexed.end(), PairComparator());

    // Create the result array A'
    std::vector<long long> a_prime(m);

    // The strategy is to pair the largest A_i with the largest B_j,
    // the second largest A_i with the second largest B_j, and so on.
    // This means we pair a_indexed[k] with b_indexed[k].
    // However, the problem asks for the output in the original order of B.
    // So, if b_indexed[k] corresponds to original index `idx_b`,
    // then a_prime[idx_b] should be a_indexed[k].first.
    for (int k = 0; k < m; ++k) {
        int original_b_index = b_indexed[k].second;
        a_prime[original_b_index] = a_indexed[k].first;
    }

    // Output the rearranged array A'
    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
