int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long count = n / m; // Number of pages divisible by m

        if (count == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Calculate the sum of last digits for one full cycle of 10 multiples
        // The last digits of m*1, m*2, ..., m*10 are (m%10)*1%10, (m%10)*2%10, ..., (m%10)*10%10
        // This is equivalent to (m*1)%10, (m*2)%10, ..., (m*10)%10
        long long sum_cycle = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_cycle += (m * i) % 10;
        }

        // Number of full cycles of 10 multiples
        long long num_full_cycles = count / 10;
        long long total_sum = num_full_cycles * sum_cycle;

        // Add the remaining last digits
        long long remaining_multiples = count % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (m * i) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y 0.000000000 0.000000000\n";
            continue;
        }

        // For a and b to be real numbers, the discriminant d^2 - 4d must be non-negative.
        // d^2 - 4d >= 0
        // d(d - 4) >= 0
        // Since d >= 0, we must have d - 4 >= 0, which means d >= 4.
        // If d is between 0 (exclusive) and 4 (exclusive), there are no real solutions.
        if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // Solutions for 'a' are (d +/- sqrt(d^2 - 4d)) / 2
            // Let's pick the '+' sign for 'a' and '-' sign for 'b' (or vice versa).
            // This ensures a >= b if we pick '+' for a and '-' for b.
            // Both a and b will be non-negative because d >= 4.
            // sqrt(d^2 - 4d) is real and non-negative.
            // d - sqrt(d^2 - 4d) >= 0 needs to be checked.
            // d >= sqrt(d^2 - 4d)
            // d^2 >= d^2 - 4d (since d >= 0, we can square both sides)
            // 0 >= -4d
            // 4d >= 0
            // This is true for d >= 0. So both solutions are non-negative.

            double sqrt_discriminant = std::sqrt(d * d - 4.0 * d);
            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            std::cout << std::fixed << std::setprecision(9) << "Y " << a << " " << b << "\n";
        }
    }
    return 0;
}

