#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor ^= a;
    }

    // Case 0: Already good
    if (current_sum == 2 * current_xor) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
        return;
    }

    // Case 1: Append 2 elements
    // We need to find b1, b2 such that:
    // (current_sum + b1 + b2) = 2 * (current_xor ^ b1 ^ b2)
    // Let b1 = current_xor.
    // Then current_xor ^ b1 = current_xor ^ current_xor = 0.
    // The equation becomes:
    // (current_sum + current_xor + b2) = 2 * (0 ^ b2)
    // (current_sum + current_xor + b2) = 2 * b2
    // current_sum + current_xor = b2
    // So, b2 = current_sum + current_xor.

    // Let's verify this choice:
    // New sum S' = current_sum + current_xor + (current_sum + current_xor) = 2 * (current_sum + current_xor)
    // New xor X' = current_xor ^ current_xor ^ (current_sum + current_xor) = current_sum + current_xor
    // Is S' = 2 * X'?
    // 2 * (current_sum + current_xor) = 2 * (current_sum + current_xor)
    // Yes, it holds.

    // The appended elements are current_xor and (current_sum + current_xor).
    // These values can be large, up to 10^9 (for current_xor) and 10^5 * 10^9 + 10^9 (for sum + xor)
    // which is roughly 10^14, fitting in long long.

    std::cout << 2 << std::endl;
    std::cout << current_xor << " " << (current_sum + current_xor) << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

