int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'a') {
            // If we encounter an 'a', it will eventually move past all 'b's to its left.
            // Each 'b' it moves past will contribute to the total steps.
            // The 'a' itself will effectively double the number of 'a's that are
            // "waiting" to move past 'b's.
            // This is because 'ab' -> 'bba'. The 'a' becomes 'bb', and the 'b' becomes 'a'.
            // The new 'a' is now to the right of the 'bb'.
            // The 'a' that was originally at s[i] effectively becomes two 'b's,
            // and the 'b' it swapped with becomes an 'a'.
            // The number of 'a's that are "active" and need to move past 'b's doubles.
            total_steps = (total_steps + count_a) % MOD;
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'b'
            // If we encounter a 'b', it means any 'a's to its right (represented by count_a)
            // will eventually move past this 'b'. Each such 'a' contributes 1 step for this 'b'.
            // So, we add count_a to total_steps.
            // This 'b' itself will eventually be transformed into an 'a' when an 'a' moves past it.
            // So, it effectively becomes an 'a' that is now waiting to move past 'b's to its left.
            // Thus, we increment count_a.
            total_steps = (total_steps + count_a) % MOD;
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

