// Function to convert a number to its parity pattern string
// For example, 12345 -> "10101" (odd, even, odd, even, odd)
// The pattern is always 18 characters long, padded with '0's on the left.
std::string get_parity_pattern(long long n) {
    std::string pattern_str;
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                pattern_str += '0';
            } else { // Odd digit
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to make it 18 characters long
    // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
    // and "if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This means we should normalize both the number's parity string and the query pattern string to a fixed length.
    // Max digits for 10^18 is 19, but 10^18 itself has 19 digits.
    // The problem states a_i < 10^18, so max value is 99...9 (18 times), which has 18 digits.
    // So, 18 is a safe length.
    while (pattern_str.length() < 18) {
        pattern_str += '0'; // Append '0' to the right, which corresponds to padding with '0's on the left of the number
    }
    std::reverse(pattern_str.begin(), pattern_str.end()); // Reverse to get correct order (most significant digit first)
    return pattern_str;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each normalized parity pattern string
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Normalize the query pattern string to 18 characters
            // Pad with '0's from the left (which means prepending '0's to the string)
            std::string normalized_s = s;
            while (normalized_s.length() < 18) {
                normalized_s = '0' + normalized_s;
            }
            std::cout << pattern_counts[normalized_s] << "\n";
        }
    }

    return 0;
}

