    int count = 0;
    int j = 0; // Pointer for the elements we are trying to place (from the sorted array)
    for (int i = 0; i < n; ++i) { // Pointer for the "original" elements (from the sorted array)
        // We are trying to find an element a[j] such that a[j] > a[i]
        // Since both arrays are sorted, if a[j] > a[i], then any a[k] with k > j will also be > a[i] (or equal)
        // We want to use the smallest possible a[j] that satisfies a[j] > a[i]
        // This leaves larger numbers available for larger a[i] values later.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // Found an element a[j] such that a[j] > a[i]
            count++;
            j++; // Move to the next element in the 'available' pool
        } else {
            // No more elements in 'a' are greater than a[i]
            // Since a is sorted, no subsequent a[k] (k > i) will be able to find a greater element either.
            break;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

