#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // prefix_counts[c][i] stores the count of character 'c' in s[0...i-1]
    // c=0 for 'x', c=1 for 'y', c=2 for 'z'
    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int c = 0; c < 3; ++c) {
            prefix_counts[c][i + 1] = prefix_counts[c][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        // Adjust to 0-indexed
        // Substring is s[l-1 ... r-1]
        // Length of substring is r - (l-1) = r - l + 1
        int len = r - l + 1;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        // Check if the counts of 'x', 'y', 'z' are "balanced"
        // i.e., their difference is at most 1
        if (std::abs(count_x - count_y) <= 1 &&
            std::abs(count_x - count_z) <= 1 &&
            std::abs(count_y - count_z) <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

