long long get_prime_factor_power(long long n, long long p) {
    if (p == 0 || p == 1) return 0; // Should not happen with prime factors
    long long count = 0;
    while (n > 0 && n % p == 0) {
        count++;
        n /= p;
    }
    return count;
}

std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        long long max_x = 1;
        std::vector<long long> q_prime_factors = get_prime_factors(q);

        for (long long f : q_prime_factors) {
            long long current_p = p;
            long long count_f_in_q = get_prime_factor_power(q, f);

            while (current_p > 0 && current_p % f == 0 && get_prime_factor_power(current_p, f) >= count_f_in_q) {
                current_p /= f;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string ans(n, ' ');
    bool found_solution = false;

    for (char pivot_char = '0'; pivot_char <= '9'; ++pivot_char) {
        char last1 = '0'; // Last digit placed in color 1
        char last2 = '0'; // Last digit placed in color 2
        bool possible = true;

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];
            if (current_digit < pivot_char) {
                // Must go to color 1
                if (current_digit < last1) {
                    possible = false;
                    break;
                }
                ans[i] = '1';
                last1 = current_digit;
            } else if (current_digit > pivot_char) {
                // Must go to color 2
                if (current_digit < last2) {
                    possible = false;
                    break;
                }
                ans[i] = '2';
                last2 = current_digit;
            } else { // current_digit == pivot_char
                // Can go to color 1 or color 2
                // Prioritize color 2 if it maintains non-decreasing order
                if (current_digit >= last2) {
                    ans[i] = '2';
                    last2 = current_digit;
                } else if (current_digit >= last1) {
                    // If cannot go to color 2, try color 1
                    ans[i] = '1';
                    last1 = current_digit;
                } else {
                    // Cannot go to either
                    possible = false;
                    break;
                }
            }
        }

        if (possible) {
            // Final check: last digit of color 1 sequence <= first digit of color 2 sequence
            // This is implicitly handled by the `last1` and `last2` logic.
            // If a digit `d` is assigned to color 1, then `d >= last1`.
            // If a digit `d` is assigned to color 2, then `d >= last2`.
            // The pivot_char ensures that all digits assigned to color 1 are <= pivot_char,
            // and all digits assigned to color 2 are >= pivot_char.
            // So, `last1` will be <= pivot_char, and `last2` will be >= pivot_char.
            // Thus, `last1 <= last2` is guaranteed if `possible` is true.
            // The only edge case is if `last1` is updated with a digit `d == pivot_char`
            // and `last2` is updated with a digit `d' == pivot_char`.
            // The logic `current_digit >= last2` for `current_digit == pivot_char`
            // ensures that if `pivot_char` can go to color 2, it does.
            // This means `last1` will only contain digits strictly less than `pivot_char`
            // or `pivot_char`s that *must* go to color 1 because `last2` is too high.
            // This strategy ensures `last1 <= pivot_char <= last2` effectively.

            found_solution = true;
            break;
        }
    }

    if (found_solution) {
        std::cout << ans << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

