void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (char c = 'a'; c <= 'z'; ++c) {
        adj[c] = std::set<char>();
    }

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char u = s[i];
        char v = s[i+1];
        adj[u].insert(v);
        adj[v].insert(u);
    }

    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited;
    char start_node = '\0';

    // Find a starting node for a path (a character with only one required neighbor)
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() == 1) {
            start_node = c;
            break;
        }
    }

    // If no node has one neighbor, it means all required characters either have 0 or 2 neighbors.
    // If all required characters have 2 neighbors, they must form a cycle, which is not allowed for a single row.
    // Or they form multiple disjoint paths/cycles.
    // If there are required characters, and all have 2 neighbors, it's impossible.
    // If there are required characters, and some have 0 neighbors, we can start with a 0-neighbor node.
    // The only case where all required characters have 2 neighbors and it's possible is if there's only one character in s,
    // but s.length() >= 1, and the loop for adjacencies runs for s.length() - 1.
    // If s.length() == 1, adjacencies are empty, all nodes have 0 neighbors.
    // If s.length() > 1, and all required nodes have 2 neighbors, it implies a cycle.
    // Example: abca -> a-b-c-a. This forms a cycle. A single row keyboard cannot have cycles.
    // So, if start_node is still '\0' and there are any required adjacencies, it's impossible.
    // We can check this by seeing if any adj[c].size() == 2 for a character c that is part of the password.
    // A simpler check: if start_node is still '\0', it means all characters involved in adjacencies have 2 neighbors.
    // This forms a cycle, which is not allowed.
    // Exception: if s.length() == 1, then adj is empty, start_node remains '\0', but it's valid.
    // In this case, we can pick any char as start_node.

    // If s.length() == 1, start_node will be '\0'. We can pick 'a' as start.
    if (s.length() == 1) {
        start_node = s[0]; // Or any char, but s[0] is a good choice.
    } else if (start_node == '\0') { // All required characters have 2 neighbors, implies a cycle.
        // This means all characters that appear in 's' have exactly two distinct neighbors.
        // This forms a cycle, which is not allowed on a linear keyboard.
        // Example: abca -> a-b-c-a.
        // The only exception is if there are no adjacencies at all (s.length() == 1),
        // but that case is handled by the s.length() == 1 check.
        // So if start_node is still '\0' here, it's impossible.
        std::cout << "NO\n";
        return;
    }

    // Build the path starting from start_node
    char current = start_node;
    char prev = '\0'; // Sentinel for the previous character in the path

    while (current != '\0' && visited.find(current) == visited.end()) {
        layout_str += current;
        visited.insert(current);

        char next_char = '\0';
        for (char neighbor : adj[current]) {
            if (neighbor != prev) {
                next_char = neighbor;
                break;
            }
        }
        prev = current;
        current = next_char;
    }

    // Check if all characters involved in adjacencies were included in the path
    for (char c = 'a'; c <= 'z'; ++c) {
        if (!adj[c].empty() && visited.find(c) == visited.end()) {
            // This means there's another disjoint path or cycle that wasn't connected to the first one.
            // A single row keyboard can only be one continuous path.
            std::cout << "NO\n";
            return;
        }
    }

    // Append remaining unvisited characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            layout_str += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

