#include <numeric>
#include <algorithm>
#include <iomanip>

// Z-algorithm implementation
std::vector<int> calculate_z_function(const std::string& s) {
    int n = s.length();
    std::vector<int> z(n);
    for (int i = 1, l = 0, r = 0; i < n; ++i) {
        if (i <= r) {
            z[i] = std::min(r - i + 1, z[i - l]);
        }
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            ++z[i];
        }
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int L = s.length();

    // Precompute Z-values for all cyclic shifts
    // z_values[i][j] stores Z-value for string s[i..L-1] + s[0..i-1] at index j
    // Specifically, z_values[i][j] is the length of the longest common prefix
    // between (s shifted left by i) and (s shifted left by i starting at index j)
    // This is equivalent to LCP(s, s_shifted_by_i_starting_at_j)
    // which is LCP(s, s_shifted_by_i_starting_at_j)
    // which is LCP(s, s_shifted_by_i_starting_at_j)
    // No, this is LCP(s_shifted_by_i, s_shifted_by_i_starting_at_j)
    // Let S_i be s shifted left by i.
    // z_values[i][j] is the length of the longest common prefix of S_i and S_i[j..L-1]
    // This is exactly what calculate_z_function does for S_i.
    // So, z_values[i] will store the Z-array for the string s_shifted_left_by_i.
    std::vector<std::vector<int>> z_values(L, std::vector<int>(L));
    for (int i = 0; i < L; ++i) {
        std::string shifted_s = s.substr(i) + s.substr(0, i);
        z_values[i] = calculate_z_function(shifted_s);
    }

    // For each possible first character c_0 (s[k])
    // and for each possible second position p (1 to L-1)
    // calculate the number of winning k's.
    // Sum these up and divide by L.

    double total_winning_prob = 0.0;

    // Iterate over all possible initial shifts k_actual (0 to L-1)
    // This k_actual is the true k chosen by Kolya.
    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char c0_val = s[k_actual]; // The first character Vasya sees

        // Find all k's that are consistent with c0_val
        std::vector<int> possible_k_indices;
        for (int i = 0; i < L; ++i) {
            if (s[i] == c0_val) {
                possible_k_indices.push_back(i);
            }
        }

        // If only one k is possible, Vasya wins immediately.
        if (possible_k_indices.size() == 1) {
            total_winning_prob += 1.0;
            continue;
        }

        // Vasya needs to choose an optimal second position p.
        // He wants to maximize the probability of winning for this specific k_actual.
        // This means he wants to maximize the number of p's that lead to a win.
        // Or, more precisely, for a given k_actual, he wants to choose p such that
        // (s[k_actual], s[(k_actual + p) % L]) uniquely identifies k_actual.
        // He will choose p that maximizes his chance of winning.
        // So, for this k_actual, we find the best p.

        int max_winning_p_count = 0; // Max number of k's uniquely identified by some p

        // Iterate over all possible second positions p (1 to L-1)
        for (int p = 1; p < L; ++p) {
            char cp_val = s[(k_actual + p) % L]; // The character Vasya sees at position p

            // Count how many k's from possible_k_indices are consistent with (c0_val, cp_val)
            std::vector<int> consistent_k_indices;
            for (int k_cand : possible_k_indices) {
                if (s[(k_cand + p) % L] == cp_val) {
                    consistent_k_indices.push_back(k_cand);
                }
            }

            // If after seeing c0_val and cp_val, there's only one consistent k,
            // and that k is k_actual, then Vasya wins for this (k_actual, p) pair.
            if (consistent_k_indices.size() == 1 && consistent_k_indices[0] == k_actual) {
                // This p works for this k_actual.
                max_winning_p_count = 1; // We found at least one p that works.
                break; // Vasya will choose this p, so we don't need to check other p's for this k_actual.
            }
        }
        total_winning_prob += max_winning_p_count;
    }

    std::cout << std::fixed << std::setprecision(15) << total_winning_prob / L << std::endl;

    return 0;
}

