                state_if_0[j] &= bit_val;
                state_if_1[j] &= bit_val;
            } else if (op_char == '|') {
                state_if_0[j] |= bit_val;
                state_if_1[j] |= bit_val;
            } else if (op_char == '^') {
                state_if_0[j] ^= bit_val;
                state_if_1[j] ^= bit_val;
            }
        }
    }

