    //   `((0 & A_j) | O_j) ^ X_j = 1` => `O_j ^ X_j = 1`
    //   `((1 & A_j) | O_j) ^ X_j = 0` => `(A_j | O_j) ^ X_j = 0`
    //   If `O_j = 0, X_j = 1`, then `0 ^ 1 = 1`. And `(A_j | 0) ^ 1 = 0` => `A_j ^ 1 = 0` => `A_j = 1`.
    //   So, `A_j=1, O_j=0, X_j=1` works. `(x_j & 1) | 0 ^ 1 = x_j ^ 1`.
    //   This means `A_j` can be 1, `X_j` can be 1.

    // Summary for each bit `j`:
    // If (state_if_0[j], state_if_1[j]) is:
    // (0, 0): `A_j=0, O_j=0, X_j=0` (result is 0)
    // (1, 1): `A_j=0, O_j=1, X_j=0` (result is 1)
    // (0, 1): `A_j=1, O_j=0, X_j=0` (result is x_j)
    // (1, 0): `A_j=1, O_j=0, X_j=1` (result is 1 - x_j)

    // We can construct the three constants `A`, `O`, `X` by setting their `j`-th bits according to the above.
    int final_and_const = 0;
    int final_or_const = 0;
    int final_xor_const = 0;

