        } else if (state_if_0[j] == 0 && state_if_1[j] == 1) { // Identity (x_j)
            // A_j=1, O_j=0, X_j=0
            final_and_const |= (1 << j);
        } else { // (state_if_0[j] == 1 && state_if_1[j] == 0) // Flip (1 - x_j)
            // A_j=1, O_j=0, X_j=1
            final_and_const |= (1 << j);
            final_xor_const |= (1 << j);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
