void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for differences (1 for strawberry, -1 for blueberry)
    // For jars 1 to n (left side)
    std::vector<int> diff_left(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_left[i + 1] = diff_left[i] + (a[i] == 1 ? 1 : -1);
    }

    // For jars n+1 to 2n (right side)
    // We iterate from right to left, so index j corresponds to jar 2n-j+1
    // diff_right[j] stores the difference for jars 2n, 2n-1, ..., 2n-j+1
    std::vector<int> diff_right(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_right[i + 1] = diff_right[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars eaten from the left (L)
    // to achieve a certain difference `d` among the remaining jars on the left.
    // `left_diff_map[d]` stores the minimum `L` such that `diff_left[n] - diff_left[L] == d`.
    // This is equivalent to `diff_left[L] == diff_left[n] - d`.
    // We are interested in `diff_left[L]` values.
    // `left_prefix_diff_map[val]` stores the minimum `L` such that `diff_left[L] == val`.
    std::map<int, int> left_prefix_diff_map;
    for (int L = 0; L <= n; ++L) {
        int current_diff = diff_left[L];
        if (left_prefix_diff_map.find(current_diff) == left_prefix_diff_map.end()) {
            left_prefix_diff_map[current_diff] = L;
        }
    }

    int min_jars_eaten = 2 * n; // Initialize with max possible jars eaten

    // Iterate over possible number of jars eaten from the right (R)
    for (int R = 0; R <= n; ++R) {
        // The difference from jars 2n, ..., 2n-R+1 is diff_right[R].
        // The difference from jars 1, ..., n is diff_left[n].
        // The difference from jars n+1, ..., 2n is diff_right[n].
        // Total initial difference: diff_left[n] + diff_right[n].
        // Difference of jars remaining on the right side (n+1 to 2n-R):
        // This is (diff_right[n] - diff_right[R]).
        // The target difference for the remaining jars (L+1 to 2n-R) is 0.
        // This means (diff_left[n] - diff_left[L]) + (diff_right[n] - diff_right[R]) = 0.
        // So, diff_left[L] = diff_left[n] + diff_right[n] - diff_right[R].
        // Let target_left_prefix_diff = diff_left[n] + diff_right[n] - diff_right[R].
        // This is the required prefix sum `diff_left[L]` for some `L`.

        int target_left_prefix_diff = diff_left[n] + diff_right[n] - diff_right[R];

        if (left_prefix_diff_map.count(target_left_prefix_diff)) {
            int L = left_prefix_diff_map[target_left_prefix_diff];
            min_jars_eaten = std::min(min_jars_eaten, L + R);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // 'i' represents the number of items taken from the left (0 to n)
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += (prefix_sum[i] - prefix_sum[0]) * l;

        // Energy for items taken from the right
        // The sum of weights for items taken from the right is total_sum - sum_of_first_i_items - sum_of_middle_items
        // Or simply, sum of weights from index n-j to n-1
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add penalty for extra items from left
        if (i > j) {
            current_energy += (long long)(i - j - 1) * Ql;
        }
        // Add penalty for extra items from right
        else if (j > i) {
            current_energy += (long long)(j - i - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

