        if (a[i] == 1) {
            last_one_idx = i;
        }
        if (last_one_idx != -1) {
            left_ones_dist[i] = i - last_one_idx;
        } else {
            left_ones_dist[i] = n + 1; // Represents infinity
        }
    }

