    //
    // Let's re-check 01010, n=5
    // a: 0 1 0 1 0
    // left_ones_dist: n+1 0 1 0 1
    // right_ones_dist: 1 0 1 0 n+1
    // left_zeros_dist: 0 1 0 1 0
