        // Fill the block in decreasing order
        for (int j = block_end_idx; j >= block_start_idx; --j) {
            p[j] = current_val--;
        }

        // Move to the next block
        i = block_end_idx;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

